-- Poems batch 390
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('83fe1600-6b3f-43a4-bbdf-ac79fda68c5a','頌古五十七首  其七','釋道昌','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','得因失有，是在非邊。',52,'全唐诗/poet.song.99000.json','["得因失有，是在非邊。", "根源未斷，枝派相連。", "不言言，口何在，轉得身來難下載。", "一帆風過洞庭湖，對面須知已違背。"]'),
('c54ff735-7292-4325-b4f8-35aeb11f05f6','頌古五十七首  其八','釋道昌','宋','宋诗','song-poetry','','[]','石臼發腳太遲，馬祖開口太早。',28,'全唐诗/poet.song.99000.json','["石臼發腳太遲，馬祖開口太早。", "十字街頭要錢，須是打他栲栳。"]'),
('991a860f-780d-40ce-8a16-95de36498177','頌古五十七首  其九','釋道昌','宋','宋诗','song-poetry','','[]','擔東過西，移前作後。',20,'全唐诗/poet.song.99000.json','["擔東過西，移前作後。", "馬首千差，佛面百醜。"]'),
('30c29b5c-2493-4bbd-a616-cf9255b77538','頌古五十七首  其一○','釋道昌','宋','宋诗','song-poetry','','[]','赤士纔將畫簸箕，烏雞何事忽驚飛。',32,'全唐诗/poet.song.99000.json','["赤士纔將畫簸箕，烏雞何事忽驚飛。", "自從題入新詩後，黄鶴樓前忘卻歸。"]'),
('cf1dcbd4-7f89-4eb0-bece-0fb4c27c9660','頌古五十七首  其一一','釋道昌','宋','宋诗','song-poetry','','[]','長沙似水洗水，老僧自倒自起。',28,'全唐诗/poet.song.99000.json','["長沙似水洗水，老僧自倒自起。", "三聖特地出頭，賣盡滿園桃李。"]'),
('b180364f-fd99-4f0b-b3a3-a92442e0a395','頌古五十七首  其一二','釋道昌','宋','宋诗','song-poetry','','[]','馬前相撲，入交失腳。',48,'全唐诗/poet.song.99000.json','["馬前相撲，入交失腳。", "不來外求，當面修削。", "六合彼中身，分明舉似人。", "到處世界總成就，脫略窼臼還滲漏。"]'),
('35f9164b-1668-4473-9b8b-399b66c1162d','頌古五十七首  其一三','釋道昌','宋','宋诗','song-poetry','','[]','據款結案，得失過半。',48,'全唐诗/poet.song.99000.json','["據款結案，得失過半。", "盡力擔當，上船離岸。", "無不指示汝，擎茶行食處。", "聖解凡情不過來。", "軒軒頭角起風雷。"]'),
('c29a1865-3d24-4349-8540-b1eb3673fa38','頌古五十七首  其一四','釋道昌','宋','宋诗','song-poetry','','[]','大悲許多手眼，如人夜摸枕子。',71,'全唐诗/poet.song.99000.json','["大悲許多手眼，如人夜摸枕子。", "徧身通身起來，盡受奴驅婢使。", "君不見認著牛跡裏，失卻大海水。", "轉變未得時，依前有依倚。", "歸去來，歸去來，拍天洪浪如浮埃。"]'),
('acdb296d-f99a-4251-9059-d7832790e6c1','頌古五十七首  其一五','釋道昌','宋','宋诗','song-poetry','','[]','至道無難，萬水千山。',52,'全唐诗/poet.song.99000.json','["至道無難，萬水千山。", "唯嫌揀擇，鵠黑烏白。", "纔有是非還護惜，不會不知全得力。", "明白裏頭如放行，腰金猶頌青青麥。"]'),
('0d1b5d09-df36-4b14-822b-66f3f862c082','頌古五十七首  其一六','釋道昌','宋','宋诗','song-poetry','','[]','天雷如鼓，云騰致雨。',54,'全唐诗/poet.song.99000.json','["天雷如鼓，云騰致雨。", "雨霽雲收，新月一鈎。", "至道無難，惟嫌揀擇。", "五年分疏太隔脈，東海鯉魚多赤梢，南山大蟲有白額。"]'),
('8ce7ec10-c5c3-4ba8-ad54-3ade503b1b12','頌古五十七首  其一七','釋道昌','宋','宋诗','song-poetry','','[]','趙州石橋，只見略彴。',42,'全唐诗/poet.song.99000.json','["趙州石橋，只見略彴。", "度驢度馬，應病與藥。", "換步移身，在富全貧。", "當頭如認著，東魯問西秦。"]'),
('a16a0a49-9570-439c-b8c5-91fad66ec822','頌古五十七首  其一八','釋道昌','宋','宋诗','song-poetry','','[]','趙州自作自受，南泉外頭相救。',28,'全唐诗/poet.song.99000.json','["趙州自作自受，南泉外頭相救。", "直饒數目分明，也是私路上走。"]'),
('1a55c371-a329-4677-9a3e-a7b6c419fe81','頌古五十七首  其一九','釋道昌','宋','宋诗','song-poetry','','[]','黄蘗活作死醫，臨濟死作活用。',28,'全唐诗/poet.song.99000.json','["黄蘗活作死醫，臨濟死作活用。", "維那聽事不真，未免喚鐘作甕。"]'),
('66e6dedf-295f-4a5f-941c-44ceb30f1e89','頌古五十七首  其二○','釋道昌','宋','宋诗','song-poetry','','[]','無位真人，處處獻新。',36,'全唐诗/poet.song.99000.json','["無位真人，處處獻新。", "攔胸扭住，不落主賓。", "乾屎橛，乾屎橛，三人證龜作箇鼈。"]'),
('ef5dca2d-cc05-4e36-9908-dfcfd3fc00e1','頌古五十七首  其二一','釋道昌','宋','宋诗','song-poetry','','[]','出頭露角，指點方見。',52,'全唐诗/poet.song.99000.json','["出頭露角，指點方見。", "見處不留，分定鍼線。", "下床扭住纔擬議，拓開一掌佛法意。", "脊背汗流喚得回，白蓮花向半天開。"]'),
('ea1efd66-1a6d-4961-a6ba-49a7b6a4d059','頌古五十七首  其二二','釋道昌','宋','宋诗','song-poetry','','[]','高揖釋迦，不拜彌勒，喫棒趁出猶費力，滴水冰生知未知，拋磚引玉有人識。',34,'全唐诗/poet.song.99000.json','["高揖釋迦，不拜彌勒，喫棒趁出猶費力，滴水冰生知未知，拋磚引玉有人識。"]'),
('db4b6ad7-2795-452f-95b1-610a9bb68dae','頌古五十七首  其二三','釋道昌','宋','宋诗','song-poetry','','[]','把火入牛欄，反身外面看。',24,'全唐诗/poet.song.99000.json','["把火入牛欄，反身外面看。", "梨花千點白，春雨幾聲寒。"]'),
('70e7ce0e-a087-4f32-b76f-ceb0467b61aa','頌古五十七首  其二四','釋道昌','宋','宋诗','song-poetry','','[]','來機深辨，有舒有卷。',67,'全唐诗/poet.song.99000.json','["來機深辨，有舒有卷。", "移卻案山，重添鍼線。", "千年田，八百主，直下承當還莽鹵。", "郎當屋舍沒人修，片瓦根椽誰去豎。", "君不見甜瓜徹蒂甜，苦瓠連根苦。"]'),
('bcb0bd0f-ad3d-483f-aa01-d4e1de887466','頌古五十七首  其二五','釋道昌','宋','宋诗','song-poetry','','[]','仰面穿針不見天，低頭拾芥不見地。',47,'全唐诗/poet.song.99000.json','["仰面穿針不見天，低頭拾芥不見地。", "天地針芥無處安，堂堂面目眼中翳。", "君不見諦當未徹在，齪人趁大彩。"]'),
('c73d196f-d2c4-461f-b32e-d186b0567caf','頌古五十七首  其二六','釋道昌','宋','宋诗','song-poetry','','[]','南陽師，肌骨好。',60,'全唐诗/poet.song.99000.json','["南陽師，肌骨好。", "洞山價，也難討。", "溈山翁，雲巖老。", "重注破，成鼓倒。", "分明行官路，不覺入荒草。", "葛藤因此到而今，業識茫茫何日了。"]'),
('73499e47-b334-4308-bb81-86c6c8cc3207','頌古五十七首  其二七','釋道昌','宋','宋诗','song-poetry','','[]','水到渠成，風行草偃。',36,'全唐诗/poet.song.99000.json','["水到渠成，風行草偃。", "類之不齊，睹之難面。", "誰信崖頽石裂時，黄金白銀如糞泥。"]'),
('836b10a8-f62c-40dc-b225-69a7b1f539a6','頌古五十七首  其二八','釋道昌','宋','宋诗','song-poetry','','[]','逆放順收，將寡敵衆。',52,'全唐诗/poet.song.99000.json','["逆放順收，將寡敵衆。", "隱顯同途，得失共用。", "針針相似不外來。", "同行語話要分開。", "自從大地火發後，古廟香爐不著灰。"]'),
('3dba2e05-ce52-4fe7-92ea-a56eebfa9402','頌古五十七首  其二九','釋道昌','宋','宋诗','song-poetry','','[]','說明道白，埋塵混垢。',36,'全唐诗/poet.song.99000.json','["說明道白，埋塵混垢。", "變化有由，敗露不走。", "誰知暗裏骨橫抽，要在轟轟霹靂手。"]'),
('4f532062-60dc-4591-b983-320ed2a1534a','頌古五十七首  其三○','釋道昌','宋','宋诗','song-poetry','','[]','佛聲從他，認我碗鳴。',52,'全唐诗/poet.song.99000.json','["佛聲從他，認我碗鳴。", "粗言歸第一義，自要看渠𡱰沸。", "喚作一頭驢，正令生光輝。", "趁手打得走無路，咭嘹舌頭何處歸。"]'),
('a93650bd-ed30-420a-b11e-edff2bce18a9','頌古五十七首  其三一','釋道昌','宋','宋诗','song-poetry','','[]','有本無本，學益學損。',52,'全唐诗/poet.song.99000.json','["有本無本，學益學損。", "搬運不時，提起卻穩。", "師子一滴迸六斛，驢乳散入別人屋。", "業識茫茫辨出時，烏雞不在蘆花宿。"]'),
('4bf83924-62a1-4372-9818-e00e45896629','頌古五十七首  其三二','釋道昌','宋','宋诗','song-poetry','','[]','法身說法，肉眼看物。',45,'全唐诗/poet.song.99000.json','["法身說法，肉眼看物。", "在智如愚，大辯如訥。", "拈起生簸箕別處舂，推出枕子露眠床，劍刃上事放毫光。"]'),
('475885bd-65c1-40ac-a303-0d73fe74bde4','頌古五十七首  其三三','釋道昌','宋','宋诗','song-poetry','','[]','高高山頂立，深深海底行。',60,'全唐诗/poet.song.99000.json','["高高山頂立，深深海底行。", "新松趁嶺種，芳草繞池生。", "手不攀枝，腳不踏樹。", "口裏啣得，當頭蹉路。", "問著西來對不對，罰錢依舊有人悔。"]'),
('962d939a-d4cb-4560-924f-bbbcd81fb7ea','頌古五十七首  其三四','釋道昌','宋','宋诗','song-poetry','','[]','腰金上太行，賊眼盡驚慞。',24,'全唐诗/poet.song.99000.json','["腰金上太行，賊眼盡驚慞。", "不因遭毒手，誰肯夜燒香。"]'),
('a1c904ed-33aa-4320-b45c-c7d196de490c','頌古五十七首  其三五','釋道昌','宋','宋诗','song-poetry','','[]','寬鞋著瘦腳，短袖入長臂。',55,'全唐诗/poet.song.99000.json','["寬鞋著瘦腳，短袖入長臂。", "竿木既隨身，逢場還作戲。", "前三三後三三，一時堆在擔頭擔。", "到得家中重點檢，目前包裹露毿毿。"]'),
('be270620-2acd-4acc-85e1-8c76bac00647','頌古五十七首  其三六','釋道昌','宋','宋诗','song-poetry','','[]','舌頭不出口，三三成九九。',24,'全唐诗/poet.song.99000.json','["舌頭不出口，三三成九九。", "算到香臺還，彼此落人後。"]'),
('ce1740cb-3d4b-4646-b358-a420e1be664a','頌古五十七首  其三七','釋道昌','宋','宋诗','song-poetry','','[]','當言不避截舌，當爐不避猛火。',56,'全唐诗/poet.song.99000.json','["當言不避截舌，當爐不避猛火。", "趁手作得家生，到老自能穩坐。", "水深杓柄長，舀水洗頭剃。", "雪峰刀上眼忽開，琉璃殿裏無關閉。"]'),
('159f104e-bfbd-4d69-81b8-8f20dddd8198','頌古五十七首  其三八','釋道昌','宋','宋诗','song-poetry','','[]','巨岳塵飛，蟭螟生兒。',46,'全唐诗/poet.song.99000.json','["巨岳塵飛，蟭螟生兒。", "兒落塵裏，如錐錐泥。", "燒火救火，閉門開門。", "拋柴家醜外頭見，萬象森羅一口吞。"]'),
('1c571801-3183-49b4-a763-4131afde1cef','頌古五十七首  其三九','釋道昌','宋','宋诗','song-poetry','','[]','俊鶻沖天，寒雞曉眠。',71,'全唐诗/poet.song.99000.json','["俊鶻沖天，寒雞曉眠。", "脫略窼窟，遲速不偏。", "截斷命根急處放，當頭手腳緩時樣。", "滴水冰生不認渠，坐籌幃幄江海量。", "君不見透網金鱗活計新，住持事繁笑殺人。"]'),
('807e412c-2ef5-44dd-aabf-780de580fb86','頌古五十七首  其四○','釋道昌','宋','宋诗','song-poetry','','[]','迅雷不及掩耳，下樁要在急水。',62,'全唐诗/poet.song.99000.json','["迅雷不及掩耳，下樁要在急水。", "水深樁腳若長，耳畔雷聲四起。", "拈起拄杖爲他中下，上上人來放過不打。", "秦人一入桃花源，子孫千世爲神仙。"]'),
('d2e2e89b-8bb6-478e-8731-5fe4aaf4b5bb','頌古五十七首  其四一','釋道昌','宋','宋诗','song-poetry','','[]','雲居道何必，興化道不必。',22,'全唐诗/poet.song.99000.json','["雲居道何必，興化道不必。", "眼若不開，夢中叫屈。"]'),
('c8f985ed-ece8-45e8-adb9-f6440e0e1d83','頌古五十七首  其四二','釋道昌','宋','宋诗','song-poetry','','[]','千里萬里，不著便處卻能回，閉了方丈依前來。',43,'全唐诗/poet.song.99000.json','["千里萬里，不著便處卻能回，閉了方丈依前來。", "雙收雙放，半合半開。", "主賓全體用，石女老黄梅。"]'),
('e8feed23-b20f-4525-a77a-ce29fd019204','頌古五十七首  其四三','釋道昌','宋','宋诗','song-poetry','','[]','趁水泛船，隨泥作佛。',64,'全唐诗/poet.song.99000.json','["趁水泛船，隨泥作佛。", "船行佛成，水泥不物。", "有拄杖兮與拄杖，船中輕蕩槳。", "無拄杖兮奪拄杖，佛面巧出相。", "好手芭蕉眼不開，塞壑填溝何處來。"]'),
('eca8ad44-cf21-4f74-a2f6-1fd423035150','頌古五十七首  其四四','釋道昌','宋','宋诗','song-poetry','','[]','前面有虎，元來是汝。',20,'全唐诗/poet.song.99000.json','["前面有虎，元來是汝。", "更問如何，冤苦冤苦。"]'),
('6f8bebdb-3813-4d75-9cd4-b312c85210b8','頌古五十七首  其四五','釋道昌','宋','宋诗','song-poetry','','[]','撞牆撞壁，曲不藏直。',60,'全唐诗/poet.song.99000.json','["撞牆撞壁，曲不藏直。", "摘葉拈花，與儉寧奢。", "羅漢有三毒，如來有二語。", "聾人爭得聞，依舊喫茶去。", "保福老，保福老，鐵眼銅睛還失了。"]'),
('dd10ec51-8158-4ce8-9f60-fa09f2ae4c45','頌古五十七首  其四六','釋道昌','宋','宋诗','song-poetry','','[]','人前慣出手，退三添作九。',50,'全唐诗/poet.song.99000.json','["人前慣出手，退三添作九。", "有眼未嘗看，無家自能走。", "雪峰之句，羚羊掛角。", "作他弟子沒來由，龍蛇陣上看謀略。"]'),
('7b824d09-500e-4a5c-9490-358b30eb1536','頌古五十七首  其四七','釋道昌','宋','宋诗','song-poetry','','[]','明頭便打，暗裏閃過。',52,'全唐诗/poet.song.99000.json','["明頭便打，暗裏閃過。", "盡底活時，死中要坐。", "門外簷間雨滴聲，衆生顛倒逐迷情。", "可憐洎不迷己處，出得身來體未明。"]'),
('1682f0e9-6c5b-4420-a489-1514a1757e4f','頌古五十七首  其四八','釋道昌','宋','宋诗','song-poetry','','[]','針頭削鐵，牛背拔毛。',52,'全唐诗/poet.song.99000.json','["針頭削鐵，牛背拔毛。", "多將少使，冷作熱燒。", "直上法堂便下去，觸忤和尚重解註。", "知是般事休便休，茫茫塞壑與填溝。"]'),
('0f77a71d-a0fc-48f1-bff5-de9a70c01e54','頌古五十七首  其四九','釋道昌','宋','宋诗','song-poetry','','[]','撲落非他，安排不多。',54,'全唐诗/poet.song.99000.json','["撲落非他，安排不多。", "蓋覆自在，隱顯包羅。", "擡頭失卻舊時路，拈篙便上別人渡。", "轉易作難，拔貧成富，千人萬人恁麽去。"]'),
('c0b18dd8-97c5-4bf0-bf39-5db7e21f2b95','頌古五十七首  其五○','釋道昌','宋','宋诗','song-poetry','','[]','塵塵三昧，缽飯桶水。',36,'全唐诗/poet.song.99000.json','["塵塵三昧，缽飯桶水。", "雲門眼中，者僧身裏。", "捏合起來無處藏，𡎺著磕著埋沒你。"]'),
('cc851b86-a76d-4fe1-912e-08331d919b43','頌古五十七首  其五一','釋道昌','宋','宋诗','song-poetry','','[]','盡卻命根，方可關門。',50,'全唐诗/poet.song.99000.json','["盡卻命根，方可關門。", "一挨一拶，電湧雷奔。", "佛法水中月，耳裏眼裏說。", "差之毫釐，失之千里，南北東西知幾幾。"]'),
('1b24dc9e-c5cf-4664-bc91-e0ef0d979ca4','頌古五十七首  其五二','釋道昌','宋','宋诗','song-poetry','','[]','被裏出指，水中露觜。',44,'全唐诗/poet.song.99000.json','["被裏出指，水中露觜。", "屈指眼開，搖觜身起。", "藥病不相治，何須盡大地。", "反笑老雲門，失卻娘生鼻。"]'),
('5115821d-8791-474f-8710-f87a11ac2cf7','頌古五十七首  其五三','釋道昌','宋','宋诗','song-poetry','','[]','將成之山，不進一簣。',52,'全唐诗/poet.song.99000.json','["將成之山，不進一簣。", "老倒雲門，坐而獲利。", "釣鼇釣鯨手段高，慣曾下海涉波濤。", "緩放急收自得便，浮家泛宅何飄飄。"]'),
('eaec17ce-df00-4d09-aec4-22680370c5c5','頌古五十七首  其五四','釋道昌','宋','宋诗','song-poetry','','[]','恰似初生月，兩口無一舌。',56,'全唐诗/poet.song.99000.json','["恰似初生月，兩口無一舌。", "到了曲彎彎，把火入牛欄。", "問他以手便斫額，猴黑誰知有猴白。", "向後失目果然是，要見長人過深水。"]'),
('60552322-580b-4bed-a18d-ed966fca5f86','頌古五十七首  其五五','釋道昌','宋','宋诗','song-poetry','','[]','針頭削鐵，佛面刮金。',20,'全唐诗/poet.song.99000.json','["針頭削鐵，佛面刮金。", "無處若有，出手便驚。"]'),
('5c529e18-734f-46a5-b563-4114b379b8ae','頌古五十七首  其五六','釋道昌','宋','宋诗','song-poetry','','[]','亂走到家來，到家便亂走。',24,'全唐诗/poet.song.99000.json','["亂走到家來，到家便亂走。", "捉得玉麒麟，咬斷別人手。"]'),
('7251d9a7-1280-43a0-b605-b071a811dc2a','頌古五十七首  其五七','釋道昌','宋','宋诗','song-poetry','','[]','絕消息處捉來，有形影中走卻。',54,'全唐诗/poet.song.99000.json','["絕消息處捉來，有形影中走卻。", "只因懶問兒孫，要把襕衫反著。", "坐久成勞，位次已高。", "起時失卻人天相，無限行人認白毫。"]'),
('4130851e-f81c-4b98-a299-41436cab0a8a','偈頌一百六十首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','世出世間希有事，顯發須憑過量人。',32,'全唐诗/poet.song.99000.json','["世出世間希有事，顯發須憑過量人。", "只將補袞調羹手，撥轉如來正法輪。"]'),
('dc8fe89c-178b-44d4-84d8-28fcc3fb4f1d','偈頌一百六十首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','大道只在目前，要且目前難睹。',28,'全唐诗/poet.song.99000.json','["大道只在目前，要且目前難睹。", "欲識大道真體，不離聲色言語。"]'),
('eb74d2a2-7a77-4b04-8076-c6a2ab8bf20b','偈頌一百六十首  其三','釋宗杲','宋','宋诗','song-poetry','','[]','這箇川藞直，自來好打鬨。',56,'全唐诗/poet.song.99000.json','["這箇川藞直，自來好打鬨。", "鬧處便入頭，惡靜而喜動。", "前年今日始歸家，今日前年路不差。", "一回飲水一回噎，一瓣栴檀一碗茶。"]'),
('4b202843-f5f8-4cc8-a01e-1aa5ea5fcfe4','偈頌一百六十首  其四','釋宗杲','宋','宋诗','song-poetry','','[]','水底泥牛嚼生鐵，憍梵鉢提咬著舌。',32,'全唐诗/poet.song.99000.json','["水底泥牛嚼生鐵，憍梵鉢提咬著舌。", "海神怒把珊瑚鞭，須彌山王痛不徹。"]'),
('c5f9f3c5-35a9-4e70-9baa-0c9d16783727','偈頌一百六十首  其五','釋宗杲','宋','宋诗','song-poetry','','[]','衝開碧落松千尺，截斷紅塵水一谿。',32,'全唐诗/poet.song.99000.json','["衝開碧落松千尺，截斷紅塵水一谿。", "不識本來真面目，將謂人題德嶠詩。"]'),
('dca5bb3a-cc5f-4e70-b3c3-4e4d1b705714','偈頌一百六十首  其六','釋宗杲','宋','宋诗','song-poetry','','[]','今朝八月十有五，顧兔天邊誰不睹。',32,'全唐诗/poet.song.99000.json','["今朝八月十有五，顧兔天邊誰不睹。", "若非東土小釋迦，放過長沙這老虎。"]'),
('babce9db-623b-405c-bf2d-6cf022b430c9','偈頌一百六十首  其七','釋宗杲','宋','宋诗','song-poetry','','[]','眼不自見，刀不自割。',54,'全唐诗/poet.song.99000.json','["眼不自見，刀不自割。", "喫飯濟饑，飲水定渴。", "臨濟德山特地迷，枉費精神施棒喝。", "除卻棒，拈卻喝，孟八郎漢，如何止遏。"]'),
('f26063bc-1177-4557-9306-9221cfc0a6b7','偈頌一百六十首  其八','釋宗杲','宋','宋诗','song-poetry','','[]','文彩未彰，消息已露。',20,'全唐诗/poet.song.99000.json','["文彩未彰，消息已露。", "文彩既彰，難爲蓋覆。"]'),
('d86da246-37cc-4f9a-9585-3c5d112554f5','偈頌一百六十首  其九','釋宗杲','宋','宋诗','song-poetry','','[]','不用安排，切莫造作。',52,'全唐诗/poet.song.99000.json','["不用安排，切莫造作。", "造作安排，無繩自縛。", "不安排，不造作，善財彈指登樓閣。", "祕魔放下手中叉，普化入市搖鈴鐸。"]'),
('91baada6-7b42-4bfa-926e-4c474b0acc77','偈頌一百六十首  其一○','釋宗杲','宋','宋诗','song-poetry','','[]','出隊半箇月，眼不見鼻孔。',24,'全唐诗/poet.song.99000.json','["出隊半箇月，眼不見鼻孔。", "失卻祖師禪，拾得箇骨董。"]'),
('c6e02f3d-d3e0-487b-ae91-a5e4910817b0','偈頌一百六十首  其一一','釋宗杲','宋','宋诗','song-poetry','','[]','正朝把筆，萬事皆吉。',44,'全唐诗/poet.song.99000.json','["正朝把筆，萬事皆吉。", "應時納祜，慶無不宜。", "若作世諦，流布平地。", "喫交更在佛法，商量眉鬚墮落。"]'),
('6355b71a-5e03-4927-bb7e-3c61b3b98f59','偈頌一百六十首  其一二','釋宗杲','宋','宋诗','song-poetry','','[]','買鐵得真金，求雨得瑞雪。',52,'全唐诗/poet.song.99000.json','["買鐵得真金，求雨得瑞雪。", "五峰玉琢成，千樹銀華結。", "龍王降吉祥，普賢呈醜拙。", "三世如來祕密門，今日一時都漏泄。"]'),
('3b87023c-138c-4443-8615-4a03ab3ba626','偈頌一百六十首  其一三','釋宗杲','宋','宋诗','song-poetry','','[]','元宵佳節同歡樂，處處咸然無盡燈。',32,'全唐诗/poet.song.99000.json','["元宵佳節同歡樂，處處咸然無盡燈。", "火光爍破勝熱面，夜神忽患冷頭疼。"]'),
('821c2857-3f06-461d-ba41-871276e0cfc2','偈頌一百六十首  其一四','釋宗杲','宋','宋诗','song-poetry','','[]','轉山河大地歸自己則易，轉自己歸山河大地則難。',42,'全唐诗/poet.song.99000.json','["轉山河大地歸自己則易，轉自己歸山河大地則難。", "有人道得不難不易句，卻來徑山手裏請捧喫。"]'),
('c4be11c5-4e3d-4ef4-9e44-7e7af6cf7048','偈頌一百六十首  其一五','釋宗杲','宋','宋诗','song-poetry','','[]','二月仲春，久雨不晴。',20,'全唐诗/poet.song.99000.json','["二月仲春，久雨不晴。", "雲門一劄，德非有鄰。"]'),
('e4bb5a57-9604-46c0-a5c1-f39cc5ed794b','偈頌一百六十首  其一六','釋宗杲','宋','宋诗','song-poetry','','[]','眼空宇宙渾無物，大坐當軒孰敢窺。',32,'全唐诗/poet.song.99000.json','["眼空宇宙渾無物，大坐當軒孰敢窺。", "選佛追官俱已了，同途把手不同歸。"]'),
('d98299b1-eef2-476c-a544-b6c9cdff1d5d','偈頌一百六十首  其一七','釋宗杲','宋','宋诗','song-poetry','','[]','一不成隻，兩不在雙。',20,'全唐诗/poet.song.99000.json','["一不成隻，兩不在雙。", "劍號巨闕，珠稱夜光。"]'),
('572efb58-23fa-4369-84fe-b57b63ac2e41','偈頌一百六十首  其一八','釋宗杲','宋','宋诗','song-poetry','','[]','今朝又是四月一，那事全然沒消息。',32,'全唐诗/poet.song.99000.json','["今朝又是四月一，那事全然沒消息。", "衲僧皮草久不乾，且喜日頭東畔出。"]'),
('2ae444a0-17f8-4521-a113-a792b8756db8','偈頌一百六十首  其一九','釋宗杲','宋','宋诗','song-poetry','','[]','今朝正是四月八，凈飯王宮生悉達。',96,'全唐诗/poet.song.99000.json','["今朝正是四月八，凈飯王宮生悉達。", "吐水九龍天外來，捧足七蓮從地發。", "點胸點肋獨稱尊，大口開張自矜伐。", "都盧往世七旬餘，四十九年恣忉怛。", "賴有雲門老跛師，一棒當時要打殺。", "人人盡道報佛恩，將此深心奉塵剎。"]'),
('2a2a6878-9349-4434-8fe2-5ef389cbb9b7','偈頌一百六十首  其二○','釋宗杲','宋','宋诗','song-poetry','','[]','徑山無寸土莊田，今夏隨宜結衆緣。',48,'全唐诗/poet.song.99000.json','["徑山無寸土莊田，今夏隨宜結衆緣。", "慵論道，懶談禪，拄杖挑來箇箇圓。", "不用息心除妄想。", "大家喫飯了瞳眠。"]'),
('5c9a8465-5803-49da-9c6c-87362c855eee','偈頌一百六十首  其二一','釋宗杲','宋','宋诗','song-poetry','','[]','稽首能度諸世間，無量殊勝福德聚。',32,'全唐诗/poet.song.99000.json','["稽首能度諸世間，無量殊勝福德聚。", "金輪統御四天下，普施群生安隱樂。"]'),
('f52639a5-3047-457c-ad48-09d7e8f0c974','偈頌一百六十首  其二二','釋宗杲','宋','宋诗','song-poetry','','[]','顛倒想生生死續，顛倒想滅生死絕。',32,'全唐诗/poet.song.99000.json','["顛倒想生生死續，顛倒想滅生死絕。", "生死絕處涅槃空，涅槃空處眼中屑。"]'),
('f71eb1c0-2003-4aa8-9516-2fef9e4a57dc','偈頌一百六十首  其二三','釋宗杲','宋','宋诗','song-poetry','','[]','德山棒，臨濟喝，今日爲君重拈掇。',73,'全唐诗/poet.song.99000.json','["德山棒，臨濟喝，今日爲君重拈掇。", "天何高，地何闊，休向糞掃堆上更添搕掩。", "換卻骨，洗卻腸，徑山退身三步，許爾諸人商量。", "紅粉易成端正女，無錢難作好兒郎。"]'),
('d9aed2e2-df99-4a9c-84d1-3fe70ffdbdb9','偈頌一百六十首  其二四','釋宗杲','宋','宋诗','song-poetry','','[]','月生一，鐵輪天子寰中勅。',36,'全唐诗/poet.song.99000.json','["月生一，鐵輪天子寰中勅。", "月生二，豐干騎虎入鬧市。", "月生三，蟭螟眼裏巨鼇翻。"]'),
('91eb7fed-999f-4229-b8fe-771a506a0988','偈頌一百六十首  其二五','釋宗杲','宋','宋诗','song-poetry','','[]','三轉法輪於大千，其輪本來常清凈。',32,'全唐诗/poet.song.99000.json','["三轉法輪於大千，其輪本來常清凈。", "天人得道此爲證，三寶於是現世間。"]'),
('c7eddfec-fc6c-4d7e-b3e3-706625837220','偈頌一百六十首  其二六','釋宗杲','宋','宋诗','song-poetry','','[]','超然居士設粥，供養一堂龍象。',28,'全唐诗/poet.song.99000.json','["超然居士設粥，供養一堂龍象。", "喫了掛起鉢盂，好箇西來榜樣。"]'),
('fb33c892-6b55-46df-a74a-a509cace2269','偈頌一百六十首  其二七','釋宗杲','宋','宋诗','song-poetry','','[]','去年人看中秋月，今年人看中秋月。',32,'全唐诗/poet.song.99000.json','["去年人看中秋月，今年人看中秋月。", "今年人是去年人，去年月是今年月。"]'),
('325143a0-fabd-47b8-ac65-7ba7cb6abeb1','偈頌一百六十首  其二八','釋宗杲','宋','宋诗','song-poetry','','[]','今朝九月初五，天色半晴半雨。',56,'全唐诗/poet.song.99000.json','["今朝九月初五，天色半晴半雨。", "衲僧鼻孔眼睛，切忌和泥合土。", "惺惺直是惺惺，靈利不妨靈利。", "等閑問著十人，五雙不知落處。"]'),
('e0efea55-b72e-48d8-b094-3c43abb4d313','偈頌一百六十首  其二九','釋宗杲','宋','宋诗','song-poetry','','[]','臘月十五天降雪，爲瑞爲祥無空闕。',32,'全唐诗/poet.song.99000.json','["臘月十五天降雪，爲瑞爲祥無空闕。", "文殊露出廣長舌，普賢大士得一橛。"]'),
('cf39fd93-2c2e-43fa-b3ca-6a58d27077c0','偈頌一百六十首  其三○','釋宗杲','宋','宋诗','song-poetry','','[]','今朝臘月二十五，諸方盡唱雲門曲。',32,'全唐诗/poet.song.99000.json','["今朝臘月二十五，諸方盡唱雲門曲。", "徑山隨例和一聲，莫言楚石不當玉。"]'),
('8601d68e-c812-44a3-bb7c-a6473ce1c9fa','偈頌一百六十首  其三一','釋宗杲','宋','宋诗','song-poetry','','[]','正月十四十五，雙徑椎鑼打鼓。',28,'全唐诗/poet.song.99000.json','["正月十四十五，雙徑椎鑼打鼓。", "要識祖意西來，看取村歌社舞。"]'),
('3235b18f-07ba-4f04-8f33-038732973b54','偈頌一百六十首  其三二','釋宗杲','宋','宋诗','song-poetry','','[]','纔方改歲賀新年，今朝又是二月一。',32,'全唐诗/poet.song.99000.json','["纔方改歲賀新年，今朝又是二月一。", "入所證處沒商量，摩訶般若波羅蜜。"]'),
('43ef3858-50af-4b8d-9db1-97431b6f814e','偈頌一百六十首  其三三','釋宗杲','宋','宋诗','song-poetry','','[]','金佛不度鑪。',24,'全唐诗/poet.song.99000.json','["金佛不度鑪。", "木佛不度火。", "泥佛不度水，真佛屋裏坐。"]'),
('1fe6fa5f-c80b-49d6-9487-721a0e381cca','偈頌一百六十首  其三四','釋宗杲','宋','宋诗','song-poetry','','[]','毘藍園裏不曾生，雙林樹下何曾滅。',32,'全唐诗/poet.song.99000.json','["毘藍園裏不曾生，雙林樹下何曾滅。", "不生不滅見瞿曇，眼中又是重添屑。"]'),
('05246173-deba-4eca-b50b-dda73349b714','偈頌一百六十首  其三五','釋宗杲','宋','宋诗','song-poetry','','[]','身口意清凈，是名佛出世。',24,'全唐诗/poet.song.99000.json','["身口意清凈，是名佛出世。", "身口意不凈，是名佛滅度。"]'),
('7661afd0-9ded-4975-902a-f44bccdc179c','偈頌一百六十首  其三六','釋宗杲','宋','宋诗','song-poetry','','[]','四月二十五，久晴忽爾雨。',54,'全唐诗/poet.song.99000.json','["四月二十五，久晴忽爾雨。", "竺士大仙心，東西密相付。", "這箇猶是時節因緣，未是衲僧門下消息。", "北山老大蟲，咬殺南山虎。"]'),
('b552d3b9-7df5-4331-9e18-79be46e5c37b','偈頌一百六十首  其三七','釋宗杲','宋','宋诗','song-poetry','','[]','何似生，莫妄想。',22,'全唐诗/poet.song.99000.json','["何似生，莫妄想。", "直饒透出古今，也是猢猻伎倆。"]'),
('c6a567d6-0acf-44a9-80a6-e5679023b4cd','偈頌一百六十首  其三八','釋宗杲','宋','宋诗','song-poetry','','[]','生是死之生，死是生之死。',46,'全唐诗/poet.song.99000.json','["生是死之生，死是生之死。", "兩路坦然平，無彼復無此。", "既無生死，又無彼此。", "明明百草頭，明明祖師意。"]'),
('d53ae1a0-de01-4bb9-80c1-bcd85b9f1ebf','偈頌一百六十首  其三九','釋宗杲','宋','宋诗','song-poetry','','[]','如天普蓋，似地普擎。',20,'全唐诗/poet.song.99000.json','["如天普蓋，似地普擎。", "一念相應，一時清凈。"]'),
('7a1f2934-95af-4031-bee5-b91ad7535bbb','偈頌一百六十首  其四○','釋宗杲','宋','宋诗','song-poetry','','[]','法是常法，道是常道。',20,'全唐诗/poet.song.99000.json','["法是常法，道是常道。", "拶破面門，點即不到。"]'),
('093c70d1-7e92-4149-83c4-6f6c1fdeee6a','偈頌一百六十首  其四一','釋宗杲','宋','宋诗','song-poetry','','[]','四月十五這公案，七月十五方結絕。',32,'全唐诗/poet.song.99000.json','["四月十五這公案，七月十五方結絕。", "即今這裏許多人，人人有理難分雪。"]'),
('79486011-eec6-47e7-b69e-974d9a010cba','偈頌一百六十首  其四二','釋宗杲','宋','宋诗','song-poetry','','[]','拆去東籬，補起西壁。',44,'全唐诗/poet.song.99000.json','["拆去東籬，補起西壁。", "徑山門下，全無準的。", "有店的，誰委悉。", "僧堂覷破香積廚，鴟吻咬殺佛殿脊。"]'),
('1e037791-f7f6-41dd-a690-f964d410bf2d','偈頌一百六十首  其四三','釋宗杲','宋','宋诗','song-poetry','','[]','秋江清淺時，白露和煙島。',24,'全唐诗/poet.song.99000.json','["秋江清淺時，白露和煙島。", "良哉觀世音，全身入荒草。"]'),
('cdb7c14b-4997-438d-a730-36e6bca42c0c','偈頌一百六十首  其四四','釋宗杲','宋','宋诗','song-poetry','','[]','處處真，處處真，塵塵盡是本來人。',32,'全唐诗/poet.song.99000.json','["處處真，處處真，塵塵盡是本來人。", "真實說時聲不現，正體堂堂沒卻身。"]'),
('944a8ea1-adb3-4868-8a49-034fa50d881b','偈頌一百六十首  其四五','釋宗杲','宋','宋诗','song-poetry','','[]','三箇與四箇，七箇與八箇。',52,'全唐诗/poet.song.99000.json','["三箇與四箇，七箇與八箇。", "數目甚分明，無人數得過。", "既是數目分明，爲甚麽無人數得過。", "道士著白襴，且非真措大。"]'),
('4247287c-423d-46a0-af6a-66d520e4f377','偈頌一百六十首  其四六','釋宗杲','宋','宋诗','song-poetry','','[]','一喝分賓主，照用一時行。',24,'全唐诗/poet.song.99000.json','["一喝分賓主，照用一時行。", "要會箇中意，日午打三更。"]'),
('71b4db02-fbc0-4829-b857-2f3e117670cb','偈頌一百六十首  其四七','釋宗杲','宋','宋诗','song-poetry','','[]','新歲擊新鼓，普施新法雨。',82,'全唐诗/poet.song.99000.json','["新歲擊新鼓，普施新法雨。", "萬物盡從新，一一就規矩。", "普賢大士欣歡，乘時打開門戶。", "放出白象王，遍地無尋處。", "唯有這箇，不屬故新。", "等閑開口，吞卻法身。", "千年桃核裏，元是舊時仁。"]'),
('732048f9-02d3-43fe-b937-90e92f9007b6','偈頌一百六十首  其四八','釋宗杲','宋','宋诗','song-poetry','','[]','今朝正月半，有則舊公案。',24,'全唐诗/poet.song.99000.json','["今朝正月半，有則舊公案。", "點起數碗燈，打鼓普請看。"]'),
('48d0c842-627d-41b8-b09d-3ef793ab74a0','偈頌一百六十首  其四九','釋宗杲','宋','宋诗','song-poetry','','[]','投子下繩床，今朝爲舉揚。',24,'全唐诗/poet.song.99000.json','["投子下繩床，今朝爲舉揚。", "驢前馬後漢，切忌亂承當。"]'),
('1d852693-5ec6-486a-826e-37b5f8226b27','偈頌一百六十首  其五○','釋宗杲','宋','宋诗','song-poetry','','[]','無邊剎境，自他不隔於毫端。',42,'全唐诗/poet.song.99000.json','["無邊剎境，自他不隔於毫端。", "十世古今，始終不離於當念。", "丈夫自有衝天志，休向如來行處行。"]'),
('314396ca-7ebd-4c92-9e3e-ef469755cdc0','偈頌一百六十首  其五一','釋宗杲','宋','宋诗','song-poetry','','[]','驅耕夫之牛，奪饑人之食。',43,'全唐诗/poet.song.99000.json','["驅耕夫之牛，奪饑人之食。", "趯翻大海水，拳倒須彌盧。", "生擒虎兕，活捉獰龍，猶未是衲僧本分事。"]'),
('f23f5f93-cac6-4035-81a9-09ffe64094f4','偈頌一百六十首  其五二','釋宗杲','宋','宋诗','song-poetry','','[]','觀音妙智力，能救世間苦。',24,'全唐诗/poet.song.99000.json','["觀音妙智力，能救世間苦。", "百華開爛熳，覷見沒可睹。"]'),
('a82fcc08-8c98-4d40-8033-759f6d7034ea','偈頌一百六十首  其五三','釋宗杲','宋','宋诗','song-poetry','','[]','大家潑一杓惡水，洗滌如來凈邊垢。',32,'全唐诗/poet.song.99000.json','["大家潑一杓惡水，洗滌如來凈邊垢。", "垢盡衆生煩惱除，狐貍便作師子吼。"]'),
('cfaf14ac-d73a-42a9-896e-91c756fcd3bb','偈頌一百六十首  其五四','釋宗杲','宋','宋诗','song-poetry','','[]','法身報身化身，咄哉魍魎妖精。',28,'全唐诗/poet.song.99000.json','["法身報身化身，咄哉魍魎妖精。", "三眼國中逢著，笑殺無位真人。"]'),
('75c31686-bb6b-44df-8f78-dd80210f5785','偈頌一百六十首  其五五','釋宗杲','宋','宋诗','song-poetry','','[]','棒打石人頭，曝曝論實事。',24,'全唐诗/poet.song.99000.json','["棒打石人頭，曝曝論實事。", "不用作禪會，不用作道會。"]'),
('0cb51d45-9ff8-4acd-a337-8e7a48b3e0a3','偈頌一百六十首  其五六','釋宗杲','宋','宋诗','song-poetry','','[]','二尊宿，一人粗似丘山，一人細如米末。',52,'全唐诗/poet.song.99000.json','["二尊宿，一人粗似丘山，一人細如米末。", "雖然粗細不同，稱來輕重恰好。", "徑山今日內實告報，汝等諸人切忌鑽龜打瓦。"]'),
('9df02993-8574-4040-b3c1-d9ab00369c5f','偈頌一百六十首  其五七','釋宗杲','宋','宋诗','song-poetry','','[]','山前一片閑田地，元來記得在。',52,'全唐诗/poet.song.99000.json','["山前一片閑田地，元來記得在。", "叉手叮嚀問祖翁，只爲契券不分明。", "幾度賣來還自買，難爲牙保人，爲憐松竹引清風。"]'),
('387925b2-135b-46b8-97bf-4dbdc7dc5624','偈頌一百六十首  其五八','釋宗杲','宋','宋诗','song-poetry','','[]','即念離念，覺與非覺。',30,'全唐诗/poet.song.99000.json','["即念離念，覺與非覺。", "有心無心，若善若惡。", "攪成一塊，將錯就錯。"]'),
('ac8bab52-161b-4c1e-90aa-eb894d4d0c80','偈頌一百六十首  其五九','釋宗杲','宋','宋诗','song-poetry','','[]','摩竭提國猶在半途，少室峰前全無巴鼻。',36,'全唐诗/poet.song.99000.json','["摩竭提國猶在半途，少室峰前全無巴鼻。", "談玄說妙好肉剜瘡，舉古明今拋沙撒土。"]'),
('f75939b8-9def-4da2-8216-e61b04067045','偈頌一百六十首  其六○','釋宗杲','宋','宋诗','song-poetry','','[]','南泉無過，口能招禍。',40,'全唐诗/poet.song.99000.json','["南泉無過，口能招禍。", "趙州禮拜，草賊大敗。", "徑山不管，結案據款。", "文殊普賢，且過一邊。"]'),
('01ae73d5-ce35-431e-ac35-5523b38f4556','偈頌一百六十首  其六一','釋宗杲','宋','宋诗','song-poetry','','[]','百二十日夏，日日無空缺。',36,'全唐诗/poet.song.99000.json','["百二十日夏，日日無空缺。", "露柱逞神通，燈籠呈醜拙。", "徹不徹，卻來棒頭爲汝決。"]'),
('0fd16841-ef7b-4c03-ae38-f6137f203b70','偈頌一百六十首  其六二','釋宗杲','宋','宋诗','song-poetry','','[]','國清才子貴，家富小兒嬌。',24,'全唐诗/poet.song.99000.json','["國清才子貴，家富小兒嬌。", "大家出隻手，彼此不相饒。"]'),
('ee505a89-6d04-4d43-a2a0-fe407ab2adef','偈頌一百六十首  其六三','釋宗杲','宋','宋诗','song-poetry','','[]','鎮州蘿蔔從來大，青州布衫斤兩明。',32,'全唐诗/poet.song.99000.json','["鎮州蘿蔔從來大，青州布衫斤兩明。", "衲子聚頭求的旨，卻似蚊虻咬鐵釘。"]'),
('ab42a369-5c7d-4be5-91ec-82fccb4fae4e','偈頌一百六十首  其六四','釋宗杲','宋','宋诗','song-poetry','','[]','今朝四月初一，衲僧放楖栗。',27,'全唐诗/poet.song.99000.json','["今朝四月初一，衲僧放楖栗。", "雖然不許默照，須要人人面壁。"]'),
('30105e59-acc8-4dfd-a69b-8bceb7d62edf','偈頌一百六十首  其六五','釋宗杲','宋','宋诗','song-poetry','','[]','芭蕉無耳聞雷開，葵華無眼隨日轉。',32,'全唐诗/poet.song.99000.json','["芭蕉無耳聞雷開，葵華無眼隨日轉。", "釋迦老子亦無生，每歲今朝浴一遍。"]'),
('ce1fe481-eb1e-4568-bddc-3ff8bf99f841','偈頌一百六十首  其六六','釋宗杲','宋','宋诗','song-poetry','','[]','文殊三處安居，誌公不是閑和尚。',29,'全唐诗/poet.song.99000.json','["文殊三處安居，誌公不是閑和尚。", "迦葉欲行正令，未免眼前見鬼。"]'),
('f431e07d-a466-4475-8ccb-b11adeb5a4fb','偈頌一百六十首  其六七','釋宗杲','宋','宋诗','song-poetry','','[]','今朝又是端千節，文殊善財忙不徹。',54,'全唐诗/poet.song.99000.json','["今朝又是端千節，文殊善財忙不徹。", "殺人活人藥不靈，自添腦後三斤鐵。", "觀音妙智力，能救世間苦。", "是甚麽，鐵蛇鑽入土。"]'),
('6fdb8ef1-982f-4f60-872e-f3c6321fd007','偈頌一百六十首  其六八','釋宗杲','宋','宋诗','song-poetry','','[]','馬師仲冬嚴寒，國一孟夏漸熱。',28,'全唐诗/poet.song.99000.json','["馬師仲冬嚴寒，國一孟夏漸熱。", "雖然寒熱不同，彼此不失時節。"]'),
('c47fcc41-5e17-4090-a249-e7ced09e0042','偈頌一百六十首  其六九','釋宗杲','宋','宋诗','song-poetry','','[]','高在絕頂，富在福嚴。',33,'全唐诗/poet.song.99000.json','["高在絕頂，富在福嚴。", "樂在天堂，苦在地獄。", "誰知席帽下，元是昔愁容的。"]'),
('4057d466-2345-4823-9bed-327428508894','偈頌一百六十首  其七○','釋宗杲','宋','宋诗','song-poetry','','[]','相逢不拈出，舉意便知有。',40,'全唐诗/poet.song.99000.json','["相逢不拈出，舉意便知有。", "巍巍不動尊，腳不離地走。", "依稀似曲纔堪聽，又被風吹別調中。"]'),
('8746c633-b089-434d-a1bf-842c9ff70779','偈頌一百六十首  其七一','釋宗杲','宋','宋诗','song-poetry','','[]','丹霞燒木佛，院主眉鬚落。',34,'全唐诗/poet.song.99000.json','["丹霞燒木佛，院主眉鬚落。", "烏飛毛墜，魚行水濁。", "要識真麒麟，只有一隻角。"]'),
('42c30915-13ee-437c-a5f0-718b3151a181','偈頌一百六十首  其七二','釋宗杲','宋','宋诗','song-poetry','','[]','一年三百六十日，今朝又是從頭起。',55,'全唐诗/poet.song.99000.json','["一年三百六十日，今朝又是從頭起。", "人人有箇主人公，水牛銜卻老鼠尾。", "深沙歡，那吒喜。", "佛殿走出門去，僧堂撞入廚庫裏。"]'),
('56f32e19-ae19-4e66-8b52-44ea28d6f2e9','偈頌一百六十首  其七三','釋宗杲','宋','宋诗','song-poetry','','[]','黄龍此語蓋天地，從來縝密不通風。',32,'全唐诗/poet.song.99000.json','["黄龍此語蓋天地，從來縝密不通風。", "後昆隨例承其響，總道貓兒解捉蟲。"]'),
('3f95daa5-151c-476b-aad1-10f858916e2f','偈頌一百六十首  其七四','釋宗杲','宋','宋诗','song-poetry','','[]','平常無生句，妙玄無私句，體明無盡句。',30,'全唐诗/poet.song.99000.json','["平常無生句，妙玄無私句，體明無盡句。", "一鏃破三關，他家有本據。"]'),
('b2646f9b-7396-4b77-9133-7ac0ad98eccd','偈頌一百六十首  其七五','釋宗杲','宋','宋诗','song-poetry','','[]','一人只知看雨，一人只知指雨。',28,'全唐诗/poet.song.99000.json','["一人只知看雨，一人只知指雨。", "子細檢點將來，大似釘椿搖櫓。"]'),
('f8e5c61d-40c9-4bbd-82e2-442ae3953681','偈頌一百六十首  其七六','釋宗杲','宋','宋诗','song-poetry','','[]','今朝二月二十，又是清明寒食。',43,'全唐诗/poet.song.99000.json','["今朝二月二十，又是清明寒食。", "靈雲不見桃華，爭信曲中有直。", "是曲耶，是直耶，多虛不如少實。"]'),
('30d926b2-06b3-468c-abf5-998173ee8c12','偈頌一百六十首  其七七','釋宗杲','宋','宋诗','song-poetry','','[]','結夏方得五日，露柱卻知端的。',28,'全唐诗/poet.song.99000.json','["結夏方得五日，露柱卻知端的。", "勃跳撞入燈籠，普爲諸人入室。"]'),
('95acbc03-8b47-466c-bf77-4a726d141e7d','偈頌一百六十首  其七八','釋宗杲','宋','宋诗','song-poetry','','[]','如人持尺量虛空，復有隨行計其數。',32,'全唐诗/poet.song.99000.json','["如人持尺量虛空，復有隨行計其數。", "虛空邊際不可得，吾君壽量亦如是。"]'),
('0e146db1-5fe2-4172-95fc-248db4c2286c','偈頌一百六十首  其七九','釋宗杲','宋','宋诗','song-poetry','','[]','今朝五月五，天降沛然雨。',36,'全唐诗/poet.song.99000.json','["今朝五月五，天降沛然雨。", "艾人與門神，聚頭相耳語。", "雪竇禪師來，一口吞佛祖。"]'),
('ac440ed9-6cbc-4fb3-b99d-0450556f04bc','偈頌一百六十首  其八○','釋宗杲','宋','宋诗','song-poetry','','[]','一箇驢鳴兩箇賊，堪與諸方爲軌則。',32,'全唐诗/poet.song.99000.json','["一箇驢鳴兩箇賊，堪與諸方爲軌則。", "正賊草賊不須論，大施門開無壅塞。"]'),
('688dda2c-b2b0-4300-a505-cbd708d72956','偈頌一百六十首  其八一','釋宗杲','宋','宋诗','song-poetry','','[]','已著槽廠，將錯就錯。',52,'全唐诗/poet.song.99000.json','["已著槽廠，將錯就錯。", "騎卻聖僧，不妨快樂。", "龍象蹴蹋，非驢所作。", "堪笑諸方，妄生穿鑿。", "休穿鑿，祥麟只有一隻角。"]'),
('5fe3b975-93b6-4062-b2a2-5466f3472a73','偈頌一百六十首  其八二','釋宗杲','宋','宋诗','song-poetry','','[]','今朝七月五，打鼓普請看。',24,'全唐诗/poet.song.99000.json','["今朝七月五，打鼓普請看。", "萬里無片雲，猶欠一大半。"]'),
('2c219011-ea44-4884-a327-94a84c45b33d','偈頌一百六十首  其八三','釋宗杲','宋','宋诗','song-poetry','','[]','久雨不最，纔晴又雨。',30,'全唐诗/poet.song.99000.json','["久雨不最，纔晴又雨。", "天道變化，萬物得所。", "雲門老漢，不在裏許。"]'),
('a3bbdf72-88aa-4347-a2b9-cd9acc67a4da','偈頌一百六十首  其八四','釋宗杲','宋','宋诗','song-poetry','','[]','皎潔一輪，寒光萬里。',67,'全唐诗/poet.song.99000.json','["皎潔一輪，寒光萬里。", "靈利者葉落知秋，傝䢆者忠言逆耳。", "休不休，已不已，小釋迦有陷虎之機，老大蟲卻無牙齒。", "當時一蹋豈造次，驀然倒地非偶爾。"]'),
('6ed9c28a-7eb0-4cd0-8ea3-a3c6738a9ac1','偈頌一百六十首  其八五','釋宗杲','宋','宋诗','song-poetry','','[]','趙州東院西，密室爛如泥。',36,'全唐诗/poet.song.99000.json','["趙州東院西，密室爛如泥。", "竇八布衫穿，赤土畫簸箕。", "簷頭雨滴滴，雞向五更啼。"]'),
('423d92bf-7344-4891-be8b-d08fd5ea13fc','偈頌一百六十首  其八六','釋宗杲','宋','宋诗','song-poetry','','[]','昨朝殘臘盡，今日賀新年。',40,'全唐诗/poet.song.99000.json','["昨朝殘臘盡，今日賀新年。", "虎逐牛方急，東君令已行。", "瑞雪已鋪銀世界，大家攜手普賢門。"]'),
('604786f4-908a-4b30-84db-e328f6947d8e','偈頌一百六十首  其八七','釋宗杲','宋','宋诗','song-poetry','','[]','妙喜與師兄，俱是圜悟子。',86,'全唐诗/poet.song.99000.json','["妙喜與師兄，俱是圜悟子。", "妙喜移住徑山，師兄遷來在此。", "雖與師兄同條生，不與師兄同條死。", "八兩與半斤，青紅對碧紫。", "師兄解唱泥牛吼，師弟寧忘木馬嘶。", "豁開頂上活人眼，鄮山山下是真歸。"]'),
('b7c05e21-62bb-4141-8a03-8ce5b68cee44','偈頌一百六十首  其八八','釋宗杲','宋','宋诗','song-poetry','','[]','達磨不來東土，二祖不住西天。',28,'全唐诗/poet.song.99000.json','["達磨不來東土，二祖不住西天。", "人人常光現前，箇箇壁立萬仞。"]'),
('93680d44-58f2-42c1-9a07-b80b6684a4f6','偈頌一百六十首  其八九','釋宗杲','宋','宋诗','song-poetry','','[]','善法堂前瑞氣新，天書來自九重城。',32,'全唐诗/poet.song.99000.json','["善法堂前瑞氣新，天書來自九重城。", "唯憑一句無私語，上祝吾皇億萬春。"]'),
('28f4bc75-7003-42ea-b2be-7228b08eae5d','偈頌一百六十首  其九○','釋宗杲','宋','宋诗','song-poetry','','[]','今朝三月十五，已得如膏之雨。',28,'全唐诗/poet.song.99000.json','["今朝三月十五，已得如膏之雨。", "農夫鼓腹歌謠，萬象森羅起舞。"]'),
('2f71b540-ae8c-435a-8c9c-6cbf78efad0d','偈頌一百六十首  其九一','釋宗杲','宋','宋诗','song-poetry','','[]','佛子住此地，則是佛受用。',24,'全唐诗/poet.song.99000.json','["佛子住此地，則是佛受用。", "常在於其中，經行及坐臥。"]'),
('c5071052-5ee7-4de0-84cb-b00d68aae955','偈頌一百六十首  其九二','釋宗杲','宋','宋诗','song-poetry','','[]','文遠在驢糞中過夏，面赤不如語直。',52,'全唐诗/poet.song.99000.json','["文遠在驢糞中過夏，面赤不如語直。", "趙州貪他小利，贏得箇餬餅。", "檢點將來，也是普州人送賊。", "鵝王擇乳，素非鴨類。"]'),
('401f4f03-ef96-457f-8e5f-b38079163fc4','偈頌一百六十首  其九三','釋宗杲','宋','宋诗','song-poetry','','[]','正說知見時，知見即是心。',24,'全唐诗/poet.song.99000.json','["正說知見時，知見即是心。", "當心即知見，知見即如今。"]'),
('3fca3396-b3e0-494b-9ce0-ee061b0a5692','偈頌一百六十首  其九四','釋宗杲','宋','宋诗','song-poetry','','[]','萬里無寸草，出門便是草，各自有公據。',42,'全唐诗/poet.song.99000.json','["萬里無寸草，出門便是草，各自有公據。", "有公據，何拘束，清風月下守株人，涼兔漸遙春草綠。"]'),
('280bbe3c-01c6-4ebf-8596-da551fe1a12e','偈頌一百六十首  其九五','釋宗杲','宋','宋诗','song-poetry','','[]','人有心看月，月無心照人。',24,'全唐诗/poet.song.99000.json','["人有心看月，月無心照人。", "有無成一片，方始得惺惺。"]'),
('205b19de-64a0-4e5e-bb76-daee85166594','偈頌一百六十首  其九六','釋宗杲','宋','宋诗','song-poetry','','[]','纔方八月中秋，又是九月十五。',28,'全唐诗/poet.song.99000.json','["纔方八月中秋，又是九月十五。", "唯有這箇不遷，一衆耳聞目睹。"]'),
('46f9fbd7-446b-4c5b-a65e-b65175407570','偈頌一百六十首  其九七','釋宗杲','宋','宋诗','song-poetry','','[]','一二三四五，五四三二一。',36,'全唐诗/poet.song.99000.json','["一二三四五，五四三二一。", "返覆數千回，總不出今日。", "霜風刮地來，法身赤骨𩪸。"]'),
('b393b49d-f110-475b-b187-bc614acc3176','偈頌一百六十首  其九八','釋宗杲','宋','宋诗','song-poetry','','[]','去是住時因，住是去時果。',24,'全唐诗/poet.song.99000.json','["去是住時因，住是去時果。", "去住與果因，無可無不可。"]'),
('cc16c846-6d46-4be4-8b8a-a71eca21b2c1','偈頌一百六十首  其九九','釋宗杲','宋','宋诗','song-poetry','','[]','心同虛空界，示等虛空法。',24,'全唐诗/poet.song.99000.json','["心同虛空界，示等虛空法。", "證得虛空時，無是無非法。"]'),
('b8cb9f40-4ec5-4378-8ab2-ee6c7e288f8e','偈頌一百六十首  其一○○','釋宗杲','宋','宋诗','song-poetry','','[]','今朝又是五月五，大鬼拍手小鬼舞。',66,'全唐诗/poet.song.99000.json','["今朝又是五月五，大鬼拍手小鬼舞。", "驀然撞著桃符神，兩手椎胸叫冤苦。", "艾人云：休叫苦，只有一處堪回互。", "回互不回互，回而更相涉，不爾依位住。"]'),
('f18622c6-54c3-41b2-89ca-6d2208874491','偈頌一百六十首  其一○一','釋宗杲','宋','宋诗','song-poetry','','[]','今朝又是六月半，記得一則舊公案。',56,'全唐诗/poet.song.99000.json','["今朝又是六月半，記得一則舊公案。", "拄杖子吞卻法身，露柱在傍偷眼看。", "看不看，拈起秦時𨍏轢鑽。", "萬別與千差，吾道一以貫。"]'),
('968ef7fe-80ed-4df7-a43d-3ddf77972987','偈頌一百六十首  其一○二','釋宗杲','宋','宋诗','song-poetry','','[]','一百二十日禁足，三十五日在外走。',64,'全唐诗/poet.song.99000.json','["一百二十日禁足，三十五日在外走。", "熨斗煎茶銚不同，泥牛解作師子吼。", "今朝法歲已周圓，拈得鼻孔失卻口。", "以大圓覺爲伽藍，七七依前四十九。"]'),
('2f6d8a12-842e-4f3b-9754-c9c68282c41a','偈頌一百六十首  其一○三','釋宗杲','宋','宋诗','song-poetry','','[]','秋江清淺時，白露和煙島。',44,'全唐诗/poet.song.99000.json','["秋江清淺時，白露和煙島。", "良哉觀世音，春身入荒草。", "在荒草，不須討。", "不識大歌妻，元來是嫂嫂。"]'),
('075851d7-96fd-47dc-a0f5-f71b427f4c82','偈頌一百六十首  其一○四','釋宗杲','宋','宋诗','song-poetry','','[]','門外春將半，山房總不知。',24,'全唐诗/poet.song.99000.json','["門外春將半，山房總不知。", "可憐拄杖子，暗裏自抽枝。"]'),
('e65abc35-b8d2-4faa-83ad-bcf5e86608d4','偈頌一百六十首  其一○五','釋宗杲','宋','宋诗','song-poetry','','[]','乾峰洗面摸著鼻，雲門喫飯咬著沙。',32,'全唐诗/poet.song.99000.json','["乾峰洗面摸著鼻，雲門喫飯咬著沙。", "二人驀地相逢著，元來卻是舊讎家。"]'),
('84b352d9-7081-4f89-a261-5b2af922c3e8','偈頌一百六十首  其一○六','釋宗杲','宋','宋诗','song-poetry','','[]','撲落非他物，縱橫不是塵。',24,'全唐诗/poet.song.99000.json','["撲落非他物，縱橫不是塵。", "山河及大地，全露法王身。"]'),
('c91d6f51-4bc9-499c-9ef2-7b3fb0e51947','偈頌一百六十首  其一○八','釋宗杲','宋','宋诗','song-poetry','','[]','十方法界至人口，法界所有即其舌。',112,'全唐诗/poet.song.99000.json','["十方法界至人口，法界所有即其舌。", "只憑此口與舌頭，祝吾君壽無間歇。", "億萬斯年注福源，如海滉漾永不竭。", "師子窟內產狻猊，鸑鷟定出丹山穴。", "爲瑞爲祥遍九垓，草木昆蟲盡歡悅。", "稽首不可思議事，喻若衆星拱明月。", "故今宣暢妙伽陀，第一義中真實說。"]'),
('def6f6ae-dae9-4836-8383-3d7fd88eb7fb','偈頌一百六十首  其一○九','釋宗杲','宋','宋诗','song-poetry','','[]','一別二十年，驀地又相見。',48,'全唐诗/poet.song.99000.json','["一別二十年，驀地又相見。", "如百煉精金，始終色不變。", "請我轉法輪，增長菩提願。", "直下絕狐疑，便悟本來面。"]'),
('0a7d6832-1579-4218-b490-a11b28b7ef0f','偈頌一百六十首  其一一○','釋宗杲','宋','宋诗','song-poetry','','[]','老胡九年話墮，可惜當時放過。',54,'全唐诗/poet.song.99000.json','["老胡九年話墮，可惜當時放過。", "致令默照之徒，鬼窟長年打坐。", "這一箇，那一箇，更一箇。", "雖然苦口叮嚀，卻似樹頭風過。"]'),
('8f094894-8765-43c6-b087-9b9e6513fbfe','偈頌一百六十首  其一一一','釋宗杲','宋','宋诗','song-poetry','','[]','一年一度解，一年一度結。',36,'全唐诗/poet.song.99000.json','["一年一度解，一年一度結。", "只是這箇事，何須更多說。", "不多說，蹋著秤鎚硬似鐵。"]'),
('fff54967-3fdc-4065-9dea-2e0cecbdafb6','偈頌一百六十首  其一一二','釋宗杲','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',73,'全唐诗/poet.song.99000.json','["有句無句，如藤倚樹。", "孟八郎漢，便恁麽去。", "機不到，語不副。", "眼裏著得百千萬億須彌山，耳裏著得無量無邊香水海。", "機副語語投機，眼裏著沙不得，耳裏著水不得。"]'),
('9a61e5de-94c2-4480-a1e6-1b6d2711ef3d','偈頌一百六十首  其一一三','釋宗杲','宋','宋诗','song-poetry','','[]','南泉放倒，雲門扶起。',34,'全唐诗/poet.song.99000.json','["南泉放倒，雲門扶起。", "放倒扶起，有賓有主。", "明眼衲僧商量，切忌別作道理。"]'),
('ecb69a39-61a6-4636-90a8-171b22b02971','偈頌一百六十首  其一一四','釋宗杲','宋','宋诗','song-poetry','','[]','諸法本來絕待，觸目且拘礙。',155,'全唐诗/poet.song.99000.json','["諸法本來絕待，觸目且拘礙。", "只因斷臂覓心，便有人求懺罪。", "無文印子既成，付法傳衣廝賴。", "致令盧老黄梅，墜石腰間舂碓。", "將謂有法與人，問著卻言不會。", "引得後代兒孫，盡作韓獹逐塊。", "雖欲扶豎宗乘，奈何東倒西傫。", "子細檢點將來，直是令人叵耐。", "若也盡令而行，一擊須教粉碎。", "有時靜坐思量，就中也有可愛。", "深沙共脩羅結親，金剛與土地指背。"]'),
('ad99f486-7563-4d0f-8d4b-616aa492657e','偈頌一百六十首  其一一五','釋宗杲','宋','宋诗','song-poetry','','[]','細不通風，大通車馬。',48,'全唐诗/poet.song.99000.json','["細不通風，大通車馬。", "突出當陽，孰辨真假。", "虛空有欛柄，無手人能把。", "跛驢蹋倒摘茶輪，草菴卸下瑠璃瓦。"]'),
('807967b2-14a2-4d57-b44e-bdf8a73835f0','偈頌一百六十首  其一一六','釋宗杲','宋','宋诗','song-poetry','','[]','洞山萬里一條鐵，瀏陽一擊百雜碎。',32,'全唐诗/poet.song.99000.json','["洞山萬里一條鐵，瀏陽一擊百雜碎。", "雲門關字常現前，翠巖眉毛在不在。"]'),
('206ee40e-b336-4ba8-b7b1-afe83c117c6d','偈頌一百六十首  其一一七','釋宗杲','宋','宋诗','song-poetry','','[]','法法本來法，無法無非法。',24,'全唐诗/poet.song.99000.json','["法法本來法，無法無非法。", "何於一法中，有法有不法。"]'),
('4e656623-6e56-459f-9e2b-0cc15daa55ba','偈頌一百六十首  其一一八','釋宗杲','宋','宋诗','song-poetry','','[]','或是或非人不識，逆行順行天莫測。',32,'全唐诗/poet.song.99000.json','["或是或非人不識，逆行順行天莫測。", "隔山人唱鷓鴣詞，錯認胡笳十八拍。"]'),
('bfaf01db-98ff-4e24-a352-bd8081d85c8f','偈頌一百六十首  其一一九','釋宗杲','宋','宋诗','song-poetry','','[]','荆棘林中善卷舒，更於驪頷探神珠。',32,'全唐诗/poet.song.99000.json','["荆棘林中善卷舒，更於驪頷探神珠。", "南山鼈鼻活拈得，乘興猶來捋虎鬚。"]'),
('f442b9bc-c9a7-45b6-8707-6cddc21e4930','偈頌一百六十首  其一二○','釋宗杲','宋','宋诗','song-poetry','','[]','休誇棒下無生忍，撥置當陽掣電機。',32,'全唐诗/poet.song.99000.json','["休誇棒下無生忍，撥置當陽掣電機。", "未屙已前驀提得，一擊自然亡所知。"]'),
('317741f1-3704-4b3a-8802-ae63e6d30c2d','偈頌一百六十首  其一二一','釋宗杲','宋','宋诗','song-poetry','','[]','多時不說禪，口邊生白醭。',103,'全唐诗/poet.song.99000.json','["多時不說禪，口邊生白醭。", "大衆苦相煎，便登曲隸彔木。", "匪論五家宗，不引傳燈錄。", "纔開兩片皮，業因招薄福。", "釋迦乾屎橛，達磨老臭禿。", "一人曲說直，一人直說曲。", "口裏水漉漉，似恁出家兒，定滅瞿曇族。", "臘月三十朝，大笑卻成哭。"]'),
('5c3cd1fe-42b5-471a-a82b-8846cf8302bd','偈頌一百六十首  其一二二','釋宗杲','宋','宋诗','song-poetry','','[]','香嚴透語滲漏，被語言縛殺。',41,'全唐诗/poet.song.99000.json','["香嚴透語滲漏，被語言縛殺。", "石霜透情滲漏，被情識使殺。", "曹山透見滲漏，被用聞覺知惑殺。"]'),
('c0352591-1ada-4997-85ff-416a6f3a1f14','偈頌一百六十首  其一二三','釋宗杲','宋','宋诗','song-poetry','','[]','這僧有頭無尾，明招有尾無頭。',32,'全唐诗/poet.song.99000.json','["這僧有頭無尾，明招有尾無頭。", "若人道得頭尾圓全句，雲門與爾拄杖子。"]'),
('0adf9224-3e38-4d14-a0d0-2d35f6876d3d','偈頌一百六十首  其一二四','釋宗杲','宋','宋诗','song-poetry','','[]','三十年來弄馬騎，今朝卻被驢兒攧。',54,'全唐诗/poet.song.99000.json','["三十年來弄馬騎，今朝卻被驢兒攧。", "就地拾得麗水金，拈起卻是新羅鐵。", "報諸人，別不別。", "夜來雪壓雲門，凍得烏龜成鼈。"]'),
('f2a2aa58-cc44-49ae-885c-d1f67fedb8cf','偈頌一百六十首  其一二五','釋宗杲','宋','宋诗','song-poetry','','[]','今夜喚明朝作來年，明朝喚今夜作去歲。',148,'全唐诗/poet.song.99000.json','["今夜喚明朝作來年，明朝喚今夜作去歲。", "即稱來年今夜合來，既號去歲明朝合去。", "來年今夜不見來，去歲明朝定不去。", "既不來，又不去，業識茫茫無本據。", "大圓鏡裏絕纖塵，箇中豈著閑家具。", "是則是，別又別，爍迦晃破秋天月。", "龐公不昧本來身，大似飛龍成跛鼈。", "爾諸人，瞥不瞥，靈利漢須看時節。", "五九盡處又逢春，衲僧腦後三斤鐵。"]'),
('4d2bbddd-7078-4669-82dc-8c41af3ba5d6','偈頌一百六十首  其一二六','釋宗杲','宋','宋诗','song-poetry','','[]','夜來兔子趕大蟲，天明走入無何有。',80,'全唐诗/poet.song.99000.json','["夜來兔子趕大蟲，天明走入無何有。", "月下珊瑚長數枝，萬象森羅齊稽首。", "拄杖子，不唧𠺕，渠儂卻善分妍醜。", "李公爛醉絕倒時，元是張公喫村酒。", "報諸人，急回首，切忌癡狂外邊走。"]'),
('3fcbb9e2-0a8b-4a43-a4e4-4fbddea97760','偈頌一百六十首  其一二七','釋宗杲','宋','宋诗','song-poetry','','[]','俊鷂不打籬邊兔，猛虎終不食伏肉。',32,'全唐诗/poet.song.99000.json','["俊鷂不打籬邊兔，猛虎終不食伏肉。", "毛頭星現北斗前，把斷天關幷地軸。"]'),
('259319c0-10bd-4812-be6c-165ee15f440e','偈頌一百六十首  其一二八','釋宗杲','宋','宋诗','song-poetry','','[]','福城東有大長者，居福城東海嶼上。',208,'全唐诗/poet.song.99000.json','["福城東有大長者，居福城東海嶼上。", "於不思議塵劫中，承事供養無數佛。", "善哉長者世希有，如優曇華時一現。", "發啟廣大真實心，創無佛處阿蘭若。", "若昔智人建梵剎，折草插地即成就。", "此心堅固等須彌，或讚或毀不搖動。", "魔王軍衆數甚多，睹茲殊勝自摧伏。", "長者視身如浮雲，變滅須臾不長久。", "當生佛國時節來，撒手便行不回顧。", "有子遵義起其家，志願身心俱及第。", "仁者則壽語不誣，當知今亦未嘗死。", "我來居是阿蘭若，不見長者生遺恨。", "故說此偈聊發揚，同住如來寂滅海。"]'),
('527789b1-c613-40d8-baff-16c98db7725d','偈頌一百六十首  其一二九','釋宗杲','宋','宋诗','song-poetry','','[]','以字不成八字非，爍迦羅眼不能窺。',32,'全唐诗/poet.song.99000.json','["以字不成八字非，爍迦羅眼不能窺。", "一毛頭上重拈出，忿怒那吒失卻威。"]'),
('93a0f1a7-5fdf-4d8f-8f73-509c6bcf4024','偈頌一百六十首  其一三○','釋宗杲','宋','宋诗','song-poetry','','[]','心空及第無階級，直下忘懷罪性空。',32,'全唐诗/poet.song.99000.json','["心空及第無階級，直下忘懷罪性空。", "一念廓然三際斷，千差萬別盡圓通。"]'),
('9c6c5372-8f0a-4cf6-aca8-1f4c7dcaad62','偈頌一百六十首  其一三一','釋宗杲','宋','宋诗','song-poetry','','[]','針鋒頭上透天關，著意忘懷兩不堪。',32,'全唐诗/poet.song.99000.json','["針鋒頭上透天關，著意忘懷兩不堪。", "直下早踰千萬劫，即今成佛未同參。"]'),
('adc8da0a-6ddf-4763-b4c1-3bcc319b36ff','偈頌一百六十首  其一三二','釋宗杲','宋','宋诗','song-poetry','','[]','普賢身相無有二，八萬四千毛孔剎。',129,'全唐诗/poet.song.99000.json','["普賢身相無有二，八萬四千毛孔剎。", "一一毛孔一如來，一一如來一塔廟。", "舍利堅固金剛身，虛空可壞此不朽。", "女子陳氏報劬勞，一一塔廟一瞻禮。", "滿足八萬四千拜，盡諸毛孔無有有遺。", "所獲功德不可量，正與普賢行願等。", "用嚴數父及慈母，遍及法界諸有情。", "永離苦海證菩提，悉得心空超彼岸。"]'),
('b7442fa2-5aec-4b3d-aedf-872179e37de7','偈頌一百六十首  其一三三','釋宗杲','宋','宋诗','song-poetry','','[]','插一枝草建梵剎，破妄想塵出經卷。',32,'全唐诗/poet.song.99000.json','["插一枝草建梵剎，破妄想塵出經卷。", "饒益廣大諸有情，成就無邊希有事。"]'),
('87a9fa46-56cd-4568-a390-759da2b9c6a9','偈頌一百六十首  其一三四','釋宗杲','宋','宋诗','song-poetry','','[]','昨日夢說禪，如今禪說夢。',184,'全唐诗/poet.song.99000.json','["昨日夢說禪，如今禪說夢。", "夢時夢如今說底，說時說昨日夢底。", "昨日合眼夢，如今開眼夢。", "諸人總在夢中聽，雲門復說夢中夢。", "驢唇先生開中笑，阿脩羅王打勃跳。", "海神失卻夜明珠，擘破彌盧穿七竅。", "三人上座請談禪，平地無風浪拍天。", "禪禪，不用思量卜度，非干文字語言。", "仰之彌高，鑽之彌堅。", "巖頭剗之則曰是句非句，臨濟用之則曰三要三玄。", "禪禪，吞卻栗棘蓬，透發金剛圓。", "夢裏明明有六趣，覺後空空無大千。"]'),
('45a9806d-1ba4-4b16-bf06-7cb9a049c3a2','偈頌一百六十首  其一三五','釋宗杲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衲僧相見莫疑猜，布袋結頭今日開。',64,'全唐诗/poet.song.99000.json','["衲僧相見莫疑猜，布袋結頭今日開。", "露柱著衫南嶽去，燈籠脫帽上天台。", "只有雲門木上座，終年無去亦無來。", "有時獨靠古屏畔，覷破門前下馬臺。"]'),
('4d64084d-d5dd-4251-8797-bb9eb749e991','偈頌一百六十首  其一三六','釋宗杲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','舉一不得舉二，放過一著落在第二。',76,'全唐诗/poet.song.99000.json','["舉一不得舉二，放過一著落在第二。", "遇貴則賤，遇賤則貴。", "築著磕著，沒處回避。", "南嶽天台去路通，君向西兮我向東，風從虎兮雲從龍。", "拈起簸箕別處舂，熨斗煎茶銚不同。"]'),
('14e5f705-2550-48ac-8516-f5a69a721daa','偈頌一百六十首  其一三七','釋宗杲','宋','宋诗','song-poetry','','[]','真生無可生，真滅無可滅。',24,'全唐诗/poet.song.99000.json','["真生無可生，真滅無可滅。", "寂滅忽現前，蝦蟆吞卻月。"]'),
('090a045f-8093-4aae-9dda-9e47e7f3ebd7','偈頌一百六十首  其一三八','釋宗杲','宋','宋诗','song-poetry','','[]','今早又風起，鬧處莫插觜。',24,'全唐诗/poet.song.99000.json','["今早又風起，鬧處莫插觜。", "觸著閻羅王，带累陰司鬼。"]'),
('b16f7799-834b-4b6f-8424-ac365a2b3376','偈頌一百六十首  其一三九','釋宗杲','宋','宋诗','song-poetry','','[]','俱劄普，日輪午。',30,'全唐诗/poet.song.99000.json','["俱劄普，日輪午。", "李將軍，射石虎。", "雖然透過那邊，枉發千鈞之弩。"]'),
('042b6eb0-23db-4441-a178-d886b183de0f','偈頌一百六十首  其一四○','釋宗杲','宋','宋诗','song-poetry','','[]','無路是趙州，老將足機籌。',24,'全唐诗/poet.song.99000.json','["無路是趙州，老將足機籌。", "關南幷塞北，當下一時收。"]'),
('e738f5d7-b508-4f7f-ab68-adda8afc217e','偈頌一百六十首  其一四一','釋宗杲','宋','宋诗','song-poetry','','[]','庭前柏樹子，今日重新舉。',24,'全唐诗/poet.song.99000.json','["庭前柏樹子，今日重新舉。", "打破趙州關，特地尋言語。"]'),
('644b8395-4430-4503-bc19-159df93ed578','偈頌一百六十首  其一四二','釋宗杲','宋','宋诗','song-poetry','','[]','聊聞舉著便承當，好肉無端已剜瘡。',32,'全唐诗/poet.song.99000.json','["聊聞舉著便承當，好肉無端已剜瘡。", "著眼機輪上頭看，方知兩兩不成雙。"]'),
('c4c0fc3b-3187-416b-9ac6-396142b5e5ec','偈頌一百六十首  其一四三','釋宗杲','宋','宋诗','song-poetry','','[]','徹骨徹髓道一句，三要三玄絕遮護。',64,'全唐诗/poet.song.99000.json','["徹骨徹髓道一句，三要三玄絕遮護。", "竺乾四七例皆迷，震旦二三渾未悟。", "我說是言非正邪，當機覿面休回互。", "殷勤爲報雲臺公，俊鷹不打籬邊兔。"]'),
('f891bd4b-364f-48ea-b4ef-ed7a3eb9e81e','偈頌一百六十首  其一四四','釋宗杲','宋','宋诗','song-poetry','','[]','即心即佛莫妄求，非心非佛休別討。',32,'全唐诗/poet.song.99000.json','["即心即佛莫妄求，非心非佛休別討。", "紅爐焰上雪華飛，一點清涼除熱惱。"]'),
('2e834101-721b-41d0-be6a-3e08b41abf15','偈頌一百六十首  其一四五','釋宗杲','宋','宋诗','song-poetry','','[]','行不到處說不難，說不到處行不難。',32,'全唐诗/poet.song.99000.json','["行不到處說不難，說不到處行不難。", "行說難到不難到，拈卻門前大案山。"]'),
('0b007865-b44a-4039-b858-b5b6d96accb9','偈頌一百六十首  其一四六','釋宗杲','宋','宋诗','song-poetry','','[]','這僧問趙州，趙州答趙州。',48,'全唐诗/poet.song.99000.json','["這僧問趙州，趙州答趙州。", "得人一馬，還人一牛。", "人平不語，水平不流。", "受恩深處宜先退，得意濃時便好休。"]'),
('02f33b3a-fc54-452a-87ec-639dfa9d9f20','偈頌一百六十首  其一四七','釋宗杲','宋','宋诗','song-poetry','','[]','冤有頭，債有主。',22,'全唐诗/poet.song.99000.json','["冤有頭，債有主。", "偶因失腳倒地，至今怨入骨髓。"]'),
('c28542db-0296-4e94-a9e1-5fe7b881d9d3','偈頌一百六十首  其一四八','釋宗杲','宋','宋诗','song-poetry','','[]','妄心顛倒造諸業，回趣真乘即懺摩。',32,'全唐诗/poet.song.99000.json','["妄心顛倒造諸業，回趣真乘即懺摩。", "真妄兩頭俱透脫，海南東畔是新羅。"]'),
('b61da6e3-b3d4-41b6-804e-c9cf3b4f7010','偈頌一百六十首  其一四九','釋宗杲','宋','宋诗','song-poetry','','[]','不落與不昧，半明兼半晦。',56,'全唐诗/poet.song.99000.json','["不落與不昧，半明兼半晦。", "不昧與不落，兩頭空索索。", "五百生前箇野狐，而今冷地謾追呼。", "座中既有江南客，休向罇前唱鷓鴣。"]'),
('c01a8de4-51aa-47c4-b5ac-8d11f46b1807','偈頌一百六十首  其一五○','釋宗杲','宋','宋诗','song-poetry','','[]','生也不道，死也不道。',51,'全唐诗/poet.song.99000.json','["生也不道，死也不道。", "公案兩重，一狀領到。", "露刃吹毛，截斷綱要。", "脫卻鶻臭衫，拈了炙臘脂帽，大坐當軒氣浩浩。"]'),
('e897f621-8c65-4b1f-a771-3ccb8a922379','偈頌一百六十首  其一五一','釋宗杲','宋','宋诗','song-poetry','','[]','丹霞燒卻木佛，翠微供養羅漢。',74,'全唐诗/poet.song.99000.json','["丹霞燒卻木佛，翠微供養羅漢。", "一人左手擡，一人右手按。", "賓主既歷然，吾道一以貫。", "師子獨游行，豈復求侶伴。", "團圞擘不開，打鼓普請看。", "雖不直分文，傾國不肯換。"]'),
('95cb501b-3657-409a-8429-b5aae4f0c96c','偈頌一百六十首  其一五二','釋宗杲','宋','宋诗','song-poetry','','[]','一二三四五，虛空闕處補。',52,'全唐诗/poet.song.99000.json','["一二三四五，虛空闕處補。", "五四三二一，當門書大吉。", "好手揮斤去鼻泥，衲僧機妙安能識。", "驀然識，百草頭邊露消息。"]'),
('b3ef14a4-8b68-45c6-b593-89014acea09a','偈頌一百六十首  其一五三','釋宗杲','宋','宋诗','song-poetry','','[]','念七念七，全無消息。',20,'全唐诗/poet.song.99000.json','["念七念七，全無消息。", "背看分明，正觀難識。"]'),
('f7e6951e-4d1d-44f5-9441-f37fab7b0118','偈頌一百六十首  其一五四','釋宗杲','宋','宋诗','song-poetry','','[]','白的的，清寥寥。',18,'全唐诗/poet.song.99000.json','["白的的，清寥寥。", "水不能濡，火不能燒。"]'),
('f824782f-c8f5-4215-9a61-794230892c00','偈頌一百六十首  其一五五','釋宗杲','宋','宋诗','song-poetry','','[]','千靈萬聖，萬聖千靈。',20,'全唐诗/poet.song.99000.json','["千靈萬聖，萬聖千靈。", "莫順人情，吉凶上卦。"]'),
('99f11c3a-2b0b-4581-8a62-92f16727aab4','偈頌一百六十首  其一五六','釋宗杲','宋','宋诗','song-poetry','','[]','大根大器大丈夫，不越一念了大事。',32,'全唐诗/poet.song.99000.json','["大根大器大丈夫，不越一念了大事。", "三世諸佛立下風，此人堪作如來使。"]'),
('ff7bc416-d013-4363-be9a-21d469d280d3','偈頌一百六十首  其一五七','釋宗杲','宋','宋诗','song-poetry','','[]','清凈慈門剎塵數，共生如來一妙相。',32,'全唐诗/poet.song.99000.json','["清凈慈門剎塵數，共生如來一妙相。", "一一諸相莫不然，是故見者無厭足。"]'),
('d8006569-dd70-42d2-a4cc-48fc5b4a198c','偈頌一百六十首  其一五八','釋宗杲','宋','宋诗','song-poetry','','[]','舉頭忽睹明星現，因茲眼病見空華。',32,'全唐诗/poet.song.99000.json','["舉頭忽睹明星現，因茲眼病見空華。", "今日還渠舊光彩，碧眸炯炯照塵沙。"]'),
('17d18c18-a581-43c3-ac30-4f16a418c3e7','偈頌一百六十首  其一五九','釋宗杲','宋','宋诗','song-poetry','','[]','夷門昔日呈家醜，拈出無邊栗棘蓬。',32,'全唐诗/poet.song.99000.json','["夷門昔日呈家醜，拈出無邊栗棘蓬。", "今日甌峰孤頂上，幸然無事又相逢。"]'),
('9fb68495-52a8-4548-ae3e-b36ed2915c9c','偈頌一百六十首  其一六○','釋宗杲','宋','宋诗','song-poetry','','[]','差之毫釐，失之千里。',58,'全唐诗/poet.song.99000.json','["差之毫釐，失之千里。", "孟春猶寒，終而復始。", "釋迦老子是繫驢橛，一大藏教是破故紙。", "如我按指，海印發光。", "汝暫舉心，塵勞先起。"]'),
('51a0a89c-3966-4ec3-b779-67031c6d403b','偈頌一百六十首  其一六一','釋宗杲','宋','宋诗','song-poetry','','[]','百雜碎，沒縫罅。',32,'全唐诗/poet.song.99000.json','["百雜碎，沒縫罅。", "明眼衲僧，盲聾瘖啞。", "金剛水際藏身，非非想天走馬。"]'),
('9b5b77eb-dbd6-4aee-b7a0-bc7324ed7c28','頌古一百二十一首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','利刃有蜜不須舐，蠱毒之家水莫嘗。',32,'全唐诗/poet.song.99000.json','["利刃有蜜不須舐，蠱毒之家水莫嘗。", "不舐不嘗俱不犯，端然衣錦自還鄉。"]'),
