('e83a1459-d215-4e80-9ffe-9de876d64aeb','頌古一百二十一首  其九六','釋宗杲','宋','宋诗','song-poetry','','[]','口是禍門，電激雷奔。',20,'全唐诗/poet.song.99000.json','["口是禍門，電激雷奔。", "娑竭出海，震動乾坤。"]'),
('ad1dbcbb-776c-47ca-a4cf-1c4d98de012a','頌古一百二十一首  其九七','釋宗杲','宋','宋诗','song-poetry','','[]','日日日日，時時時時。',20,'全唐诗/poet.song.99000.json','["日日日日，時時時時。", "違時失候，箇老古錐。"]'),
('18b59e77-bb82-4c9c-9068-19e44f9edd83','頌古一百二十一首  其九八','釋宗杲','宋','宋诗','song-poetry','','[]','直出直入，當面不識。',20,'全唐诗/poet.song.99000.json','["直出直入，當面不識。", "更擬如何，著甚死急。"]'),
('51df75e7-13e2-4990-af59-c5eaff125e7c','頌古一百二十一首  其九九','釋宗杲','宋','宋诗','song-poetry','','[]','殺人須是殺人漢，當下一刀成兩段。',32,'全唐诗/poet.song.99000.json','["殺人須是殺人漢，當下一刀成兩段。", "頭臂雖虧劍刃鋒，何似秦時𨍏轢鑽。"]'),
('d62aaddb-44bc-422b-961c-4e4675db23fa','頌古一百二十一首  其一○○','釋宗杲','宋','宋诗','song-poetry','','[]','十字街頭，現成行貨。',20,'全唐诗/poet.song.99000.json','["十字街頭，現成行貨。", "擬欲商量，漆桶蹉過。"]'),
('8f8147ed-d327-4f1d-a270-3b37bc8714fd','頌古一百二十一首  其一○一','釋宗杲','宋','宋诗','song-poetry','','[]','兔角龜毛眼裏栽，鐵山當面勢崔嵬。',32,'全唐诗/poet.song.99000.json','["兔角龜毛眼裏栽，鐵山當面勢崔嵬。", "東西南北無門入，曠劫無明當下灰。"]'),
('729fe48b-b658-47de-8e31-0c8d018f2a26','頌古一百二十一首  其一○二','釋宗杲','宋','宋诗','song-poetry','','[]','雲門鑒咦，少有人知。',17,'全唐诗/poet.song.99000.json','["雲門鑒咦，少有人知。", "咄，無孔鐵鎚。"]'),
('81c48dd1-162e-42a7-a207-833616954b12','頌古一百二十一首  其一○三','釋宗杲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，甲乙丙丁庚戊己。',24,'全唐诗/poet.song.99000.json','["一口吸盡西江水，甲乙丙丁庚戊己。", "咄咄咄，囉囉哩。"]'),
('5d0e46ba-b561-47a7-8bfa-eb2c718d9fea','頌古一百二十一首  其一○四','釋宗杲','宋','宋诗','song-poetry','','[]','燕坐道場經十劫，一一從頭俱漏泄。',32,'全唐诗/poet.song.99000.json','["燕坐道場經十劫，一一從頭俱漏泄。", "世間多少守株人，掉棒擬打天邊月。"]'),
('32d6ce8f-edc8-4103-9fc0-3f8e15a2c388','頌古一百二十一首  其一○五','釋宗杲','宋','宋诗','song-poetry','','[]','獨坐許誰知，青山對落暉。',24,'全唐诗/poet.song.99000.json','["獨坐許誰知，青山對落暉。", "華須連夜發，莫待曉風吹。"]'),
('2f1c6094-6d5c-4388-926d-7b9899ddc49e','頌古一百二十一首  其一○六','釋宗杲','宋','宋诗','song-poetry','','[]','荷葉團團團似鏡，菱角尖尖尖似錐。',32,'全唐诗/poet.song.99000.json','["荷葉團團團似鏡，菱角尖尖尖似錐。", "風吹柳絮毛毬走，雨打梨花蛺蝶飛。"]'),
('ed6d1456-7d0b-4aee-8feb-39bccdcf66c5','頌古一百二十一首  其一○七','釋宗杲','宋','宋诗','song-poetry','','[]','春至自開華，秋來還落葉。',24,'全唐诗/poet.song.99000.json','["春至自開華，秋來還落葉。", "黄面老瞿曇，休搖三寸舌。"]'),
('f5f682fb-aae0-4ec2-aa94-538aa7e90f96','頌古一百二十一首  其一○八','釋宗杲','宋','宋诗','song-poetry','','[]','壁上安燈盞，堂前置酒臺。',24,'全唐诗/poet.song.99000.json','["壁上安燈盞，堂前置酒臺。", "悶來打三盞，何處得愁來。"]'),
('54b842e0-7965-4365-aa6a-d46ad1fddd1d','頌古一百二十一首  其一○九','釋宗杲','宋','宋诗','song-poetry','','[]','陝府鐵牛白癩，嘉州大像耳聵。',28,'全唐诗/poet.song.99000.json','["陝府鐵牛白癩，嘉州大像耳聵。", "兩箇病痛一般，咄哉漆桶不快。"]'),
('c957f221-7146-4772-9dc9-deb8c8d18e0f','頌古一百二十一首  其一一○','釋宗杲','宋','宋诗','song-poetry','','[]','華陰山前百尺井，中有寒泉徹骨冷。',32,'全唐诗/poet.song.99000.json','["華陰山前百尺井，中有寒泉徹骨冷。", "誰家女子來照影，不照其餘照斜領。"]'),
('ae3468ae-e7c4-4e54-9a43-aec08f11a5da','頌古一百二十一首  其一一一','釋宗杲','宋','宋诗','song-poetry','','[]','掌內摩尼曾不顧，誰能護惜孃生袴。',32,'全唐诗/poet.song.99000.json','["掌內摩尼曾不顧，誰能護惜孃生袴。", "浮盃不會老婆禪，直至如今遭點污。"]'),
('0224b0a6-0b40-4c1b-a1fd-2d567ef30222','頌古一百二十一首  其一一二','釋宗杲','宋','宋诗','song-poetry','','[]','電光石火尚猶遲，猗死禪和那得知。',32,'全唐诗/poet.song.99000.json','["電光石火尚猶遲，猗死禪和那得知。", "轉面回頭擬尋討，夕陽已過綠梢西。"]'),
('e06888d8-9c4c-4808-a2f1-e665a3b915c7','頌古一百二十一首  其一一三','釋宗杲','宋','宋诗','song-poetry','','[]','眼光爍破四天下，婆子拳頭沒縫罅。',32,'全唐诗/poet.song.99000.json','["眼光爍破四天下，婆子拳頭沒縫罅。", "當機覿面事如何，猛虎脊梁誰解跨。"]'),
('1453b7ff-2f04-4b00-9828-5595b100ab57','頌古一百二十一首  其一一四','釋宗杲','宋','宋诗','song-poetry','','[]','三世諸佛不知有，老老大在外邊走。',64,'全唐诗/poet.song.99000.json','["三世諸佛不知有，老老大在外邊走。", "眼皮蓋盡五須彌，大洋海裏翻筋斗。", "狸奴白牯卻知有，瀑布不溜青山走。", "堪笑無端王老師，錯認簸箕作熨斗。"]'),
('1a3f50dc-044d-4674-b4d3-f9b0d6c1ca1d','頌古一百二十一首  其一一五','釋宗杲','宋','宋诗','song-poetry','','[]','一堆紅焰亘晴空，不問金鍮鐵錫銅。',32,'全唐诗/poet.song.99000.json','["一堆紅焰亘晴空，不問金鍮鐵錫銅。", "入裏盡教成水去，那容蚊蚋泊其中。"]'),
('51378cb1-cd6d-43dd-9892-58e60f4fc701','頌古一百二十一首  其一一六','釋宗杲','宋','宋诗','song-poetry','','[]','崎崎嶇嶇平坦坦，平坦坦處甚崎嶇。',32,'全唐诗/poet.song.99000.json','["崎崎嶇嶇平坦坦，平坦坦處甚崎嶇。", "驀地跛驢能蹴蹋，抹過追風天馬駒。"]'),
('e0de0d8b-4849-450b-825b-d2301742ca5e','頌古一百二十一首  其一一七','釋宗杲','宋','宋诗','song-poetry','','[]','雲門舉起竹篦，開口知君話墮。',28,'全唐诗/poet.song.99000.json','["雲門舉起竹篦，開口知君話墮。", "上方香積不餐，甘伏食人涕唾。"]'),
('83a0dceb-09ff-4513-bef5-11a9e52247a1','頌古一百二十一首  其一一八','釋宗杲','宋','宋诗','song-poetry','','[]','雲門舉起竹篦，禪和切忌針錐。',28,'全唐诗/poet.song.99000.json','["雲門舉起竹篦，禪和切忌針錐。", "鸞鳳不棲荆棘，𮭗𮭗偏守空池。"]'),
('ed33236b-5764-400b-8895-76db249efa2f','頌古一百二十一首  其一一九','釋宗杲','宋','宋诗','song-poetry','','[]','雲門舉起竹篦，通身带水拕泥。',28,'全唐诗/poet.song.99000.json','["雲門舉起竹篦，通身带水拕泥。", "奉報參玄上士，撒手懸崖勿遲。"]'),
('73f86c5b-ae6e-44c2-8063-04264bb29fe2','頌古一百二十一首  其一二○','釋宗杲','宋','宋诗','song-poetry','','[]','雲門舉起竹篦，擬議知君亂統。',28,'全唐诗/poet.song.99000.json','["雲門舉起竹篦，擬議知君亂統。", "直饒救得眼睛，當下失卻鼻孔。"]'),
('05251d80-9799-4e14-bf98-a3fdfdf15983','頌古一百二十一首  其一二一','釋宗杲','宋','宋诗','song-poetry','','[]','雲門舉起竹篦，露出心肝五臓。',28,'全唐诗/poet.song.99000.json','["雲門舉起竹篦，露出心肝五臓。", "可憐猗死禪和，猶自魂飛膽喪。"]'),
('29f0b8a6-04f4-4303-bae3-6ce7f8a45c69','皇帝在建邸請陞堂偈','釋宗杲','宋','宋诗','song-poetry','','[]','豁開頂門眼，照徹大千界。',24,'全唐诗/poet.song.99000.json','["豁開頂門眼，照徹大千界。", "既作法中王，於法得自在。"]'),
('8908405b-b083-48fe-9f55-bc639377d1a6','又作偈','釋宗杲','宋','宋诗','song-poetry','','[]','大根大器大力量，荷擔大事不尋常。',32,'全唐诗/poet.song.99000.json','["大根大器大力量，荷擔大事不尋常。", "一毛頭上通消息，遍界明明不覆藏。"]'),
('eda854fa-db48-4f8e-9448-24f575a7edd7','御賜真贊師演成四偈  其一','釋宗杲','宋','宋诗','song-poetry','','[]','生滅不滅，如水中月。',20,'全唐诗/poet.song.99000.json','["生滅不滅，如水中月。", "不可攬觸，妙在甄別。"]'),
('e633fe3c-d450-4fcc-a7aa-6ad18a0a30a2','御賜真贊師演成四偈  其二','釋宗杲','宋','宋诗','song-poetry','','[]','常住不住，是真實義。',20,'全唐诗/poet.song.99000.json','["常住不住，是真實義。", "一幅丹青，輝天鑑地。"]'),
('0da9ef80-d269-467e-b880-7ac9b13a154b','御賜真贊師演成四偈  其三','釋宗杲','宋','宋诗','song-poetry','','[]','圓覺空明，胡來漢現。',20,'全唐诗/poet.song.99000.json','["圓覺空明，胡來漢現。", "一點靈光，萬化千變。"]'),
('04938e09-1310-484c-a153-bdbcdba9ef8a','御賜真贊師演成四偈  其四','釋宗杲','宋','宋诗','song-poetry','','[]','隨物現處，廓清寰宇。',20,'全唐诗/poet.song.99000.json','["隨物現處，廓清寰宇。", "不動神情，氣吞項羽。"]'),
('5a789b54-3297-40d9-ba69-10578477aa96','泉州惠安縣迎藏經請小參偈','釋宗杲','宋','宋诗','song-poetry','','[]','稽首十力大導師，三界獨尊無比況。',304,'全唐诗/poet.song.99000.json','["稽首十力大導師，三界獨尊無比況。", "示現成佛轉法輪，廣演無邊契經海。", "衆生心想念念殊，所轉法輪亦差別。", "法輪功德不可量，盡思竭力無能測。", "有大經卷在一塵，量等三千大千界。", "世有聰慧明達人，具足天眼悉知見。", "破塵出經作佛事，不作實與非實想。", "又以無邊法界空，納在佛身一毛孔。", "須彌鐵圍及大海，一一包容無迫隘。", "一毛既爾餘悉然，導師方便亦如是。", "念念普遍諸毛孔，念念克證金剛慧。", "念念成就佛菩提，念念滿足普賢願。", "而不生於戲論心，亦不住於深境界。", "如夢如幻如水月，如優曇華出世間。", "如是常轉大經卷，了無能轉所轉者。", "三世諸佛諸菩薩，聲聞獨覺及天人。", "地獄修羅鬼畜等，一一皆承此經力。", "我今復與諸佛子，各生殊勝難遇心。", "還攝此經一歸塵，安住毘盧法寶藏。"]'),
('9f56ac10-36d9-43fc-89a1-d6cc9a579cfb','莊泉伯檢察爲先安撫請陞堂偈','釋宗杲','宋','宋诗','song-poetry','','[]','近來學佛人，少見不顛倒。',144,'全唐诗/poet.song.99000.json','["近來學佛人，少見不顛倒。", "唯務資談柄，棄大而就小。", "昧卻直截事，外邊打之遶。", "畢竟那一著，何曾得分曉。", "獨有莊居士，真實沒虛矯。", "斷除煩惱根，烈火燒乾草。", "心地既安然，魔境豈能擾。", "任爾鬧浩浩，我常靜悄悄。", "末後示真歸，如脫破布襖。", "加趺入禪定，皓月臨清沼。", "透過生死關，擊碎無價寶。", "剛正大丈夫，一了一切了。"]'),
('6bffecbf-f8a1-4984-a917-b49899f14b5d','方敷文請陞堂舉那吒太子因緣','釋宗杲','宋','宋诗','song-poetry','','[]','骨肉都還父母了，不知那箇是那吒。',32,'全唐诗/poet.song.99000.json','["骨肉都還父母了，不知那箇是那吒。", "一毛頭上翻身轉，一一毛頭渾不差。"]'),
('79cad665-fdf7-4a41-80cc-707911a3f375','趙提宮請陞堂偈','釋宗杲','宋','宋诗','song-poetry','','[]','言前薦得已天涯，句後承當路轉賒。',32,'全唐诗/poet.song.99000.json','["言前薦得已天涯，句後承當路轉賒。", "一擊鐵關如粉碎，水天空闊雁行斜。"]'),
('cd80c8e6-3842-4753-a32d-3827bfe8061d','李參政轉物庵','釋宗杲','宋','宋诗','song-poetry','','[]','若能轉物，即同如來。',80,'全唐诗/poet.song.99000.json','["若能轉物，即同如來。", "咄哉瞿曇，誑諕癡獃。", "物無自性，我亦非有。", "轉者爲誰，徒勞心手。", "知無自性，復是何物。", "瞥起情塵，捫空揣骨。", "此菴無作，住者何人。", "具頂門眼，試辨疏親。"]'),
('272f6fd8-1477-4405-9f59-8b629c259ea8','富樞密妙高堂','釋宗杲','宋','宋诗','song-poetry','','[]','妙高堂，隨所至。',65,'全唐诗/poet.song.99000.json','["妙高堂，隨所至。", "牓未懸，落第二。", "似猛焰，藏蚊蚋。", "擬承當，生妄計。", "德雲師，安有作。", "在別峰，亦寬廓。", "住佛地，何所旋轉。", "我作銘，任圖度。"]'),
('9c4d51b1-7b89-4991-b655-1c7c1d4d831f','魏侍郎凈心閣','釋宗杲','宋','宋诗','song-poetry','','[]','偉哉廣大寂滅心，譬如虛空不分別。',176,'全唐诗/poet.song.99000.json','["偉哉廣大寂滅心，譬如虛空不分別。", "擬心求凈即染污，況復比倫諸佛土。", "又如夢中所見物，所見雖有不可取。", "如是通達無有疑，凈心心義炳然現。", "是義現矣難測量，超諸色相離言說。", "過去未來現在世，佛及菩薩與聲聞。", "一切含識有情類，平等於義如實了。", "善哉奇特過量人，只以此閣演是義。", "演已便息隨所緣，亦與夢中無差別。", "我以父母所生口，說此無上妙伽陀。", "莊嚴廣大寂滅心，爲諸來者作饒益。"]'),
('19cd5258-14df-4c6e-a460-a882fdfe3b99','向侍郎無熱軒','釋宗杲','宋','宋诗','song-poetry','','[]','勇猛精進過量人，號曰薌林大居士。',255,'全唐诗/poet.song.99000.json','["勇猛精進過量人，號曰薌林大居士。", "住無變易真實處，而常順行諸佛法。", "不作世間顛倒業，成辦出世勝方便。", "而能於此方便中，幻出難思諸境界。", "復於難思境界中，而現種種殊勝事。", "華林寶樹咸放光，接影連輝相鑒徹。", "光色清凈如金剛，世間無有能壞者。", "又如無熱寶池，四面分流入於海。", "是海廣大無邊際，不出居士一毛孔。", "於一毛孔放光明，八萬四千同時發。", "不勞居士轉舌相，只以此光宣妙法。", "是法即是此光明，不離是光說此法。", "大海毛孔亦復爾，此是薌林無熱義。", "是義如空不可量，一一包羅世間相。", "我今以此無義語，略爲居士出隻手。", "佛子來登無熱軒，衆寶妙沙開戶牖。"]'),
('06da0e10-624d-49fb-9107-a4ab1cc74d3b','蔡知縣小庵','釋宗杲','宋','宋诗','song-poetry','','[]','此庵非小亦非大，堪笑石頭空捏怪。',64,'全唐诗/poet.song.99000.json','["此庵非小亦非大，堪笑石頭空捏怪。", "不知法界即此庵，彊謂此庵含法界。", "而今欲識住庵人，萬象之中獨露身。", "妙喜爲寫此庵牓，要與太虛爲近鄰。"]'),
('2fc1804a-142a-41eb-95c0-3e1e2271d3fc','汪狀元燕坐軒','釋宗杲','宋','宋诗','song-poetry','','[]','不於三界現身意，棹舉何如憒憒時。',32,'全唐诗/poet.song.99000.json','["不於三界現身意，棹舉何如憒憒時。", "寄語軒中燕坐者，好看新月下前谿。"]'),
('393d2bca-91ed-4bef-bd98-8c79d52b9b57','韓司諫樂谷','釋宗杲','宋','宋诗','song-poetry','','[]','人言至樂在此谷，孰信樂爲谷所移。',32,'全唐诗/poet.song.99000.json','["人言至樂在此谷，孰信樂爲谷所移。", "以樂均施不樂者，方名真樂丈夫兒。"]'),
('92f77688-a867-452a-9227-697531e4112a','又六湛堂','釋宗杲','宋','宋诗','song-poetry','','[]','非湛非搖此法源，當機莫厭假名存。',64,'全唐诗/poet.song.99000.json','["非湛非搖此法源，當機莫厭假名存。", "直須過量英靈漢，方入無邊廣大門。", "萬境交羅元不二，六窗晝夜未嘗昏。", "翻思龐老事無別，擲劍揮空豈有痕。"]'),
('d065b0d7-3188-452d-bc01-55008bf1e14c','又同塵庵','釋宗杲','宋','宋诗','song-poetry','','[]','塵無自性，攬真成立。',60,'全唐诗/poet.song.99000.json','["塵無自性，攬真成立。", "擬和其光，同亦俱失。", "外既匪寬，內亦不窒。", "是義非虛，亦復非實。", "庵中主人，如玉處石。", "作如是觀，千載一息。"]'),
('d8d5eb92-6658-493c-97b7-56f7742787f6','喻郎中觀我庵','釋宗杲','宋','宋诗','song-poetry','','[]','萬物備於我，我觀卒未休。',24,'全唐诗/poet.song.99000.json','["萬物備於我，我觀卒未休。", "智者返觀我，縱橫得自由。"]'),
('3a38f73c-a8dd-4dc9-9e97-d1e52a22726c','黄智通居士善住庵','釋宗杲','宋','宋诗','song-poetry','','[]','善住庵中人，從來無所住。',24,'全唐诗/poet.song.99000.json','["善住庵中人，從來無所住。", "只這無住心，便是安身處。"]'),
('8b69e00f-632a-4e60-add4-1ef1556d7601','謝紫巖居士','釋宗杲','宋','宋诗','song-poetry','','[]','紫巖分惠建谿茗，妙喜答以青州衫。',32,'全唐诗/poet.song.99000.json','["紫巖分惠建谿茗，妙喜答以青州衫。", "得人一牛還一馬，前三三與後三三。"]'),
('f5bda960-bceb-4492-aa5f-67f028e681db','答劉安撫','釋宗杲','宋','宋诗','song-poetry','','[]','毛錐子上通消息，爭似亡言絕見知。',32,'全唐诗/poet.song.99000.json','["毛錐子上通消息，爭似亡言絕見知。", "後夜一輪空界月，清光千里共依依。"]'),
('66711d98-3f04-45ff-b6e8-c9c272786c1c','寄無垢居士','釋宗杲','宋','宋诗','song-poetry','','[]','上苑玉池方解凍，人間楊柳又垂春。',32,'全唐诗/poet.song.99000.json','["上苑玉池方解凍，人間楊柳又垂春。", "山堂盡日焚香坐，長憶毘耶多口人。"]'),
('c19cf38e-ef9c-4a93-852f-5381b9df4c47','示汪居士','釋宗杲','宋','宋诗','song-poetry','','[]','一毛頭上無邊剎，決定識情難測量。',32,'全唐诗/poet.song.99000.json','["一毛頭上無邊剎，決定識情難測量。", "直下不生邪險見，壺中日月自然長。"]'),
('91327343-8cb9-48f8-a638-2d0be9bcafea','示周子充寫華嚴經','釋宗杲','宋','宋诗','song-poetry','','[]','總別同異，成壞行布。',60,'全唐诗/poet.song.99000.json','["總別同異，成壞行布。", "圓融無礙，塵人衆剎。", "非寬剎入，衆塵非隘。", "居士筆端，宣暢果海。", "因源自在，我今說偈。", "贊揚同證，一真法界。"]'),
('8b9d497d-a5d3-4542-8ab9-04759b82faf4','示了然居士','釋宗杲','宋','宋诗','song-poetry','','[]','長樂沙坑鄭了然，不依本分要參禪。',32,'全唐诗/poet.song.99000.json','["長樂沙坑鄭了然，不依本分要參禪。", "自言已到無參處，哥羅管爾米疆年。"]'),
('79002b5e-068d-415e-817b-0790e5541802','示韓令人','釋宗杲','宋','宋诗','song-poetry','','[]','說不到處著一句，風前截斷千差路。',32,'全唐诗/poet.song.99000.json','["說不到處著一句，風前截斷千差路。", "超佛越祖只如今，壁立萬仞無回互。"]'),
('fdec226e-7ef7-46bc-b422-36903d1d5868','示大悲長老','釋宗杲','宋','宋诗','song-poetry','','[]','一棒打破生死窟，當時凡聖絕行蹤。',32,'全唐诗/poet.song.99000.json','["一棒打破生死窟，當時凡聖絕行蹤。", "返笑趙州心不歇，老來猶自走西東。"]'),
('366608a9-265b-405a-a8b1-79a96eaa2cfa','示祥雲懿長老','釋宗杲','宋','宋诗','song-poetry','','[]','奪卻衲僧拄杖，當下便無伎倆。',28,'全唐诗/poet.song.99000.json','["奪卻衲僧拄杖，當下便無伎倆。", "喝下鐵眼忽開，直據千峰頂上。"]'),
('b5c3d3cc-9b36-4df9-94c0-76ff1184e18d','示鼎需禪人','釋宗杲','宋','宋诗','song-poetry','','[]','面門竪亞摩醯眼，肘後斜懸奪命符。',32,'全唐诗/poet.song.99000.json','["面門竪亞摩醯眼，肘後斜懸奪命符。", "瞎卻眼，解卻符，趙州東壁掛葫蘆。"]'),
('1e174b28-722d-4f24-8469-c736b1d7bb24','示彌光禪人','釋宗杲','宋','宋诗','song-poetry','','[]','龜毛拈得笑咍咍，一擊萬重關鎖開。',32,'全唐诗/poet.song.99000.json','["龜毛拈得笑咍咍，一擊萬重關鎖開。", "慶快平生在今日，孰云千里賺吾來。"]'),
('d23f8507-5e23-4a7e-9e51-43859837a2b5','示祖元禪人','釋宗杲','宋','宋诗','song-poetry','','[]','萬仞崖頭解放身，起來依舊卻惺惺。',32,'全唐诗/poet.song.99000.json','["萬仞崖頭解放身，起來依舊卻惺惺。", "饑餐渴飲渾無事，那論昔人非昔人。"]'),
('1c4a1a8e-a3ca-4b4c-b0a2-aa4062a9d22f','示遵璞禪人','釋宗杲','宋','宋诗','song-poetry','','[]','一口吞盡三世佛，正是吾家客作兒。',32,'全唐诗/poet.song.99000.json','["一口吞盡三世佛，正是吾家客作兒。", "爭似璞禪無用處，一毛頭上便忘機。"]'),
('35f538c4-01e9-4890-8585-e28c67dab77f','示法泉侍者','釋宗杲','宋','宋诗','song-poetry','','[]','言前超佛祖，日輪正當午。',60,'全唐诗/poet.song.99000.json','["言前超佛祖，日輪正當午。", "豁開三要關，一擊塗毒鼓。", "既發上頭機，莫問千鈞弩。", "放去絕遮攔，捏聚非回互。", "咄哉老瞿曇，住住住住住。"]'),
('e4d58fa0-34b6-459d-bbb4-973fc9cc1a18','示用禪人','釋宗杲','宋','宋诗','song-poetry','','[]','未點先行不唧溜，不撥自轉已出醜。',64,'全唐诗/poet.song.99000.json','["未點先行不唧溜，不撥自轉已出醜。", "那堪更鼓兩片皮，豈止鑿空開戶牖。", "火中木馬空嘶鳴，水底泥牛謾哮吼。", "用禪用禪聽我言，拶到懸崖須放手。"]'),
('2938a06d-3e8d-4ed0-89e6-2736946ff078','送直禪人','釋宗杲','宋','宋诗','song-poetry','','[]','直出直入，直行直坐。',90,'全唐诗/poet.song.99000.json','["直出直入，直行直坐。", "直禪上人，直須恁麽。", "本自圓成，不立功課。", "饑來喫飯，寒來向火。", "不在瞿曇，非干達磨。", "擬心思量，返遭殃禍。", "我說是言，已招口過。", "明眼人前，一場話墮。", "請事斯語，無忘骨剉。"]'),
('0cede2d1-eeb9-4b7e-ba15-26eab26e6ba4','送法輪思藏主化鍾','釋宗杲','宋','宋诗','song-poetry','','[]','覆爲鍾，仰爲鼎。',46,'全唐诗/poet.song.99000.json','["覆爲鍾，仰爲鼎。", "自是法輪家風，妙喜爭取馳騁。", "思禪人，固相請。", "援毫臨紙忽猛省，一聲直透須彌頂。"]'),
('3737a7f9-4b16-46de-a4cb-fb2f8638c685','送超僧鑑','釋宗杲','宋','宋诗','song-poetry','','[]','桶底脫時大地闊，命根斷處碧潭清。',32,'全唐诗/poet.song.99000.json','["桶底脫時大地闊，命根斷處碧潭清。", "好將一點紅爐雪，散作人間照夜燈。"]'),
('3962b6a9-d1ae-433a-a2ca-8a675d46d151','寄福勝長老','釋宗杲','宋','宋诗','song-poetry','','[]','真人十八界元空，三十一人同姓呂。',31,'全唐诗/poet.song.99000.json','["真人十八界元空，三十一人同姓呂。", "分散游山各占山，三十一又同處。"]'),
('782611d0-dd72-4525-b277-daee612d48c6','寄歸宗華侄禪師','釋宗杲','宋','宋诗','song-poetry','','[]','坐斷金輪第一峰，千妖百怪自潛蹤。',32,'全唐诗/poet.song.99000.json','["坐斷金輪第一峰，千妖百怪自潛蹤。", "年來又得真消息，說道楊岐正脈通。"]'),
('b972f41a-0484-49bc-8b64-140fbb34cf45','送了明長老歸長蘆','釋宗杲','宋','宋诗','song-poetry','','[]','人言棒頭出孝子，我道憐兒不覺醜。',64,'全唐诗/poet.song.99000.json','["人言棒頭出孝子，我道憐兒不覺醜。", "長蘆長老恁麽來，妙喜空費一張口。", "從教四海妄流傳，野干能作師子吼。", "孰云無物贈伊行，喝下鐵圍山倒走。"]'),
('90f9d6c4-e9b5-4c5b-af55-33a349de41d5','釋迦出山相讚','釋宗杲','宋','宋诗','song-poetry','','[]','正覺山前折卻本，三七日內心頭悶。',32,'全唐诗/poet.song.99000.json','["正覺山前折卻本，三七日內心頭悶。", "卻來鹿苑討便宜，好與拽翻椎一頓。"]'),
('ce6e339a-81fc-4cf5-afef-a76f8c5f6480','文殊問疾讚','釋宗杲','宋','宋诗','song-poetry','','[]','居士何曾病，是病因問有。',24,'全唐诗/poet.song.99000.json','["居士何曾病，是病因問有。", "兩眼對兩眼，世醫咸拱手。"]'),
('508065b4-3ccd-4896-bec0-82b813d9b758','觀音大士讚','釋宗杲','宋','宋诗','song-poetry','','[]','過去正法明，現前觀自在。',120,'全唐诗/poet.song.99000.json','["過去正法明，現前觀自在。", "眼觀諸音聲，耳聽衆妙色。", "二義俱寂滅，誰受此說者。", "是說亦寂滅，誰爲此說者。", "能觀及所觀，能聽洎所聽。", "返觀觀聽者，是亦無所有。", "大哉觀世音，快說如是法。", "是法不思議，聽者亦希有。", "我今以一毛，遍量法界空。", "作此如幻言，讚是真實要。"]'),
('8753af16-c6b1-480a-90d8-d721c60770b2','入定觀音讚','釋宗杲','宋','宋诗','song-poetry','','[]','世間種種音聲相，衆以耳聽非目睹。',176,'全唐诗/poet.song.99000.json','["世間種種音聲相，衆以耳聽非目睹。", "唯此大士眼能觀，瞑目諦觀爲佛事。", "於眼境界無所取，耳鼻舌身意亦然。", "善哉心洞十方空，六根互顯如是義。", "眼色耳聲鼻嗅香，身觸意思無差別。", "當以此觀如是觀，取此爲實成妄想。", "若離妄想取實法，展轉惑亂失本心。", "本心既失隨顛倒，不見大士妙色身。", "無眼耳鼻舌身意，互顯這義亦寂滅。", "亦無在土妙色身，亦無種種音聲相。", "佛子能作如是觀，永離世間生死苦。"]'),
('91d2216f-2356-4eb3-b601-f8eea0d05496','維摩居士讚','釋宗杲','宋','宋诗','song-poetry','','[]','冷坐毘耶城，百病一時發。',24,'全唐诗/poet.song.99000.json','["冷坐毘耶城，百病一時發。", "不得文殊來，幾乎無合殺。"]'),
('a1963d49-bf17-4130-a136-ab49febe26a0','九祖伏馱密多尊者讚','釋宗杲','宋','宋诗','song-poetry','','[]','默坐半百春，無喜亦無瞋。',24,'全唐诗/poet.song.99000.json','["默坐半百春，無喜亦無瞋。", "東西行七步，抖擻舊精神。"]'),
('68c764c0-d143-4b6e-8c4c-77331cd08a29','初祖達磨大師讚','釋宗杲','宋','宋诗','song-poetry','','[]','來時已沒當門齒，去時唯有一隻履。',32,'全唐诗/poet.song.99000.json','["來時已沒當門齒，去時唯有一隻履。", "葱嶺那邊逢宋雲，十分彰露醜舉止。"]'),
('d534fa72-3ceb-4da7-b6b8-8144533b51e7','傅大士讚','釋宗杲','宋','宋诗','song-poetry','','[]','天上無彌勒，地下無彌勒。',24,'全唐诗/poet.song.99000.json','["天上無彌勒，地下無彌勒。", "拍版與門槌，畢竟是何物。"]'),
('3209934b-8500-4b14-8b0d-665471b6baad','六祖大鑑禪師讚','釋宗杲','宋','宋诗','song-poetry','','[]','擔柴賣火村裏漢，舌本瀾翻不奈何。',32,'全唐诗/poet.song.99000.json','["擔柴賣火村裏漢，舌本瀾翻不奈何。", "自道來時元沒口，卻能平地起風波。"]'),
('bb230b4d-0f13-4f06-a3ab-8f3125659b52','李長者讚','釋宗杲','宋','宋诗','song-poetry','','[]','以一毛端智，遍量法界空。',24,'全唐诗/poet.song.99000.json','["以一毛端智，遍量法界空。", "智空無自性，空智在其中。"]'),
('15ed9b15-b4f3-4867-bef1-8b472cf229aa','龐居士讚','釋宗杲','宋','宋诗','song-poetry','','[]','男女不婚嫁，隨緣賣笊籬。',24,'全唐诗/poet.song.99000.json','["男女不婚嫁，隨緣賣笊籬。", "這般滋味子，豈與外人知。"]'),
('1bae9cf7-b418-4899-b74a-b81fc18b1d10','趙州和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','庭柏無根，虛空有骨。',40,'全唐诗/poet.song.99000.json','["庭柏無根，虛空有骨。", "十分魯鈍，似遼天鶻。", "熱至乘涼，寒燒榾柮。", "夫是之謂，趙州古佛。"]'),
('88faf3d9-fa05-4dd7-b0b2-d41385ab8450','船子和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','驀口一橈玄路絕，藥山之道始流傳。',32,'全唐诗/poet.song.99000.json','["驀口一橈玄路絕，藥山之道始流傳。", "離鉤三寸無消息，覺海方乘般若船。"]'),
('10b9a53e-98be-4aa2-92fd-34e163d4a460','臨濟和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','稱鎚上捏出汁，枯骨裏敲出髓。',61,'全唐诗/poet.song.99000.json','["稱鎚上捏出汁，枯骨裏敲出髓。", "全無些子藴藉，一味賣弄口嘴。", "更說甚麽三要三玄，四種料揀。", "大似青天白日，十字街頭，見神見鬼。", "咄。"]'),
('60f4f068-c095-4b37-b9f1-cf0cb57e30bc','雲門和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','開雪峰口，出睦州氣。',63,'全唐诗/poet.song.99000.json','["開雪峰口，出睦州氣。", "袖手儼然，眈眈虎視。", "我說是言，有語無義。", "石火電光，咄哉鈍滯。", "伽梨勃窣知是誰，有人續得末後句，許爾親見渠儂。"]'),
('873e85cd-964a-48f0-9d15-636e4d21bf7f','布袋和尚讚二首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','三千威儀都不修，八萬細行渾不顧。',62,'全唐诗/poet.song.99000.json','["三千威儀都不修，八萬細行渾不顧。", "只因鬧市等箇人，被人喚作破落戶。", "兜率內院久拋離，縱歸迷卻來時路。", "稽首彌勒世尊，得恁寬腸大肚。"]'),
('c3ea0f34-b6d1-4270-8cfd-f1c6d8b47b72','布袋和尚讚二首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','肩擔一條吉撩棒，棒頭掛雙破木履。',64,'全唐诗/poet.song.99000.json','["肩擔一條吉撩棒，棒頭掛雙破木履。", "盡力撮卻布袋口，不知裏許有甚底。", "落落魄魄鬧市行，藞藞苴苴沒羞恥。", "龍華會上若逢渠，定與椎落當門齒。"]'),
('23fee599-244c-46ba-a41d-c01996595ed8','金華聖者讚','釋宗杲','宋','宋诗','song-poetry','','[]','金華聖者誰識，撞著豬頭便喫。',60,'全唐诗/poet.song.99000.json','["金華聖者誰識，撞著豬頭便喫。", "雖然無愛無憎，其奈有損有益。", "使得破落僧徒，也道逆行順行天莫測。", "若無末後一著，至今有口難分析。"]'),
('3aeadd2b-528a-44fd-a784-f8abe6c3219d','南安巖主讚','釋宗杲','宋','宋诗','song-poetry','','[]','贈以之中語，咸云祕密言。',48,'全唐诗/poet.song.99000.json','["贈以之中語，咸云祕密言。", "誰知此老子，非妙亦非玄。", "直截不藏覆，當機火裏蓮。", "誰人明此意，端坐自擎拳。"]'),
('b4a645d3-5747-4eb4-95fe-0b4bbf18fd34','言法華讚','釋宗杲','宋','宋诗','song-poetry','','[]','旋陀羅尼三昧，語默元無罣礙。',56,'全唐诗/poet.song.99000.json','["旋陀羅尼三昧，語默元無罣礙。", "攬衣著屐走街，剛被時人笑怪。", "問伊住止何處，向道我儂弗會。", "進前擬議思量，咄哉漆桶不快。"]'),
('a16dbe9e-86ce-4b59-9d8e-cc423978f45d','楊岐和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','異類中行，拕犁拽耙。',20,'全唐诗/poet.song.99000.json','["異類中行，拕犁拽耙。", "栗棘金圈，是何言話。"]'),
('7ed29383-46ac-4451-ab07-313f844288e0','白雲端和尚讚二首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','少處更減，多處又添。',20,'全唐诗/poet.song.99000.json','["少處更減，多處又添。", "達磨不會，卻反西天。"]'),
('d119e99d-673c-4551-acaa-0045261e21f7','白雲端和尚讚二首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','饑餐渴飲，閑坐困眠。',20,'全唐诗/poet.song.99000.json','["饑餐渴飲，閑坐困眠。", "赤手殺人，血濺梵天。"]'),
('91f3c79e-4f33-4ea5-a9e7-1b817f49d629','五祖演和尚讚二首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','赤骨力地，有𪛌無袴。',20,'全唐诗/poet.song.99000.json','["赤骨力地，有𪛌無袴。", "敢與海神，爭先鬬富。"]'),
('49f9ff7d-58b8-4ce3-ac84-cb9fd0b84e8b','五祖演和尚讚二首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','說大脫空，荷擔佛祖。',36,'全唐诗/poet.song.99000.json','["說大脫空，荷擔佛祖。", "七八圓全，不成三五。", "村歌社舞可憐生，引得兒孫弄泥土。"]'),
('93f10f67-a21a-4458-a758-8b2bb77dc9c6','西余端和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','被底禮寅朝，去住隨風掃。',74,'全唐诗/poet.song.99000.json','["被底禮寅朝，去住隨風掃。", "名呼章相公，侮嫚圓照老。", "不托和尚，兩拳打翻。", "回頭妖僧，一句罵倒。", "只看這幾著子，不必問他禪道。", "箇是金毛師子兒，狐貍野干徒叫譟。"]'),
('5409ea89-ffa0-47ef-952a-08089ec4bf57','慧日雅和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','嵌嵌枯枯，磊磊落落。',86,'全唐诗/poet.song.99000.json','["嵌嵌枯枯，磊磊落落。", "喑嗚叱咤，萬人氣索。", "宴坐胡床，傾湫倒嶽。", "秉殺活劍，解生死縛。", "不墮塵緣，寧居寂寞。", "豁開濟北，三要三玄。", "提持關西，末後一著。", "慧日之影沈姑谿，泥牛觸折祥麟角。"]'),
('7e8683da-6b66-41c9-ba3c-4e36c2de3eac','寂音尊者讚','釋宗杲','宋','宋诗','song-poetry','','[]','頭如杓，面如楪。',56,'全唐诗/poet.song.99000.json','["頭如杓，面如楪。", "口無舌，說無竭。", "是而非，同而別。", "種空華，抽暗楔。", "死木蛇，活如蝎。", "擊塗毒，腦門裂。", "是阿誰，甘露滅。"]'),
('554a60bf-ed35-4ed9-ab0e-44cdd8744164','草堂清和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','凜凜孤風世所稀，碧眸炯炯電光輝。',64,'全唐诗/poet.song.99000.json','["凜凜孤風世所稀，碧眸炯炯電光輝。", "貧兒示與衣中寶，富者教伊赤體歸。", "毒手慣曾烹佛祖，洪鑪常用大鉗鎚。", "小根魔子還知否，此是吾家真白眉。"]'),
('e8961e40-4315-4f96-af8d-c1fc057850c6','圜悟和尚讚三首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','道大德備之詞，讚師之真。',123,'全唐诗/poet.song.99000.json','["道大德備之詞，讚師之真。", "此處無金二兩，俗人酤酒三升。", "超佛越祖之談，讚師之禪。", "削圓方竹杖，鞔卻紫茸氈。", "無可論，無可說，正是守著繫驢橛。", "那堪更言七坐道場三奉詔旨，大似鄭州出曹門，且喜沒交涉。", "降此之外，畢竟如何。", "江南兩浙，春寒秋熱。", "寄語諸方，不要饒舌。"]'),
('fa61b683-9d84-46b7-8e91-d7f0509c5686','圜悟和尚讚三首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','風雷爲舌，虛空爲口。',50,'全唐诗/poet.song.99000.json','["風雷爲舌，虛空爲口。", "應群生機，作師子吼。", "眼光爍破四天下，驚起法身藏北斗。", "箇是楊岐嫡孫，喝下須彌倒走。"]'),
('a7e73db8-572d-4349-b997-1585a94b06ad','圜悟和尚讚三首  其三','釋宗杲','宋','宋诗','song-poetry','','[]','這老漢無置錐之地而不貧，有無價之寶而不富。',81,'全唐诗/poet.song.99000.json','["這老漢無置錐之地而不貧，有無價之寶而不富。", "睹衆善而不欣，遇諸惡而不怖。", "一著當陽全提，要且秋毫不露。", "有時石火裏藏身，卻向電影中回互。", "塞卻臨濟三玄門，截斷巖頭末後句。"]'),
('88e219cd-5840-4571-be03-148c118930e3','普融平和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','示無作相，擊塗毒鼓。',60,'全唐诗/poet.song.99000.json','["示無作相，擊塗毒鼓。", "行無緣惡，誅佛誅祖。", "如是見得普融，妙喜未敢相許。", "直下來也，如龍似虎。", "一槌打破太虛空，至今一缺無人補。"]'),
('b1012715-8eb0-4970-aa72-cf17d734002f','長靈卓如和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','厚重如山，嚴冷似鐵。',114,'全唐诗/poet.song.99000.json','["厚重如山，嚴冷似鐵。", "破毘盧印，坐衲僧舌。", "派出靈源，源清流徹。", "指曜靈寒，呼顧兔熱。", "謂此是長靈眼中重著屑，謂此非長靈知君猶未瞥。", "是耶非耶，俱爲剩說。", "真耶妄耶，水中捉月。", "而今要見這老人，剔起眉毛須辨別。", "嘉州大像喫一槌，陝府鐵牛流出血。"]'),
('d7e5f72d-b906-451b-a752-b63641b8bb7a','佛性泰和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','慣說五家宗派禪，不將玄妙與人傳。',32,'全唐诗/poet.song.99000.json','["慣說五家宗派禪，不將玄妙與人傳。", "晚年一處真奇特，食罷長伸兩腳眠。"]'),
('496888ea-c53d-4292-b491-1771b460f9a7','佛燈珣和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','天姿出格蕭灑，胸次過人惺惺。',66,'全唐诗/poet.song.99000.json','["天姿出格蕭灑，胸次過人惺惺。", "臨濟頂中髓，楊岐眼裏睛。", "棒頭明殺活，喝下顯疏親。", "孤鸞無伴侶，師子不同群。", "鍾山佛鑑這嫡子，雙徑山僧之法兄。"]'),
('df200baf-40eb-4f7d-a9a0-8ff047807fa8','竹庵珪和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','讚嘆竹庵也是妙喜，罵詈竹庵也是妙喜，讚之罵之各有所以。',110,'全唐诗/poet.song.99000.json','["讚嘆竹庵也是妙喜，罵詈竹庵也是妙喜，讚之罵之各有所以。", "讚之者爲渠具衲僧正眼，罵之者爲渠浸在醋甕裏。", "或曰如竹庵之爲宗師也，不可讚不可罵。", "精金美玉自有定價，讚之罵之徒增話欛。", "妙喜聞之笑而不答，但拊掌叩齒三下，從教渠讚龜打瓦。"]'),
('df83e84e-45a8-42ee-8232-853076bc8dda','天童和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','烹佛烹祖大鑪韝，鍛凡鍛聖惡鉗鎚。',117,'全唐诗/poet.song.99000.json','["烹佛烹祖大鑪韝，鍛凡鍛聖惡鉗鎚。", "起曹洞於已墜之際，針膏肓於必死之時。", "善說法要，罔涉離微。", "不起于座，而變荆棘林爲梵釋龍天之宮而無作無爲。", "神澄定靈，雪頂龐眉。", "良工幻出兮，不許僧繇知。", "虛堂張掛兮，梁寶公猶迷。", "箇是天童老古錐，妙喜知音更有誰。"]'),
('4391228c-81fc-4bae-9f4b-f8b55149eed7','普明琳和尚讚','釋宗杲','宋','宋诗','song-poetry','','[]','觸處無礙，得大自在。',38,'全唐诗/poet.song.99000.json','["觸處無礙，得大自在。", "達磨脊梁，釋迦腦蓋。", "夫是之謂普明老人，敢與諸塵作對者也。"]'),
('a942d692-6ea0-461f-86a4-0db263c53397','李參政請讚','釋宗杲','宋','宋诗','song-poetry','','[]','這漢沒量罪過，不合引惹措大。',56,'全唐诗/poet.song.99000.json','["這漢沒量罪過，不合引惹措大。", "被渠笑裏藏刀，殺卻吾祖達磨。", "不知有底冤讎，一向興災作禍，杲上座諾，惺惺著，莫教話墮。"]'),
('148cfd4c-a49c-4d18-b55c-de56b61d84dc','吳提刑請讚','釋宗杲','宋','宋诗','song-poetry','','[]','這箇村和尚，少人能近傍。',85,'全唐诗/poet.song.99000.json','["這箇村和尚，少人能近傍。", "黑漆粗竹篦，佛來也一棒。", "沒秋毫人情，有萬千無狀。", "慈悲時觀音菩薩之所不如，瞋恚時阿脩羅王亦難比況。", "世上可憎可惡者是這般底阿師，如何，也有人畫渠供食。"]'),
('ad3d33cf-0e24-4377-8fb6-a6932d83789d','鄭學士請讚','釋宗杲','宋','宋诗','song-poetry','','[]','參得圜悟禪，擔起睦州版。',64,'全唐诗/poet.song.99000.json','["參得圜悟禪，擔起睦州版。", "透過祖師關，瞎卻頂門眼。", "肚裏黑漫漫，這中平坦坦。", "性氣得人憎，發時渾不管。", "鞏縣茶瓶喫一槌，擊碎饒州白瓷碗。"]'),
('98055b19-80ff-49cf-90b6-e6e7d7326daf','蔡郎中請讚','釋宗杲','宋','宋诗','song-poetry','','[]','賦性暴，舉止傲，說甚禪，談甚道。',52,'全唐诗/poet.song.99000.json','["賦性暴，舉止傲，說甚禪，談甚道。", "有箇沒意智獃郎，隨例妄想顛倒。", "蔡郎中還見麽，若也當面諱卻，便是監主自盜。"]'),
('7789db17-dbbf-4587-b233-e070ff395897','蔡宣教請讚','釋宗杲','宋','宋诗','song-poetry','','[]','手裏指東畫西，口中胡說亂道。',57,'全唐诗/poet.song.99000.json','["手裏指東畫西，口中胡說亂道。", "一生慣打葛藤，天真不屬做造。", "有箇蔡正卿，時時來著到。", "水流濕，火就燥，馬面團圞隨人所好。"]'),
('a285d1a5-5f3c-4e19-8c58-f325f075da17','蔡宣教請讚','釋宗杲','宋','宋诗','song-poetry','','[]','咄哉無知，半憨半癡。',52,'全唐诗/poet.song.99000.json','["咄哉無知，半憨半癡。", "黑豆換人眼睛，十分愛討便宜。", "一朝死入地獄，定墮鑊湯泥犁。", "佛也救爾不得，任爾鳳林吒之。"]'),
('60b749aa-0586-4c0c-9da1-d8450d14f673','儲大夫請讚','釋宗杲','宋','宋诗','song-poetry','','[]','雲門妙喜真，雲臺居士畫。',87,'全唐诗/poet.song.99000.json','["雲門妙喜真，雲臺居士畫。", "利鈍不相資，展向虛堂掛。", "妙利中鈍，鈍得顢頇。", "雲臺鈍中利，利得脫酒。", "如今利鈍都掛壁，師子翻身絕蹤跡。", "蹤跡無，便塗糊，一時分付諸大夫。", "唵摩尼達里悉利蘇盧。"]'),
('22a6536f-7608-4500-a121-26bfc7bbe13f','趙通判請讚','釋宗杲','宋','宋诗','song-poetry','','[]','渭汝是善人耶，嫉惡之太甚。',73,'全唐诗/poet.song.99000.json','["渭汝是善人耶，嫉惡之太甚。", "謂汝是惡人耶，好賢而樂善。", "而於善惡兩塗之間了無遺恨。", "咦，好箇自是漢，高談無畔岸，成佛作祖且緩緩。", "這一則公案，分付趙通判。"]'),
('608b6a38-c5d5-4f9d-9dd7-d164ad614241','許司理請讚','釋宗杲','宋','宋诗','song-poetry','','[]','湛不搖處，正好著力。',56,'全唐诗/poet.song.99000.json','["湛不搖處，正好著力。", "欲識吾真，出陰界入。", "一毛端頭，師子返擲。", "赤肉團上，萬仞壁立。", "沖密湛然知不知，鐵牛生得玉貓兒。"]'),
('2d9a2880-e5cf-4b6a-b080-35abfc1e817d','廖知縣請讚','釋宗杲','宋','宋诗','song-poetry','','[]','我讚我真，孰能委悉。',70,'全唐诗/poet.song.99000.json','["我讚我真，孰能委悉。", "火風煗動，地水堅濕。", "俱屬現量，擬心則失。", "就而明之，是妄非實。", "背而捐之，土木瓦石。", "吾說是言，如箭射的。", "離此別求，幻惑無識。"]'),
('c7075b4d-8131-422a-a028-b2ccbf872116','朱主簿請讚','釋宗杲','宋','宋诗','song-poetry','','[]','龐老曾升馬祖堂，西江吸盡更無雙。',32,'全唐诗/poet.song.99000.json','["龐老曾升馬祖堂，西江吸盡更無雙。", "而今妙喜朱居士，覿面分明不覆藏。"]'),
('69337d8e-993c-4e69-95fa-c5d315450510','聞監務請讚','釋宗杲','宋','宋诗','song-poetry','','[]','謂汝太惺惺，時復放淈𣸩。',60,'全唐诗/poet.song.99000.json','["謂汝太惺惺，時復放淈𣸩。", "謂汝太褊急，間或又容物。", "既作人天師，開口便輕忽。", "莊嚴賢劫中，且無如此佛。", "寄語聞子清，莫信這箇賊。"]'),
('7d0ef583-60c7-4cd5-b510-4f9ac51673d7','唐道人請讚','釋宗杲','宋','宋诗','song-poetry','','[]','這尊慈，無摸索。',82,'全唐诗/poet.song.99000.json','["這尊慈，無摸索。", "忽地喜，忽地惡。", "喜也，和氣如春百華開萼，怒也，雷電風雲一時俱作。", "似恁麽做處，若非阿脩羅王，即是金僊大覺。", "唐道人，緊收卻。", "逢人不用展開，卷來送在壁角。"]'),
('7f8535e3-ec7f-4899-8d24-283ff73628ee','江令請讚','釋宗杲','宋','宋诗','song-poetry','','[]','渠本宣州人，生緣在寧國。',84,'全唐诗/poet.song.99000.json','["渠本宣州人，生緣在寧國。", "前不尊釋迦，後不敬彌勒。", "家貧無飯噇，出家去投佛。", "行腳走諸方，江南遍江北。", "纔參臨濟禪，便作白拈賊。", "眼裏有瞳人，肚中無點墨。", "還如跛阿師，說得行不得。"]'),
('0b43a8f1-a2ab-464e-a48c-17b88826e159','無著道人請讚','釋宗杲','宋','宋诗','song-poetry','','[]','汝求吾之讚，復讚吾之真。',112,'全唐诗/poet.song.99000.json','["汝求吾之讚，復讚吾之真。", "大海絕涓滴，須彌無一塵。", "以訐爲直而非直，以察爲明而非明。", "象王回旋，師子嚬呻。", "性不可會，瞥喜瞥瞋。", "與佛祖爲冤敵，與魔外爲親姻。", "自是其是，而人不汝是。", "自神其神，而人不汝神。", "如此爲人善知識，少喫酸醋三五升。"]'),
('7dd27c54-34b9-49f4-828b-a7c892a434c9','超宗道人請讚','釋宗杲','宋','宋诗','song-poetry','','[]','一條白棒，佛祖俱打。',50,'全唐诗/poet.song.99000.json','["一條白棒，佛祖俱打。", "超宗禪人，大膽不怕。", "畫我來乞讚，鬼門上帖卦。", "三十年後此話大行，任一切人鑽龜打瓦。"]'),
('26da643a-af31-4cbb-9cce-d5e5ef404e16','舟峰長老求讚','釋宗杲','宋','宋诗','song-poetry','','[]','蕭蕭灑灑，有取有捨。',76,'全唐诗/poet.song.99000.json','["蕭蕭灑灑，有取有捨。", "藞藞苴苴，無真無假。", "客來須看，賊來須打。", "一條竹篦，天上天下。", "背觸當鋒，任人酬價。", "咄哉村僧，少說大話。", "龜年收取掛高堂，從他讚嘆從他罵。"]'),
('18eb656a-f8ab-4ea9-bbe4-d491bd8f6c6e','鼎需禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','身心一如，身外無餘。',20,'全唐诗/poet.song.99000.json','["身心一如，身外無餘。", "咄這瞎驢，付與鼎需。"]'),
('a22abc1b-2c62-4568-9776-d17021b053db','藴聞禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','藴聞聞自性，自性離聞藴。',24,'全唐诗/poet.song.99000.json','["藴聞聞自性，自性離聞藴。", "吾真亦復然，迥超千聖頂。"]'),
('009d82dd-c2c7-4094-b2f0-f3a39fb7f90b','用宣禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','宣傳吾真，吾爲宣說。',20,'全唐诗/poet.song.99000.json','["宣傳吾真，吾爲宣說。", "眨上眉毛，大巧若拙。"]'),
('b0f3fdb0-bbde-4a49-943e-0fa49417cb60','思岳禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','兩耳卓朔口門窄，兩眼皮薄鼻露竅。',32,'全唐诗/poet.song.99000.json','["兩耳卓朔口門窄，兩眼皮薄鼻露竅。", "一生舌本謾瀾翻，何曾唱得胡家調。"]'),
('a694f888-2e20-4e50-b71d-e4826486e43f','悟本禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','一千七百癡衲子，圍遶這箇無明叟。',112,'全唐诗/poet.song.99000.json','["一千七百癡衲子，圍遶這箇無明叟。", "細膩渾沒一星兒，粗糙卻有七八斗。", "未嘗寂寂入禪定，終日波波廊下走。", "爲人巴鼻亦好笑，更不容人謾開口。", "盲枷瞎棒當慈悲，是與不是劈脊婁。", "如斯主法作宗師，枉續牟尼子孫後。", "本禪千萬莫學伊，學伊和爾不唧溜。"]'),
('a35b1d5d-692d-42c3-9506-50adcde3405a','法寶禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','這無狀，世間稀。',46,'全唐诗/poet.song.99000.json','["這無狀，世間稀。", "住佛屋，著佛衣。", "噇佛飯，說佛非。", "多忿怒，少慈悲。", "畫得似差毫氂，寶禪者應自知。"]'),
('c6014031-4ee4-47f0-a2f6-bd0aa4dadc10','守凈禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','瞋恚癡未除，心意識顛倒。',56,'全唐诗/poet.song.99000.json','["瞋恚癡未除，心意識顛倒。", "談禪信口開，舌頭胡亂掃。", "其施汝者不名福田，供養汝者墮三惡道。", "箇是雲門村僧，即非杜撰長老。"]'),
('09f687da-e9d8-4808-833e-7832782de503','遵璞禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','臨濟燒黄檗禪版，香嚴哭溈山拄杖。',65,'全唐诗/poet.song.99000.json','["臨濟燒黄檗禪版，香嚴哭溈山拄杖。", "雲門村叟效顰，顰也作這般伎倆。", "咄。", "傳來鐵鉢盛貓飯，磨衲袈裟入墨盆。", "祖翁活計那壞了，不知將底付兒孫。"]'),
('3a5d774d-07cc-4271-b633-5fb6c3f22bbb','僧鶚禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','這漢一生空倔彊，偏向人前放軟頑。',64,'全唐诗/poet.song.99000.json','["這漢一生空倔彊，偏向人前放軟頑。", "涅槃路上栽荆棘，解脫門前緊著關。", "不別法身三種病，豈識楞嚴義八還。", "謾把少林在孔笛，等閑吹過汩羅灣。"]'),
('05de65cd-5bb5-4b7c-a96c-751cae61b2cb','晉言禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','虛空裏揣出骨，閃電中作窼窟。',28,'全唐诗/poet.song.99000.json','["虛空裏揣出骨，閃電中作窼窟。", "有問妙喜家風，此外更無別物。"]'),
('96847bfe-5d93-4213-9031-b1b375fee9da','祖傳禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','藞苴全似川僧，蕭灑渾如浙客。',80,'全唐诗/poet.song.99000.json','["藞苴全似川僧，蕭灑渾如浙客。", "偏向情未生時，拈出報慈一隔。", "尊性不定，莫可窺測。", "見小時嫌蟭螟眼太寬，見大時謂太虛空忒窄。", "似這般底阿師，如何受人天供養，好與劈腮一摑。"]'),
('6f7d7f97-8d80-417c-8d8d-71931f81d02c','妙道禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','這村僧，無明大。',104,'全唐诗/poet.song.99000.json','["這村僧，無明大。", "少柔和，多褊隘。", "愛罵人，舌頭快。", "受佛蔭，破佛戒。", "不精進，常懈怠。", "謗般若，彌天罪。", "入地獄，永不悔。", "聞者憎，見者怪。", "撹叢林，尤叵耐。", "虛銷信施三十年，異世出頭償夙債。", "就中只有一處長，解道雞嶼洋無蓋。"]'),
('619c07e3-dabe-4631-abfe-8dbaef6039d3','沖密禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','佛祖有密語，有說即不密。',48,'全唐诗/poet.song.99000.json','["佛祖有密語，有說即不密。", "密禪畫吾真，密意已漏泄。", "如析栴檀香，片片體非別。", "密意在其中，密亦如是說。"]'),
('adca9faf-0777-44e2-95b8-179bfe55043a','文俊禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','咄這擔版漢，從來無所知。',48,'全唐诗/poet.song.99000.json','["咄這擔版漢，從來無所知。", "曾經一頓飽，忘卻累年饑。", "動便觸人諱，拍盲不識時。", "平生沒活計，赤手討便宜。"]'),
('5d7c5fda-285e-4fdf-92b5-6c3ac4988db7','如本禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','真兮妄兮兩孤，作對待兮偏枯。',44,'全唐诗/poet.song.99000.json','["真兮妄兮兩孤，作對待兮偏枯。", "水凌虛而風靜兮月非無，即妄即真兮毒藥與醍醐。", "到此誰人識得渠。"]'),
('8cd5b1a2-3573-4614-b6e5-4a90cde334a5','法宏禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','不曾動著舌頭，葛藤已遍天下。',56,'全唐诗/poet.song.99000.json','["不曾動著舌頭，葛藤已遍天下。", "等閑一擊虛空，隨手便成縫罅。", "法宏貌得吾真，仿佛鎮州普化。", "我今寫讚上頭，要作叢林佳話。"]'),
('0b27f97d-a555-4e6f-b999-023ab79103d1','德光禪人求讚','釋宗杲','宋','宋诗','song-poetry','','[]','有德必有光，其光無間隔。',79,'全唐诗/poet.song.99000.json','["有德必有光，其光無間隔。", "名實要相稱，非青黄赤白。", "參徹佛祖頂𩕳禪，不是等閑相誑嚇。", "我所參得底只要涅槃堂裏用，且不聽杜撰禪師三千八百畫。", "吾爲作證明，他年將作軌格。"]'),
('ca7f1ee3-5108-4d92-9adb-1f88228cd885','若懷首座求讚歸洋嶼庵','釋宗杲','宋','宋诗','song-poetry','','[]','吾於閩有大因緣，夜夢晝思無間然。',32,'全唐诗/poet.song.99000.json','["吾於閩有大因緣，夜夢晝思無間然。", "他日定歸洋嶼去，楞伽室內作終焉。"]'),
('c6a82abf-6418-452a-a384-23393c90ae74','雪峰空長老求讚','釋宗杲','宋','宋诗','song-poetry','','[]','慧空抓著吾癢處，吾嘗劄著伊痛處。',145,'全唐诗/poet.song.99000.json','["慧空抓著吾癢處，吾嘗劄著伊痛處。", "痛處癢，癢處痛，不與千聖同途，豈與衲僧共用。", "莫言掃帚竹裏無錢筒，蒿枝叢林無梁棟。", "雖然家醜不可外揚，也要諸方眼目定動。", "而今各自不得已，一任畫出這般不唧溜底老凍{鼻|鳥/瓜}。", "但將懸向壁角落頭，使來者瞻之仰之。", "晝夜六時燒兜樓婆畢力迦沈水栴檀之香，作七代祖翁之供。"]'),
('ad17f564-dfe6-4c7c-af65-c80da413adc5','師玿長老求讚','釋宗杲','宋','宋诗','song-poetry','','[]','畫得百千本，都盧祇這是。',24,'全唐诗/poet.song.99000.json','["畫得百千本，都盧祇這是。", "師玿好承當，楊岐第七世。"]'),
('464dc314-4da3-498a-9cc3-f09357a16d10','禪人求讚  其一','釋宗杲','宋','宋诗','song-poetry','','[]','咄哉滅胡種，面目真可惡。',84,'全唐诗/poet.song.99000.json','["咄哉滅胡種，面目真可惡。", "過橋便拆橋，得路便塞路。", "雖欲彊柔和，畢竟觸人怒。", "萬事類如此，誰敢相親附。", "乞兒囊本空，常誇敵國富。", "聞說閻羅王，未免生怕怖。", "休更放大言，嫌佛不肯做。"]'),
('e23ca290-dc9c-4549-8353-e9e34c5f2b4f','禪人求讚  其二','釋宗杲','宋','宋诗','song-poetry','','[]','鄒搜斂似天烝棗，輕輕觸著便煩惱。',64,'全唐诗/poet.song.99000.json','["鄒搜斂似天烝棗，輕輕觸著便煩惱。", "身著如來三事衣，口中謗佛法僧寶。", "從來纖芥不與人，一毫不就他人討。", "驀然合眼入黄泉，定須聒噪閻羅老。"]'),
('c6cf82db-3eb7-40bb-bae4-ae76d40e7d11','禪人求讚  其三','釋宗杲','宋','宋诗','song-poetry','','[]','上無片瓦蓋頭，下無卓錐之地。',44,'全唐诗/poet.song.99000.json','["上無片瓦蓋頭，下無卓錐之地。", "赤骨𩪸箇渾身，與人爭甚閑氣。", "些子無明不奈何，說甚祖師西來意。"]'),
('fcc1a5b4-d27c-49de-b4f2-61f45ee1b775','禪人求讚  其四','釋宗杲','宋','宋诗','song-poetry','','[]','鐵蛇在握，毒氣爍爍。',20,'全唐诗/poet.song.99000.json','["鐵蛇在握，毒氣爍爍。", "擬議不來，劈口便著。"]'),
('8409ff7a-adcc-4e94-8893-303b77eaa334','臨寂頌','釋宗杲','宋','宋诗','song-poetry','','[]','生也只恁麽，死也只恁麽。',24,'全唐诗/poet.song.99000.json','["生也只恁麽，死也只恁麽。", "有偈與無偈，是甚麽熱大。"]'),
('38505cfc-906d-4aa6-96d0-430cfa68a773','偈頌十四首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','普提宿將坐重圍，劫外時聞木馬嘶。',32,'全唐诗/poet.song.99000.json','["普提宿將坐重圍，劫外時聞木馬嘶。", "寸刃不施魔膽碎，望風先已竪降旗。"]'),
('53d62f84-a89b-416f-b3d1-4b6d82b3835a','偈頌十四首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','開人眼，閉人眼。',47,'全唐诗/poet.song.99000.json','["開人眼，閉人眼。", "一手推，一手挽。", "不是三要三玄，亦作四種料揀。", "畢竟是箇甚麽，雲峰輥毬，睦州擔板。"]'),
('9a693f34-208d-4af5-930f-2f597b8d0744','偈頌十四首  其三','釋宗杲','宋','宋诗','song-poetry','','[]','一刀截斷生死路，摩醯正眼頂門開。',32,'全唐诗/poet.song.99000.json','["一刀截斷生死路，摩醯正眼頂門開。", "無邊業障俱鎖殞，寒山拾得在天台。"]'),
('ff6af14c-55b3-4289-b4c7-9f665ffd4220','偈頌十四首  其四','釋宗杲','宋','宋诗','song-poetry','','[]','女流中有大丈夫，示現其身化其類。',160,'全唐诗/poet.song.99000.json','["女流中有大丈夫，示現其身化其類。", "以戒定慧解脫法，攝彼貪欲瞋恚癡。", "雖處於中作佛事，如風行空無所依。", "過去未來及現在，塵沙諸佛及菩薩。", "異口同音發是言，善哉奇特世希有。", "心源清凈無憂喜，不作無喜無憂想。", "逢場作戲隨世緣，而於世緣無所著。", "六月火雲燒碧空，雷聲忽震三千界。", "銷除熱惱獲清涼，是彼丈夫誕時節。", "我說此偈助光明，普施法界諸女人。"]'),
('f5a0fef8-0ace-4d4d-8cdc-4eabd8483b79','偈頌十四首  其五','釋宗杲','宋','宋诗','song-poetry','','[]','佛之一字尚不喜，有何生死可相關。',32,'全唐诗/poet.song.99000.json','["佛之一字尚不喜，有何生死可相關。", "當機覿面難回互，說甚楞嚴義八還。"]'),
('b4a70546-46e9-4388-9b03-f129ea20155f','偈頌十四首  其六','釋宗杲','宋','宋诗','song-poetry','','[]','無諸比丘名近悅，爲母王氏請普說。',161,'全唐诗/poet.song.99000.json','["無諸比丘名近悅，爲母王氏請普說。", "妙喜便登曲收彔床，忉忉怛怛恣饒舌。", "從來法本離言詮，不假思量與分別。", "說甚地獄及天堂，四聖六凡俱泯絕。", "縱有魔王欲作難，金剛寶劍當頭截。", "王氏養子要參禪，只這一念永不滅。", "彈指頓明諸法門，釋迦彌勒齊超越。", "還如塗毒鼓當軒，一擊聞之皆腦裂。", "無邊煩惱悉蠲除，夙業舊殃湯沃雪。", "末後一句爲重宣，凝然萬里一條鐵。"]'),
('79c55550-678c-4e02-b83a-c8dcbacfe211','偈頌十四首  其七','釋宗杲','宋','宋诗','song-poetry','','[]','荒田無人耕，耕著有人爭。',24,'全唐诗/poet.song.99000.json','["荒田無人耕，耕著有人爭。", "無風荷葉動，決定有魚行。"]'),
('a0e7851f-97e6-4abd-8e69-625d848c7454','偈頌十四首  其八','釋宗杲','宋','宋诗','song-poetry','','[]','青氈本是吾家物，今日重還舊日僧。',32,'全唐诗/poet.song.99000.json','["青氈本是吾家物，今日重還舊日僧。", "珍重聖恩何以報，萬年松上一枝藤。"]'),
('53edf429-d20a-4ae5-987e-02bbf34aa3d4','偈頌十四首  其九','釋宗杲','宋','宋诗','song-poetry','','[]','惡念既不生，善念常相續。',24,'全唐诗/poet.song.99000.json','["惡念既不生，善念常相續。", "諸波羅密門，一切自具足。"]'),
('0d40ef49-c1fe-4e97-adcb-326f4a2aa969','偈頌十四首  其一○','釋宗杲','宋','宋诗','song-poetry','','[]','覺空空，覺空空。',34,'全唐诗/poet.song.99000.json','["覺空空，覺空空。", "覺覺覺空，空空亦空。", "欲識無窮好消息，都盧只在此軒中。"]'),
('0d0de063-6539-4e48-a129-1116b9017e5d','偈頌十四首  其一一','釋宗杲','宋','宋诗','song-poetry','','[]','蓋天蓋地那一著，無今無古絕承當。',32,'全唐诗/poet.song.99000.json','["蓋天蓋地那一著，無今無古絕承當。", "謾將分付密禪者，一任諸方亂度量。"]'),
('1afa8d99-f166-4d9d-b0d3-612d014c284b','偈頌十四首  其一二','釋宗杲','宋','宋诗','song-poetry','','[]','瞎驢滅卻正法眼，臨濟宗風始大張。',32,'全唐诗/poet.song.99000.json','["瞎驢滅卻正法眼，臨濟宗風始大張。", "可憐裨販如來者，盡將蓋覆錯商量。"]'),
('e1c66e35-df95-488c-b94e-f071fc707140','偈頌十四首  其一三','釋宗杲','宋','宋诗','song-poetry','','[]','無上大涅槃，圓明常寂照。',192,'全唐诗/poet.song.99000.json','["無上大涅槃，圓明常寂照。", "凡愚謂之死，外道執爲斷。", "諸求一乘入，目以爲無作。", "盡屬情所計，六十二見本。", "妄立虛假名，何爲真實義。", "唯有過量人，通達無取捨。", "以知五藴法，及以藴中我。", "外現衆色像，一一音聲相。", "平等如夢幻，不起凡聖見。", "不作涅槃解，二邊三際斷。", "常應諸根用，而不起用想。", "分別一切法，不起分別想。", "劫火燒海底，風鼓山相擊。", "真常寂滅樂，涅槃相如是。", "吾今彊言說，令汝捨邪見。", "汝勿隨言解，許汝知少分。"]'),
('bded7b02-3b81-4a59-b3e9-a1581873495e','偈頌十四首  其一四','釋宗杲','宋','宋诗','song-poetry','','[]','只欠{囗九}地一下爾，若得{囗九}地一下了。',88,'全唐诗/poet.song.99000.json','["只欠{囗九}地一下爾，若得{囗九}地一下了。", "儒即釋，釋即儒。", "僧即俗，俗即僧。", "凡即聖，聖即凡。", "我即爾，爾即我。", "天即地，地即天。", "波即水，水即波。", "酥酪醍醐攪成一味，瓶盤釵釧鎔成一金。"]'),
('94189094-72bb-42da-9335-acb3cb8fe61f','偈頌十四首  其一五','釋宗杲','宋','宋诗','song-poetry','','[]','莫戀凈潔處，凈處使人困。',96,'全唐诗/poet.song.99000.json','["莫戀凈潔處，凈處使人困。", "莫戀快活卜，快活使人狂。", "如水之任器，隨方圓短長。", "放下不放下，更請細思量。", "三界與萬法，匪歸何有鄉。", "若只便恁麽，此事大乖張。", "爲報許居士，家親作禍殃。", "豁開千聖眼，不須頻禱禳。"]'),
('181e569f-f0b0-46ab-80d7-82d0a51c73a1','畫髑髏頌','釋宗杲','宋','宋诗','song-poetry','','[]','即此形骸，便是其人。',20,'全唐诗/poet.song.99000.json','["即此形骸，便是其人。", "一靈皮袋，皮袋一靈。"]'),
('45e0520b-9e87-4c79-8924-3b1154e8f4e5','讚法海真','釋宗杲','宋','宋诗','song-poetry','','[]','廓圓通門，續雲門派。',60,'全唐诗/poet.song.99000.json','["廓圓通門，續雲門派。", "燕坐胡床，虎視百怪。", "佩毘盧印，摧伏魔外。", "一句當陽，電光非快。", "不動道場，而入三昧。", "贊之毀之，俱遭白癩。"]'),
('0c4afb22-a113-4ae9-8ab7-c1a81b7bfbce','頌古六首  其一','釋宗杲','宋','宋诗','song-poetry','','[]','三千威儀都不修，八萬細行全不顧。',63,'全唐诗/poet.song.99000.json','["三千威儀都不修，八萬細行全不顧。", "只因鬧市裏等人，被人喚作破落戶。", "兜率內院久拋離，縱歸忘卻來時路。", "稽首彌勒世尊，得與麽寬腸大肚。"]'),
('0da6f57a-3fe7-4a59-a852-d8be552ab697','頌古六首  其二','釋宗杲','宋','宋诗','song-poetry','','[]','擔柴賣火村裏漢，舌本瀾翻不奈何。',32,'全唐诗/poet.song.99000.json','["擔柴賣火村裏漢，舌本瀾翻不奈何。", "自道來時元沒口，卻能平地起風波。"]'),
('97cf962d-ee64-45ca-ae12-5bb2ae170f7e','頌古六首  其三','釋宗杲','宋','宋诗','song-poetry','','[]','即心即佛莫妄求，非心非佛休別討。',32,'全唐诗/poet.song.99000.json','["即心即佛莫妄求，非心非佛休別討。", "紅爐燄上雪花飛，一點清涼除熱惱。"]'),
('7dd406cf-fdc6-4767-b97d-b86b56c0e92d','頌古六首  其四','釋宗杲','宋','宋诗','song-poetry','','[]','驀口一橈玄路絕，藥山之道始流傳。',32,'全唐诗/poet.song.99000.json','["驀口一橈玄路絕，藥山之道始流傳。", "離鈎三寸無消息，覺海說乘般若船。"]'),
('a0d24a96-d108-431a-9228-c0c0b2bdb2d1','頌古六首  其五','釋宗杲','宋','宋诗','song-poetry','','[]','俱胝一指頭，喫飯飽方休。',24,'全唐诗/poet.song.99000.json','["俱胝一指頭，喫飯飽方休。", "腰纏十萬貫，騎鶴下揚州。"]'),
('d8a3dfec-71fe-45f6-a348-af6cb79d49f8','頌古六首  其六','釋宗杲','宋','宋诗','song-poetry','','[]','何必不必，綿綿密密，覿面當機。',31,'全唐诗/poet.song.99000.json','["何必不必，綿綿密密，覿面當機。", "有人續得末後句，許你親見二尊宿。"]'),
('aa122491-ba1f-4be9-af29-c86419394c53','澄馮楫居士會藥山問石頭見性成佛公案偈','釋宗杲','宋','宋诗','song-poetry','','[]','梵語唐言，打成一塊。',20,'全唐诗/poet.song.99000.json','["梵語唐言，打成一塊。", "咄哉俗人，得此三昧。"]'),
('2d416e62-7a3f-4822-a383-cf05dce0aaa1','證通身一具金鎖骨偈','釋宗杲','宋','宋诗','song-poetry','','[]','通身一具金鎖骨，堪與人天爲規則。',32,'全唐诗/poet.song.99000.json','["通身一具金鎖骨，堪與人天爲規則。", "要識臨濟小廝兒，便是當年白拈賊。"]'),
('8122569e-1a3f-4367-803a-9ff5d3e411e8','閱藏後題智證庵壁','釋宗杲','宋','宋诗','song-poetry','','[]','柏子拈來香滿廬，蒲團靜裏結跏呋。',32,'全唐诗/poet.song.99000.json','["柏子拈來香滿廬，蒲團靜裏結跏呋。", "三年過眼千千卷，此際分明一字無。"]'),
('3698e5d1-66f3-413c-a017-bd4a2affb422','偈四首  其一','釋曇賁','宋','宋诗','song-poetry','','[]','五百生中受屈，祇緣不識個落字。',44,'全唐诗/poet.song.99000.json','["五百生中受屈，祇緣不識個落字。", "百千衆中較量，祇緣不識個昧字。", "都來兩字淆訛，陷卻多少平直。"]'),
('12ef7b4b-2f19-43e0-a2e4-5ccbffcb6444','偈四首  其二','釋曇賁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','維摩病，說盡道理。',54,'全唐诗/poet.song.99000.json','["維摩病，說盡道理。", "龍翔病，咳嗽不已。", "咳嗽不已，說盡道理。", "說盡道理，咳嗽不已。", "本是長江湊風冷，卻教露柱患頭風。"]'),
('54d347fc-1ba9-4e54-ac4b-a87ce14ff969','偈四首  其三','釋曇賁','宋','宋诗','song-poetry','','[]','團圞擘不破，瀟灑覷不見。',24,'全唐诗/poet.song.99000.json','["團圞擘不破，瀟灑覷不見。", "喚作正法眼，入地獄如箭。"]'),
('6574fa5c-3832-4373-a29f-d4f2a23a4a40','偈四首  其四','釋曇賁','宋','宋诗','song-poetry','','[]','濃將紅粉傅了面，滿把真珠蓋卻頭。',32,'全唐诗/poet.song.99000.json','["濃將紅粉傅了面，滿把真珠蓋卻頭。", "不識佳人真面目，空教人唱小涼州。"]'),
('20597647-29cd-48b8-a80f-68d4b49486df','頌古四首  其一','釋曇賁','宋','宋诗','song-poetry','','[]','竿頭崖頭撒手去，閬州澧州尋路歸。',32,'全唐诗/poet.song.99000.json','["竿頭崖頭撒手去，閬州澧州尋路歸。", "廉纖脫盡全機露，八角磨盤空裏飛。"]'),
('51cdca81-5415-49f6-98d1-158cebd136c3','頌古四首  其二','釋曇賁','宋','宋诗','song-poetry','','[]','婆子因行掉臂，趙州因事長智。',52,'全唐诗/poet.song.99000.json','["婆子因行掉臂，趙州因事長智。", "無端一句淆沎，惹得四海鼎沸。", "勘破了，有誰知。", "春風過後無消息，留得殘花一兩枝。"]'),
('71db95f5-d0cb-4e49-9444-6892f05acfaf','頌古四首  其三','釋曇賁','宋','宋诗','song-poetry','','[]','带雪含霜半倚籬，橫斜影裏露仙姿。',32,'全唐诗/poet.song.99000.json','["带雪含霜半倚籬，橫斜影裏露仙姿。", "前村昨夜春來了，竹屋老僧猶未知。"]'),
('82a1f20d-c75f-4a14-9fcc-2283b2a222d4','頌古四首  其四','釋曇賁','宋','宋诗','song-poetry','','[]','明宣一道聰明呪，暗寫兩行靈寶符。',32,'全唐诗/poet.song.99000.json','["明宣一道聰明呪，暗寫兩行靈寶符。", "謾道騎鯨遊六合，何曾有夢到華胥。"]'),
('1ce81e25-2ad7-4f60-9da5-72d394b99e5f','悼落牙','釋曇賁','宋','宋诗','song-poetry','','[]','汝從何所來，遁跡在我口。',120,'全唐诗/poet.song.99000.json','["汝從何所來，遁跡在我口。", "美惡必同嘗，冷暖共知有。", "我口時動搖，汝體常堅守。", "夫何一病纏，遽落鉗匠手。", "汝今先我徂，我在嗟無後。", "堅者既不留，軟者豈能久。", "平生敲磕句，一一如雷吼。", "嚼破百彌盧，咬斷衆窼臼。", "我力既若是，汝形安得朽。", "無生復無離，庶洗言說咎。"]'),
('d7907250-ae3c-458c-a938-157bdc753f78','偈二首  其一','釋曇賁','宋','宋诗','song-poetry','','[]','一見便見，八角磨盤空裏轉。',54,'全唐诗/poet.song.99000.json','["一見便見，八角磨盤空裏轉。", "一得永得，辰錦朱砂如墨黑。", "秋風吹渭水，已落雲門三句裏。", "落葉滿長安，幾箇而今被眼瞞。"]'),
('36e761dc-40d5-4a97-8af5-5d364eafa8c3','偈二首  其二','釋曇賁','宋','宋诗','song-poetry','','[]','鬧籃方喜得抽頭，退鼓而今打未休。',32,'全唐诗/poet.song.99000.json','["鬧籃方喜得抽頭，退鼓而今打未休。", "莫把乳峰千丈雪，重來換我一雙眸。"]'),
('2685559d-dd4b-490a-b4b0-5092696a09b5','頌古二十七首  其一','釋曇賁','宋','宋诗','song-poetry','','[]','兩手擎來教放下，空身立地更疑猜。',32,'全唐诗/poet.song.99000.json','["兩手擎來教放下，空身立地更疑猜。", "根塵識界無尋處，多謝春風爛漫開。"]'),
('c5714a4b-8fb8-4c80-ac10-8405bd9d52f5','頌古二十七首  其二','釋曇賁','宋','宋诗','song-poetry','','[]','剎剎塵塵見不難，頭陀何苦被他瞞。',32,'全唐诗/poet.song.99000.json','["剎剎塵塵見不難，頭陀何苦被他瞞。", "當初若論收姦細，莫把瞿曇做佛看。"]'),
('c015b126-6f2f-4cc5-8572-d89ca47c0342','頌古二十七首  其三','釋曇賁','宋','宋诗','song-poetry','','[]','六月上伏，八月中秋。',20,'全唐诗/poet.song.99000.json','["六月上伏，八月中秋。", "人平不語，水平不流。"]'),
('bb6ac451-feb2-4e94-b078-7bf00df60149','頌古二十七首  其四','釋曇賁','宋','宋诗','song-poetry','','[]','日暖風和景更奇，華華草草露全機。',32,'全唐诗/poet.song.99000.json','["日暖風和景更奇，華華草草露全機。", "荼蘼一陣香風起，引得遊蜂到處飛。"]'),
('cc6bc2ad-96e7-4a9b-8fea-1117de133665','頌古二十七首  其五','釋曇賁','宋','宋诗','song-poetry','','[]','映林映日一般紅，吹落吹開總是風。',32,'全唐诗/poet.song.99000.json','["映林映日一般紅，吹落吹開總是風。", "可惜擷芳人不見，一時分付與遊蜂。"]'),
('bea4de46-ed0f-46c9-a2e0-92f25b154a38','頌古二十七首  其六','釋曇賁','宋','宋诗','song-poetry','','[]','截斷從教來袞袞，隨流未必去滔滔。',32,'全唐诗/poet.song.99000.json','["截斷從教來袞袞，隨流未必去滔滔。", "青山長鎖欲飛勢，滄海合知來處高。"]'),
('5d9f417c-2c1a-457c-b46b-784f8f822c80','頌古二十七首  其七','釋曇賁','宋','宋诗','song-poetry','','[]','漏傳長樂未央靜，月瀉甘泉太液秋。',32,'全唐诗/poet.song.99000.json','["漏傳長樂未央靜，月瀉甘泉太液秋。", "夜半樂聲回步輦，喚回三十六宮愁。"]'),
('67068255-d312-4636-b638-9c511c0fad9c','頌古二十七首  其八','釋曇賁','宋','宋诗','song-poetry','','[]','兩指斤開權撮起，一毛頭上爲吹開。',32,'全唐诗/poet.song.99000.json','["兩指斤開權撮起，一毛頭上爲吹開。", "這回不在身邊立，休說清風徧九垓。"]'),
('689584f3-5971-4d01-b95f-2036ba30b277','頌古二十七首  其九','釋曇賁','宋','宋诗','song-poetry','','[]','未曾拈出定盤星，多少行家怨不平。',32,'全唐诗/poet.song.99000.json','["未曾拈出定盤星，多少行家怨不平。", "待得權衡地就手，方知斤兩自分明。"]'),
('c501507f-7154-4ff6-9bba-4d5371d93a77','頌古二十七首  其一○','釋曇賁','宋','宋诗','song-poetry','','[]','認得斑斑急上弦，吼風一鏃去驚天。',32,'全唐诗/poet.song.99000.json','["認得斑斑急上弦，吼風一鏃去驚天。", "近前子細來觀覷，誰把藍田石射穿。"]'),
('c71fc843-489d-4e05-91a2-6702b1859693','頌古二十七首  其一一','釋曇賁','宋','宋诗','song-poetry','','[]','風月山川共一家，誰來語下定龍蛇。',32,'全唐诗/poet.song.99000.json','["風月山川共一家，誰來語下定龍蛇。", "太白不曾登便殿，筆頭昨夜自生花。"]'),
('26094ef3-e630-4e29-8f6d-95669bf56ab9','頌古二十七首  其一二','釋曇賁','宋','宋诗','song-poetry','','[]','一足垂來親點眼，嶺頭功德已圓成。',32,'全唐诗/poet.song.99000.json','["一足垂來親點眼，嶺頭功德已圓成。", "長髭只怕精神露，卻指紅爐片雪輕。"]'),
('57350032-3176-4a98-bfc3-2b302794e392','頌古二十七首  其一三','釋曇賁','宋','宋诗','song-poetry','','[]','以何爲體呵呵笑，推倒當頭陷虎機。',32,'全唐诗/poet.song.99000.json','["以何爲體呵呵笑，推倒當頭陷虎機。", "鳥带香從花裏出，龍含雨向洞中歸。"]'),
('138fa04b-aa33-4472-947b-b3af4c21cb8d','頌古二十七首  其一四','釋曇賁','宋','宋诗','song-poetry','','[]','黄鶴樓前題一篇，無限措大失平仄。',32,'全唐诗/poet.song.99000.json','["黄鶴樓前題一篇，無限措大失平仄。", "長沙一隻眼長長，今古何曾有蹤跡。"]'),
('17d616c6-9844-43cc-80ee-0c3a51fcedbf','頌古二十七首  其一五','釋曇賁','宋','宋诗','song-poetry','','[]','指點深紅與昔同，更無夭艷在芳叢。',32,'全唐诗/poet.song.99000.json','["指點深紅與昔同，更無夭艷在芳叢。", "南泉笑裏移春去，留得殘紅醉蜜蜂。"]'),
('fb60b3fc-c3af-497b-8959-df85c7b88e35','頌古二十七首  其一六','釋曇賁','宋','宋诗','song-poetry','','[]','蒙頭不覺齁齁睡，開眼從教燄燄紅。',32,'全唐诗/poet.song.99000.json','["蒙頭不覺齁齁睡，開眼從教燄燄紅。", "若謂平常便無事，須防豆爆冷灰中。"]'),
('333ef69a-5d02-4930-8521-cd0130ec902a','頌古二十七首  其一七','釋曇賁','宋','宋诗','song-poetry','','[]','信手揮來一一親，祇林劍下絕煙塵。',32,'全唐诗/poet.song.99000.json','["信手揮來一一親，祇林劍下絕煙塵。", "行徧天台幷雁蕩，歸來重看錦江春。"]'),
('890a8e64-97f0-4fa8-986c-a8f25749c792','頌古二十七首  其一八','釋曇賁','宋','宋诗','song-poetry','','[]','血盆似口劍如牙，竭世樞機未足誇。',32,'全唐诗/poet.song.99000.json','["血盆似口劍如牙，竭世樞機未足誇。", "親到龍潭龍不現，者回失卻眼中花。"]'),
('a4c115e1-4400-4519-9ff0-f0ce55b5c21a','頌古二十七首  其一九','釋曇賁','宋','宋诗','song-poetry','','[]','冰稜鎖斷長河口，不見人從鳥道來。',32,'全唐诗/poet.song.99000.json','["冰稜鎖斷長河口，不見人從鳥道來。", "一陣風回脩竹裏，玉闌干上雪成堆。"]'),
('ce4b502e-516b-4df1-95c0-07fa460ae43e','頌古二十七首  其二○','釋曇賁','宋','宋诗','song-poetry','','[]','七寶盃酌葡萄酒，金花紙寫清平詞。',32,'全唐诗/poet.song.99000.json','["七寶盃酌葡萄酒，金花紙寫清平詞。", "春風院靜無人見，閑把君王玉笛吹。"]'),
('b4b73e6e-64f5-4f67-bc5b-e65dd9cd6c8a','頌古二十七首  其二一','釋曇賁','宋','宋诗','song-poetry','','[]','白牯問狸奴，虛空酬萬象。',50,'全唐诗/poet.song.99000.json','["白牯問狸奴，虛空酬萬象。", "電激不停蹤，谷虛誰答響。", "啐兮啄兮，清機歷掌。", "回頭𨍏轢範秦時，舌上葛藤長萬丈。"]'),
('3e042812-7f74-4251-ad10-b5f05c5c7a31','頌古二十七首  其二二','釋曇賁','宋','宋诗','song-poetry','','[]','脫得邊城戍役身，卻來偷賞上園春。',32,'全唐诗/poet.song.99000.json','["脫得邊城戍役身，卻來偷賞上園春。", "御街前畔低聲語，不覺衝他貌事人。"]'),
('752f3500-51e1-4155-ad33-9d3c8216cf50','頌古二十七首  其二三','釋曇賁','宋','宋诗','song-poetry','','[]','水不洗水，金不博金。',40,'全唐诗/poet.song.99000.json','["水不洗水，金不博金。", "昧毛色而得馬，靡絲絃而樂琴。", "結繩畫卦有許事，喪盡真淳盤古心。"]'),
('e1704e33-be46-4af3-b7c0-4c5d3c3a1393','頌古二十七首  其二四','釋曇賁','宋','宋诗','song-poetry','','[]','牙根爛嚼真彌勒，腹裏橫吞老釋迦。',32,'全唐诗/poet.song.99000.json','["牙根爛嚼真彌勒，腹裏橫吞老釋迦。", "大地虛空皆得飽，這回不到負檀家。"]'),
('c1936a50-3a28-4ad2-9a5e-7ab4688ccc8a','頌古二十七首  其二五','釋曇賁','宋','宋诗','song-poetry','','[]','一雨一陰風未和，春從不快裏消磨。',32,'全唐诗/poet.song.99000.json','["一雨一陰風未和，春從不快裏消磨。", "桃花暗已隨流水，空使劉郎惆悵多。"]'),
('d3795798-fbf4-44e7-a509-a52c0168ee19','偈頌四首  其一','釋了朴','宋','宋诗','song-poetry','','[]','清白傳家，赤窮到骨。',48,'全唐诗/poet.song.99000.json','["清白傳家，赤窮到骨。", "心似寒灰，口如木突。", "縱有些兒葛藤，盡機也拈不出。", "憑何接待方來，聊與一摑一咄。"]'),
('a60bbf2e-4601-4916-a77f-3cd9880a1d95','偈頌四首  其二','釋了朴','宋','宋诗','song-poetry','','[]','洞山麻三斤，趙州庭前柏。',48,'全唐诗/poet.song.99000.json','["洞山麻三斤，趙州庭前柏。", "滯貨賣不行，未免著潤色。", "五彩畫牛頭，便道是極則。", "七寶絡象身，此個更奇特。"]'),
('993883d2-454a-40b7-a912-8fb3750713a2','偈頌四首  其三','釋了朴','宋','宋诗','song-poetry','','[]','桃花紅，李花白，東君怯寒辨未得。',50,'全唐诗/poet.song.99000.json','["桃花紅，李花白，東君怯寒辨未得。", "且令蝴蝶舞三臺，啄木和成十八拍。", "呵呵呵，可憐陌上遊人，開眼堂堂著賊。"]'),
('8c0f76eb-9da3-4c7e-8177-a64dd561af3f','偈頌四首  其四','釋了朴','宋','宋诗','song-poetry','','[]','觀音巖玲玲瓏瓏，太白石丁丁東東。',34,'全唐诗/poet.song.99000.json','["觀音巖玲玲瓏瓏，太白石丁丁東東。", "西園菜蟥似不堪食，東谷花發卻無賴紅。"]'),
('13cfbc89-e284-4682-8a56-29f4f08a3f76','呈無示和尚','釋了朴','宋','宋诗','song-poetry','','[]','赤腳波斯入大唐，一家有事百家忙。',32,'全唐诗/poet.song.99000.json','["赤腳波斯入大唐，一家有事百家忙。", "而今四海清如鏡，率土普天歸我王。"]'),
('4963882f-544a-41a9-b327-85e908ab0e80','偈頌三首  其一','釋了朴','宋','宋诗','song-poetry','','[]','酷暑如焚不易禁，炎炎赫赫欲流金。',32,'全唐诗/poet.song.99000.json','["酷暑如焚不易禁，炎炎赫赫欲流金。", "夜明簾外無人到，靈木超然轉綠陰。"]'),
('ceb4194d-acdf-46bc-a14a-e953411090e1','偈頌三首  其二','釋了朴','宋','宋诗','song-poetry','','[]','牛皮鞔露柱，露柱啾啾叫。',80,'全唐诗/poet.song.99000.json','["牛皮鞔露柱，露柱啾啾叫。", "燈籠佯不知，虛明還自照。", "殿脊老蚩吻，聞得呵呵笑。", "三門側耳聽，就上打之遶。", "譬如十日菊，開徹阿誰要。", "呵呵呵，未必秋香一夜衰，熨斗煎茶不同銚。"]'),
('b1d0d925-4894-45fd-ad24-08e53110dcd4','偈頌三首  其三','釋了朴','宋','宋诗','song-poetry','','[]','德山入門便棒，臨濟入門便喝。',52,'全唐诗/poet.song.99000.json','["德山入門便棒，臨濟入門便喝。", "臨濟喝處，德山棒頭耳聾；德山棒時，臨濟喝下眼瞎。", "雖然一搦一擡，就中全生全殺。"]'),
('32983a79-6171-42b6-81d2-5b33ebf2f568','頌古','釋了朴','宋','宋诗','song-poetry','','[]','靈雲一笑見桃花，三十餘年始到家。',32,'全唐诗/poet.song.99000.json','["靈雲一笑見桃花，三十餘年始到家。", "從此春風春雨後，亂隨名字落天涯。"]'),
('e049641a-0d4d-4bbf-be81-1105392468fa','偈','釋宗回','宋','宋诗','song-poetry','','[]','縣吏追呼不暫停，爭如長往事分明。',32,'全唐诗/poet.song.99000.json','["縣吏追呼不暫停，爭如長往事分明。", "從前有箇無生曲，且喜今朝調已成。"]'),
('d0539154-a479-43fa-bfd8-404d4efce672','偈','釋本','宋','宋诗','song-poetry','','[]','半在河南半在北，一片虛凝似墨黑。',32,'全唐诗/poet.song.99000.json','["半在河南半在北，一片虛凝似墨黑。", "冷地思量愁殺人，叵耐雲門這老賊。"]'),
('d831d6d0-3509-4ab0-9ed7-4a586fb08927','偈頌三首  其一','釋先','宋','宋诗','song-poetry','','[]','小林三拜得吾髓，鷲嶺拈花一笑新。',32,'全唐诗/poet.song.99000.json','["小林三拜得吾髓，鷲嶺拈花一笑新。", "莫謂藏身無影跡，月明照見夜行人。"]'),
('744496e8-51bd-41ac-a5ab-f4c7aec95a04','偈頌三首  其二','釋先','宋','宋诗','song-poetry','','[]','三轉法輪於大千，其輪本來常清凈。',30,'全唐诗/poet.song.99000.json','["三轉法輪於大千，其輪本來常清凈。", "若能奉持速取證，急急如律令。"]'),
('4850f8b6-959f-4d91-a6e4-155d016ec718','偈頌三首  其三','釋先','宋','宋诗','song-poetry','','[]','十二月初一，歲事將周畢。',40,'全唐诗/poet.song.99000.json','["十二月初一，歲事將周畢。", "臘月火燒山，旱雷轟霹靂。", "瞌睡師僧驚覺來，三九依前二十九。"]'),
('c0f0a0f8-8793-40b1-b3e4-9aec99d5e772','偈頌三首','鄭滋','宋','宋诗','song-poetry','','[]','大廈將顛仆，一木安能支。',192,'全唐诗/poet.song.99000.json','["大廈將顛仆，一木安能支。", "唐室既頹齧，有才何所施。", "表聖隱王官，出處適其宜。", "藩鎮方跋扈，擁兵相雄雌。", "尾大不可掉，綱紀日凌夷。", "雖云務姑息，要求無定期。", "當此誰爲援，欲進速禍基。", "優遊向泉石，琴酒聊自恣。", "休休復莫莫，終永忘所規。", "著史以見志，迂闊從人嗤。", "風馭去不返，幽谷空遺祠。", "名與前峰高，挺挺爲表儀。", "潔與飛瀑幷，濁流應忸怩。", "方今重完節，褒封來非遲。", "發揚在守土，抗章無媿辭。", "庶幾慰精爽，光輝于盛時。"]'),
('a46aefa0-2916-4a72-8f0f-6ab8489d17d8','墨梅  其一','王鈇','宋','宋诗','song-poetry','','[]','前身姑射冰相似，今代潘妃玉不如。',32,'全唐诗/poet.song.99000.json','["前身姑射冰相似，今代潘妃玉不如。", "坐對真成在江國，淡煙微雨暗扶疏。"]'),
('9814fd74-01dd-4f68-a483-a4a7b392238e','墨梅  其二','王鈇','宋','宋诗','song-poetry','','[]','可是傷春故癯瘦，未應無意作娉婷。',32,'全唐诗/poet.song.99000.json','["可是傷春故癯瘦，未應無意作娉婷。", "不須更向嶺頭覓，只此松煤更典型。"]'),
('fa4b433d-cb0c-4c39-b39c-20fa1ef48089','蝶','王鈇','宋','宋诗','song-poetry','','[]','粉翼瓊鬚似剪裁，飛飛自遠逐香來。',32,'全唐诗/poet.song.99000.json','["粉翼瓊鬚似剪裁，飛飛自遠逐香來。", "花間得意情多恨，應笑王孫殢酒盃。"]'),
('8c389e4f-985a-487e-abbb-c0e4c1cdf0a3','句','王鈇','宋','宋诗','song-poetry','','[]','誰言淹泊意，無酒爲澆胸。',12,'全唐诗/poet.song.99000.json','["誰言淹泊意，無酒爲澆胸。"]'),
('475231e2-b46c-4b21-8b16-5cf56c3a5e25','臨終口占','蔡振','宋','宋诗','song-poetry','','[]','生也非贅，死兮何缺。',22,'全唐诗/poet.song.99000.json','["生也非贅，死兮何缺。", "與時俱行，別是一般風月。"]'),
('79d11680-7a76-468c-9d9d-6a141f0f0f4f','題玉巖  其一','李傳','宋','宋诗','song-poetry','','[]','雨餘山色一番新，物態民情若遇春。',64,'全唐诗/poet.song.99000.json','["雨餘山色一番新，物態民情若遇春。", "正好憑高飄逸興，便教避世出紅塵。", "再登雲外通天路，就見巖中慕道人。", "俯仰熙和都得意，心歡手舞喜逢辰。"]'),
('ef3844ab-3f1c-449d-ab5e-f0479ff29451','題玉巖  其二','李傳','宋','宋诗','song-poetry','','[]','良時漸近一歸新，人物熙熙樂此春。',64,'全唐诗/poet.song.99000.json','["良時漸近一歸新，人物熙熙樂此春。", "石磴屈盤登絕頂，巖高虛寂斷纖塵。", "登臨疑是壺中景，談笑真同物外人。", "可是英靈招隱逸，芳名千載起茲辰。"]'),
('6ea9f9eb-8340-4d91-a7c1-eef4b869a9c0','和張洵蒙亭詩韻','尚用之','宋','宋诗','song-poetry','','[]','江亭勝既冠三湘，仁智所樂皆其旁。',144,'全唐诗/poet.song.99000.json','["江亭勝既冠三湘，仁智所樂皆其旁。", "翠岫俯映青羅光，上月喬木摩穹蒼。", "亭下川遐覆銀塘，水面風來笑語香。", "騷人相值喜飛觚，雄辯清談五月涼。", "飲餘相與坐方牀，論文日暮興何辰。", "佳篇疾讀韻瑯瑯，直疑星斗煥光芒。", "格高調古說奇方，況復筆法追二王。", "事業無窮嘆茫茫，丹鉛點勘策非郎。", "與公致道心可忘，浩歌直造無何鄉。"]'),
('cd0891b4-e362-4554-bfbf-029566a40068','依楊益老韻賦曾公巖','尚用之','宋','宋诗','song-poetry','','[]','當暑都忘畏赫曦，遊觀邂逅得心期。',64,'全唐诗/poet.song.99000.json','["當暑都忘畏赫曦，遊觀邂逅得心期。", "咸其自爾從天造，賁以人爲特地奇。", "風露乍涼秋至後，林巒散影月明時。", "朱轓好事留佳客，大醉高巖許鎮隨。"]'),
('4bbb340c-2a86-46fe-9b8b-3d1b226fbded','留題雉山','尚用之','宋','宋诗','song-poetry','','[]','座下聞經本至誠，改頭易面悟前身。',32,'全唐诗/poet.song.99000.json','["座下聞經本至誠，改頭易面悟前身。", "信知大道無難事，一念真如雉化人。"]'),
('3eee5254-d076-48b0-8860-0c7e4a47b783','游澹山巖  其一','尚用之','宋','宋诗','song-poetry','','[]','我來訓狐無所聞，老人戲我不動塵。',64,'全唐诗/poet.song.99000.json','["我來訓狐無所聞，老人戲我不動塵。", "道愧未嘗分寸得，心灰要似尋常人。", "斷崖危絆藤蔓古，殘僧靜對桃李春。", "次山不遇過山谷，倬□妙句垂堅珉。"]'),
('a28a3da8-b598-4373-bd05-df369a8e060d','游澹山巖  其二','尚用之','宋','宋诗','song-poetry','','[]','巖深樹綠春長在，巖暝雨霽雲初歸。',64,'全唐诗/poet.song.99000.json','["巖深樹綠春長在，巖暝雨霽雲初歸。", "天愛護持有神物，蛇去因果無狐疑。", "石田藥臼誰與刻，香山乳竇苔生衣。", "未問城南閬州比，此景自是寰中稀。"]'),
('595ddb72-558f-45ec-912f-9db8aa8b0589','賞梅佳什既不得陪從又莫獲少留深以爲恨輒賡嚴韻酬敘','孫逸','宋','宋诗','song-poetry','','[]','郡務裝懷日晷催，東園未睹一枝梅。',64,'全唐诗/poet.song.99000.json','["郡務裝懷日晷催，東園未睹一枝梅。", "從容後賞輸先見，汩沒塵勞恨阻陪。", "待雪最宜寒艷坼，迎春會有暗香來。", "悵然歸棹匆匆去，徒使臨風憶共杯。"]'),
('673a383b-2f2b-44b8-9af3-6cc683eb32ee','張叔夜挽詩二首  其一','李儔','宋','宋诗','song-poetry','','[]','聲名凜凜動寰區，忠義存心老不渝。',64,'全唐诗/poet.song.99000.json','["聲名凜凜動寰區，忠義存心老不渝。", "奮不顧生惟盡節，虞無遺策悉嘉謨。", "獨提南服三千旅，首冒重圍萬死塗。", "時事已更身已逝，惟將陰德付鵷雛。"]'),
('1a51991c-ab5e-49d3-9b62-4e0329b157b9','張叔夜挽詩二首  其二','李儔','宋','宋诗','song-poetry','','[]','命世文章伯，鴻樞柱石臣。',48,'全唐诗/poet.song.99000.json','["命世文章伯，鴻樞柱石臣。", "殞身因衛社，嗣德豈無人。", "丹旐西原路，輀車萬里春。", "一門蒙待遇，徒有淚沾巾。"]'),
('1373e95f-c579-4df7-8e64-f685f2a4c87d','青白堂','趙子巖','宋','宋诗','song-poetry','','[]','北庵竹玉青，南階梅雪白。',96,'全唐诗/poet.song.99000.json','["北庵竹玉青，南階梅雪白。", "吏散隱几坐，觀化聊自適。", "竹青表勁節，梅白留佳實。", "太守謝二友，粗官謾陳力。", "取名吾有寄，梅竹蓋假借。", "青白遺子孫，先訓存金石。", "斯民彫瘵餘，政教當尚德。", "雖微甘棠化，韋弦託三益。"]'),
('8b614d9d-80e0-4415-9a6e-32dfed6fc315','題異花','荆州掾','宋','宋诗','song-poetry','','[]','山花紅與綠，日暮顔色足。',24,'全唐诗/poet.song.99000.json','["山花紅與綠，日暮顔色足。", "無名我不識，有毒君莫觸。"]'),
('862cf279-8157-4841-8424-c791dc2df038','中秋月和桃源夫人','陳純','宋','宋诗','song-poetry','','[]','仙源嘗誤到，羈思正蕭然。',48,'全唐诗/poet.song.99000.json','["仙源嘗誤到，羈思正蕭然。", "秋靜夜方靜，月圓人更圓。", "清尊歌越調，仙棹泛晴川。", "幽意知多少，重重類楚綿。"]'),
('64cb6356-310f-4835-a08e-03dab149377d','句','陳純','宋','宋诗','song-poetry','','[]','莫辭終夕看，動是隔年期。',12,'全唐诗/poet.song.99000.json','["莫辭終夕看，動是隔年期。"]'),
('304ac2bf-f093-4a8a-9b36-5c20c1b6f9e4','詩一首','邊公式','宋','宋诗','song-poetry','','[]','松蘿深處有神天，小剎何妨納大千。',64,'全唐诗/poet.song.99000.json','["松蘿深處有神天，小剎何妨納大千。", "掛塔定知宣久住，歌吟何幸得流傳。", "袖中出簡聊應爾，門上題詩豈偶然。", "顧我未除煩惱習，與師同結未來緣。"]'),
('41010ba5-9925-491c-8961-0dd17e7e7824','游大滌','丁先民','宋','宋诗','song-poetry','','[]','我欲避塵囂，乘風入洞霄。',48,'全唐诗/poet.song.99000.json','["我欲避塵囂，乘風入洞霄。", "循溪山作路，駕水石爲橋。", "臺殿黄金鎖，神仙碧玉簫。", "拂衣天柱頂，清思欲飄飄。"]'),
('eb52754a-5eaf-4b01-ae65-c9805e04d6cc','游洞霄宮','丁先民','宋','宋诗','song-poetry','','[]','午過青山渡，揚鞭入洞霄。',48,'全唐诗/poet.song.99000.json','["午過青山渡，揚鞭入洞霄。", "旁觀昔隱跡，信步冷泉橋。", "說簡金龍古，仙風道古饒。", "小軒曾寄宿，秋雨鬧芭蕉。"]'),
('0b13be5c-cc3f-428b-a192-211c1a4a2170','詠蟬','陸蒙老','宋','宋诗','song-poetry','','[]','綠蔭深處汝行藏，風露從來是稻粱。',32,'全唐诗/poet.song.99000.json','["綠蔭深處汝行藏，風露從來是稻粱。", "莫倚高枝縱繁響，也宜回首顧螳螂。"]'),
('f9257cf4-96b5-4046-8569-c0bf736f8f96','嘉禾八詠 披雲閣','陸蒙老','宋','宋诗','song-poetry','','[]','城角巍欄見海涯，春風簾幕暖飄花。',32,'全唐诗/poet.song.99000.json','["城角巍欄見海涯，春風簾幕暖飄花。", "雲煙斷處滄波闊，一簇樓臺十萬家。"]'),
('00663540-0922-4024-a2b3-2d25c932b174','嘉禾八詠 月波樓','陸蒙老','宋','宋诗','song-poetry','','[]','月疑宮闕下銀潢，碧轉欄干萬頃光。',32,'全唐诗/poet.song.99000.json','["月疑宮闕下銀潢，碧轉欄干萬頃光。", "我是水晶宮裏客，倚樓猶自羨滄浪。"]'),
('89fb1c16-022c-4292-abfa-ef1f8b7951ba','嘉禾八詠 金魚池','陸蒙老','宋','宋诗','song-poetry','','[]','池上春風動白蘋，池邊清淺見金鱗。',32,'全唐诗/poet.song.99000.json','["池上春風動白蘋，池邊清淺見金鱗。", "新波已縱遊魚樂，調笑江頭結網人。"]'),
('ff72e773-8c21-4454-9f68-7ab6a21b17e4','嘉禾八詠 宣公橋','陸蒙老','宋','宋诗','song-poetry','','[]','當時倉卒倚鴻籌，清白堪封萬戶侯。',32,'全唐诗/poet.song.99000.json','["當時倉卒倚鴻籌，清白堪封萬戶侯。", "陵谷已非家世遠，畫橋依舊水東流。"]'),
('83b90aa5-d6e1-4ebb-95ff-7e07f8448383','嘉禾八詠 五柳橋','陸蒙老','宋','宋诗','song-poetry','','[]','五柳先生倦折腰，孤眠千載仰風標。',32,'全唐诗/poet.song.99000.json','["五柳先生倦折腰，孤眠千載仰風標。", "青衫令尹頭如雪，不厭朝昏過此橋。"]'),
('aced49ab-541d-494e-b0ab-5de051ebe302','嘉禾八詠 會景亭','陸蒙老','宋','宋诗','song-poetry','','[]','清入欄干酒易醒，春風楊柳幾沙汀。',32,'全唐诗/poet.song.99000.json','["清入欄干酒易醒，春風楊柳幾沙汀。", "平沙抵得瀟湘闊，祇欠螺峰數點青。"]'),
('faecf613-a6ad-4e23-8d81-422eea642496','嘉禾八詠 蘇小小墓','陸蒙老','宋','宋诗','song-poetry','','[]','瑤臺歸去鶴空還，一曲霓裳落世間。',32,'全唐诗/poet.song.99000.json','["瑤臺歸去鶴空還，一曲霓裳落世間。", "秋雨幾番黄葉落，朝雲應欠到香山。"]'),
('7d5ebb42-b518-45f0-8600-3f01d8c8e6f1','嘉禾八詠 羞墓','陸蒙老','宋','宋诗','song-poetry','','[]','玉顔羞見錦衣侯，草木煙封雨鎖愁。',32,'全唐诗/poet.song.99000.json','["玉顔羞見錦衣侯，草木煙封雨鎖愁。", "不似田文門下客，一貧一富不知羞。"]'),
('b233d1ca-a514-4a78-bec5-465ae33bb884','赴官晉陵別端禪師','陸蒙老','宋','宋诗','song-poetry','','[]','枕上浮生過半百，短髪毿毿霜樣白。',144,'全唐诗/poet.song.99000.json','["枕上浮生過半百，短髪毿毿霜樣白。", "西溪溪上舊家山，歲歲故鄉歸似客。", "船頭漸近古松門，云是吳均讀書宅。", "煙雲半嶺見層樓，崢嶸鼇頂蓬宮窄。", "有人掛衲歸盤陀，稜稜瘦骨真維摩。", "幾年面壁舌不動，忽然拍手演漁歌。", "秋來滿船載明月，直鈎不釣閑黿鼉。", "一雨笠，一煙簑，五湖深處任風波。", "黄梅渡口水流急，救護心誰如老婆。"]'),
('35f3ba74-91ea-4663-8886-ea01dc7e1036','贄鄉先生吳邦範','陳顯良','宋','宋诗','song-poetry','','[]','蓬萊有喬松，特立風雨外。',84,'全唐诗/poet.song.99000.json','["蓬萊有喬松，特立風雨外。", "元氣毓靈柯，甘露日滋溉。", "昭映暘谷霞，文章成五采。", "矯矯梁棟資，明堂不久待。", "遠隔東瀛波，求之不可邁。", "清飈六合生，貞操千年在。", "終當巢鸞鳳，出與聖時會。"]'),
('a59683f9-4fda-4bfc-974e-7b9cd393ddaa','送張師言知台州二首  其一','李長民','宋','宋诗','song-poetry','','[]','岧嶢台嶽鎮東陬，地近行都委寄優。',64,'全唐诗/poet.song.99000.json','["岧嶢台嶽鎮東陬，地近行都委寄優。", "就付金庭老宮使，曾持虎節古揚州。", "行春想見勤宣布，訪古無因預唱酬。", "我誦甘棠增感慨，願公封殖表前修。"]'),
('82de3194-cde7-468b-a951-9b6093753d11','送張師言知台州二首  其二','李長民','宋','宋诗','song-poetry','','[]','皖嶺潛溪已厭觀，此行更賞浙東山。',64,'全唐诗/poet.song.99000.json','["皖嶺潛溪已厭觀，此行更賞浙東山。", "雲開天姥極清曠，霧暗石橋窮險難。", "年德俱高真召杜，風情未減眷樊蠻。", "側聞侍從多虛位，寧許耆英便賜閑。"]'),
('723afcfa-3bc5-484a-87a3-b67ce1275003','廉堂','李長民','宋','宋诗','song-poetry','','[]','政拙慚無善最聞，但欣青嶂對誰門。',32,'全唐诗/poet.song.99000.json','["政拙慚無善最聞，但欣青嶂對誰門。", "公餘靜室聊觀易，客到廉堂謾潔罇。"]'),
('2f691f21-9510-41a0-afd5-ac22f37a8891','城南蔣莊四首  其一','李長民','宋','宋诗','song-poetry','','[]','愁臥愁亭上，蘭時忽過中。',48,'全唐诗/poet.song.99000.json','["愁臥愁亭上，蘭時忽過中。", "幽人倦賞物，青帝謾施功。", "柳眼依依碧，桃梢冉冉紅。", "真須家醸酒，一醉百花叢。"]'),
('8fb9fa39-5a3b-49f5-b8c9-519fc9d7fafc','城南蔣莊四首  其二','李長民','宋','宋诗','song-poetry','','[]','郊居人事絕，倦暑每晨興。',48,'全唐诗/poet.song.99000.json','["郊居人事絕，倦暑每晨興。", "蓮□池中佛，筍供林下僧。", "吟餘厭蟬噪，望遠喜禾登。", "朝市忘懷久，何勞羨賜冰。"]'),
('740c7fcf-fbf7-478d-b3de-052ba2703476','城南蔣莊四首  其三','李長民','宋','宋诗','song-poetry','','[]','今旦商飈起，蕭然雲氣秋。',48,'全唐诗/poet.song.99000.json','["今旦商飈起，蕭然雲氣秋。", "稚蛩工促織，老蔓擬牽牛。", "莫賦潘安閣，聊登王粲樓。", "家園歸未得，孤夢遶松楸。"]'),
('ff95b9a5-ffcf-4122-9af9-ce578faf89fb','城南蔣莊四首  其四','李長民','宋','宋诗','song-poetry','','[]','寒來惟喜睡，忽忽又朝暾。',48,'全唐诗/poet.song.99000.json','["寒來惟喜睡，忽忽又朝暾。", "地迥霜逾白，庭空鵲自喧。", "甑頭煙半吐，盞面酒微溫。", "莫問烏銀價，晴簷好負暄。"]'),
('c4dbf2d7-b01c-42a0-bdf4-edcfa9413b72','鹿苑寺一擊軒二首  其一','李長民','宋','宋诗','song-poetry','','[]','我聽風篁是梵音，如何俗耳等閑聞。',32,'全唐诗/poet.song.99000.json','["我聽風篁是梵音，如何俗耳等閑聞。", "自來擊處無人會，千古知心只此君。"]'),
('f0edad27-c41f-4d92-9c7e-d54203896346','鹿苑寺一擊軒二首  其二','李長民','宋','宋诗','song-poetry','','[]','密密堂堂悟有時，躁求那便契精微。',32,'全唐诗/poet.song.99000.json','["密密堂堂悟有時，躁求那便契精微。", "憑誰舉似圓居士，好助香巖證上機。"]'),
('956dd84f-bffc-40f5-97bc-cc20601117ca','海鹽道中','李長民','宋','宋诗','song-poetry','','[]','一舸凌風去，縈紆度幾村。',48,'全唐诗/poet.song.99000.json','["一舸凌風去，縈紆度幾村。", "水清魚視子，地美稻生孫。", "山近塵埃遠，秋晴枕席溫。", "悠悠向何所，欸乃武陵源。"]'),
('6c506b34-56a4-4ed8-ac97-6f0cddf5aa08','句','李長民','宋','宋诗','song-poetry','','[]','地迥七杉成斗野，雨餘雙練瀉晴川。',16,'全唐诗/poet.song.99000.json','["地迥七杉成斗野，雨餘雙練瀉晴川。"]'),
('9083a311-0363-4e50-a239-63dd2e778555','圓壇午龕行事','王俊乂','宋','宋诗','song-poetry','','[]','平日郊邱事口談，今朝相祀列星參。',64,'全唐诗/poet.song.99000.json','["平日郊邱事口談，今朝相祀列星參。", "大裘袞袞冕升南陛，小次龍牀近午龕。", "韋杜去真尺五，嵩神祀聖似呼三。", "清都佩玉人歸後，尚聽笙鏞萬谷酣。"]'),
('684f9fc5-9ec5-4ad3-8f4d-f586a9f5c57d','大陽成湯殿內芝草詩','劉泳','宋','宋诗','song-poetry','','[]','新構湯祠映碧成，梁間瑞草表虔誠。',64,'全唐诗/poet.song.99000.json','["新構湯祠映碧成，梁間瑞草表虔誠。", "也同□□寒光潤，氣稟元精素質清。", "神爵五莖難比□，建□三本未爲榮。", "烝民共喜嘉祥異，和氣時臻□□平。"]'),
('b3f4f117-d796-4665-9afc-23baf2bcb8b8','譏王黼','宣和民謠','宋','宋诗','song-poetry','','[]','三百貫，且通判。',16,'全唐诗/poet.song.99000.json','["三百貫，且通判。", "五百索，直秘閣。"]'),
('93cc0061-ba92-44c9-af7a-a4e8754ce646','頌','釋法昇','宋','宋诗','song-poetry','','[]','我誦光明經，自得三昧力。',47,'全唐诗/poet.song.99000.json','["我誦光明經，自得三昧力。", "舉起便周圓，何用高聲覓。", "一日三百部，日輪猶昃。", "見者總生疑，我自心堅實。"]'),
('c55ed358-e7e9-40f1-9341-b8d5778fe5bb','句','祝廉夫','宋','宋诗','song-poetry','','[]','會當歸去來。',6,'全唐诗/poet.song.99000.json','["會當歸去來。"]'),
('4b9c619f-ff4a-4220-8287-d7df8c118f92','用廉夫韻招諸友登清微亭','傅察','宋','宋诗','song-poetry','','[]','束带縛吏事，發狂中憤興。',144,'全唐诗/poet.song.99000.json','["束带縛吏事，發狂中憤興。", "世情多面朋，噂沓惡背憎。", "緬懷数君子，皎皎瑩壺冰。", "披雲見顔色，洗翠露鋒稜。", "忘形到坦率，髙論破炎蒸。", "藹然嘉譽在，顧我獨無稱。", "文場屡交鏑，師老畏侵凌。", "况復時雨過，綠苗覆千塍。", "便當共臨眺，此興那可勝。", "孤亭枕席佳，下有寒潭澄。", "仰看霞綺散，坐待月華升。", "嘲詠縱歡謔，明朝期再登。"]'),
('653f14ac-986f-4a7e-a73d-7b5766a77008','廉夫有會當歸去来之句復次前韻','傅察','宋','宋诗','song-poetry','','[]','少小尚奇偉，長年病莫興。',144,'全唐诗/poet.song.99000.json','["少小尚奇偉，長年病莫興。", "折腰仕五斗，詎敢論好憎。", "居然畏罪罟，局如履春冰。", "每懷鷹隼翮，韝上看鋒稜。", "追随縉紳後，糠籺雜肴烝。", "泮宫天下士，藉甚得儒稱。", "巍巍衆峰上，跛足豈易凌。", "朝廷重薦延，拔茅餘空塍。", "公孫富經術，非子誰能勝。", "坐見萬頃波，甖缶汲逾澄。", "沛然下膏澤，蓊若朝雲升。", "勿云歎留滯，青史他年登。"]'),
('5115de07-b6c3-480d-a4b8-2f993a740919','次韻廉夫登清微亭二首  其一','傅察','宋','宋诗','song-poetry','','[]','蝸舍不容膝，煩歊局寢興。',144,'全唐诗/poet.song.99000.json','["蝸舍不容膝，煩歊局寢興。", "豈惟倦束带，絺綌猶云憎。", "清微跨城角，窣兀疑凝冰。", "深池暮黯黯，遠岫朝稜稜。", "往歲與申子，賓朋日雲蒸。", "遂令棟宇陋，顧盻流名稱。", "先生今詩伯，氣欲青雲凌。", "鏘然出佳句，椒蘭布畦塍。", "邀我避暑遊，意重愧難勝。", "何當酌沆瀣，神明自清澄。", "嗟彼浮名者，此亭豈易升。", "踟蹰恐後時，攝衣請先登。"]'),
('988d1cd2-c4d1-4ca1-be62-16f8cbbdd199','次韻廉夫登清微亭二首  其二','傅察','宋','宋诗','song-poetry','','[]','大火氣方熾，新金伏未興。',144,'全唐诗/poet.song.99000.json','["大火氣方熾，新金伏未興。", "茅屋苦卑陋，藴毒空自憎。", "流汗常被體，滌煩屢飲冰。", "那堪青蠅輩，鼓趐作威稜。", "薰風爍炎日，沸鼎助薪蒸。", "每思謀爽塏，地隘舊無稱。", "高亭枕城隈，粉堞勢騰凌。", "清水繞其足，茂林瞰田塍。", "此間有異趣，躋攀弗能勝。", "佳招適我願，坐覺神魂澄。", "何當卜鄰舍，與子朝夕升。", "飄然忘世累，長嘯效孫登。"]'),
('3d4a4d07-afaf-43a2-9df7-9928b3725ff6','次韻祝廉夫登南樓','傅察','宋','宋诗','song-poetry','','[]','膏雨潤四野，草木蘇中乾。',168,'全唐诗/poet.song.99000.json','["膏雨潤四野，草木蘇中乾。", "駕言共臨眺，凌雲陟層盤。", "華宇蔭曦日，溽暑随風闌。", "清談無俗好，茶果有餘歡。", "撥置簿領煩，憇此簟席安。", "悠然得佳趣，可以寄簪冠。", "耳目去局促，心體自廣胖。", "何如斂手版，觸熱事上官。", "晚来纖靄霽，矯首欣遐觀。", "一鳥沒天外，千林杳雲端。", "西山有爽氣，淺綠浮巑岏。", "翻疑圖畫裏，未覺雲夢寬。", "蕭蕭林間蟬，已如咽暮寒。", "直恐霜露至，歸歟可忘餐。"]'),
('778e1d72-4b6b-43e9-85dc-191320e63373','同七兄寄二李','傅察','宋','宋诗','song-poetry','','[]','昔我在淇水，二陸皆少年。',216,'全唐诗/poet.song.99000.json','["昔我在淇水，二陸皆少年。", "伯也氣軒昻，丹鶴唳青田。", "季方文章士，摛華桃李妍。", "力學乃未已，有如火始然。", "相見一傾蓋，便誦膠漆堅。", "笑語玉麈折，登臨蠟屐穿。", "時時出秀句，洒若沈疴痊。", "爾来踰十歲，自當冠貂蟬。", "胡爲茅屋下，寂寞尚草玄。", "方今明堂構，收拾棟與椽。", "安得刷羽翮，吹噓送上天。", "此志儻不遂，何用空言傳。", "不如李翰林，沉醉自稱仙。", "不如陶彭澤，歸来謝塵緣。", "但解琴中趣，何妨甕傍眠。", "富貴草頭露，名譽空中烟。", "子意竟何如，余心方寂然。", "願求真實語，莫作猾頭禪。"]'),
('6d2c8739-07b7-4cfb-ab29-2cd4833e71c4','夏日登清微亭','傅察','宋','宋诗','song-poetry','','[]','永日留煩暑，斯樓得屢登。',72,'全唐诗/poet.song.99000.json','["永日留煩暑，斯樓得屢登。", "向来知異境，高處若無憑。", "遠岫生雲直，輕風蹙浪層。", "試承金掌露，更接玉壺冰。", "抵掌賓朋盛，題詩氣象增。", "望窮遺憾在，我欲醉時升。"]'),
('dbd21729-e71a-4a9e-a036-0da63b9fa248','清微亭分韻得空字','傅察','宋','宋诗','song-poetry','','[]','縹緲千層外，縈紆一徑通。',96,'全唐诗/poet.song.99000.json','["縹緲千層外，縈紆一徑通。", "飛甍明落日，巨棟掛斜虹。", "賞眺資公退，招邀得調同。", "九天開浩蕩，萬象入牢籠。", "水色連晴碧，雲容借晚空。", "清乘庾公興，快挹楚王風。", "弁側金罍倒，樓昏畫角終。", "明朝車馬客，陡覺厭塵紅。"]'),
('8dc22189-f1d4-42e2-8097-adbd6bad1211','大暑同蔣明亞叟熙載夜登清微亭','傅察','宋','宋诗','song-poetry','','[]','土潤伏新金，陽歊困亭午。',240,'全唐诗/poet.song.99000.json','["土潤伏新金，陽歊困亭午。", "曦御駐征驂，朱光徹厚土。", "鳥雀噪階除，蛙蚓鳴草莽。", "簿領抗塵容，茅簷庇環堵。", "蜂蠆亂繩床，蚊蟁隱雷鼓。", "椶拂徒爾爲，青蠅敢予侮。", "避喧空百慮，對食但三吐。", "舉箑未搖風，揮汗已成雨。", "那能整冠巾，誰復對賓主。", "豈惟眩生花，坐覺氣如縷。", "南方有高樓，兀然蔽華宇。", "摳衣倦躋攀，策杖愁傴僂。", "俄頃叩雲端，飄蕭開洞府。", "新凉颯爾来，舊暑脱然愈。", "清池涌波瀾，疏星穿牖戶。", "夜氣襲冰霜，月明粲珪組。", "烏鵲倦還飛，遊魚清可数。", "珍菓走金盤，清談揮玉麈。", "群籟正囂囂，幽夢方栩栩。", "何當食瓊漿，一夕生毛羽。"]'),
('444f5eb5-bc28-4d59-8486-119855de0acd','夜登清微亭雲陰掩翳東北有雨少頃月出皎然復次前韻','傅察','宋','宋诗','song-poetry','','[]','融融暑未闌，悄悄夜方午。',240,'全唐诗/poet.song.99000.json','["融融暑未闌，悄悄夜方午。", "命駕聊叩門，尋幽得兹土。", "俯瞩但蒼茫，前瞻何鹵莽。", "萬籟正虛無，群生各安堵。", "蟬嘯作笙簫，蛙鳴當鍾鼓。", "鳬舄正参差，詼諧懼狎侮。", "豈惟冠蓋傾，已覺肝膽吐。", "坐久隱奔雷，天邉垂密雨。", "疏木列賓朋，衆峰自臣主。", "螢火落明星，爐烟裊青縷。", "那能勝酒杯，所欣瞻德宇。", "高歌屡激昻，失喜或俛偻。", "蕭颯濯塵襟，清虛湛靈府。", "快如仙爪爬，洒若頭風愈。", "須臾出金盤，照曜開玉戶。", "映浪雜瓊瑰，穿簾間璧組。", "斯遊豈前謀，後會難逆数。", "歡餘岸綸巾，語約揮松麈。", "可能伴雞棲，亦復随蝶栩。", "廣寒會可升，試爲刷翎羽。"]'),
('4496f0cb-3862-4743-9745-9ff2ed71f68f','次晁之道韻','傅察','宋','宋诗','song-poetry','','[]','翰林詩百篇，發興自斗酒。',120,'全唐诗/poet.song.99000.json','["翰林詩百篇，發興自斗酒。", "同遊八仙中，七者顔已厚。", "邇来数百年，斯人那復有。", "風流城東晁，四海蔚稱首。", "之子乃其豪，異代得密友。", "滿腹貯詩書，妙意寓醪酎。", "政使譽日新，位卑未爲醜。", "亭亭澗底松，不如園中柳。", "芝菌冠衆芳，其出木枯朽。", "叫閽問大鈞，得致君側否。"]'),
('c01bae85-d7f5-4dd1-b592-e3e802c1aca8','送承祖赴定州幕府','傅察','宋','宋诗','song-poetry','','[]','中山控北陲，強弩號百萬。',192,'全唐诗/poet.song.99000.json','["中山控北陲，強弩號百萬。", "單于銜國恩，方且事逃遁。", "謀帥得真儒，不煩一戟頓。", "風流本江左，亹亹有餘論。", "幕府極妙選，参謀不容遜。", "藉甚丞相孫，凌雲氣豪健。", "所懷社稷計，嘗願竊有獻。", "蹭蹬三十年，羈旅頗自困。", "因人作遠遊，實亦乖素願。", "談笑青油幕，聊復可排悶。", "嗟余謬從學，塵根苦遲鈍。", "一官聯事久，矜式每自勸。", "但覺有不如，未見有進寸。", "公亦不吾厭，叩撃愧煩溷。", "念當爲遠别，悵然亦多恨。", "時方苦炎蒸，行矣期強飯。"]'),
('45ca7b01-ab2f-4376-8a0c-2317f75c59e9','伯時往河東戲與廉夫分韻道相思之意三首  其一','傅察','宋','宋诗','song-poetry','','[]','日月劇跳丸，暫别亦已久。',72,'全唐诗/poet.song.99000.json','["日月劇跳丸，暫别亦已久。", "青山繚層巔，道里阻且右。", "今晨登南樓，會此同志友。", "思公聊北望，竚立但搔首。", "秋風八月天，霽色明朝牖。", "軒車何時來，遲爾一杯酒。"]'),
('82c379b5-00d0-4227-844e-33fd46badaa0','伯時往河東戲與廉夫分韻道相思之意三首  其二','傅察','宋','宋诗','song-poetry','','[]','朝氛霽西山，晚日明髣髴。',72,'全唐诗/poet.song.99000.json','["朝氛霽西山，晚日明髣髴。", "搖憐太行上，陟巘眩可畏。", "王侯眇小夫，中盤凌雲氣。", "端如車公賢，談笑出真味。", "胡爲久崎嶇，使我重歔欷。", "王事有程期，来歸懼其未。"]'),
('e0220489-c8b0-456a-b48a-963d37c51c10','伯時往河東戲與廉夫分韻道相思之意三首  其三','傅察','宋','宋诗','song-poetry','','[]','之子何磊落，本是青雲才。',72,'全唐诗/poet.song.99000.json','["之子何磊落，本是青雲才。", "委翅蓬蒿下，黧面垂䯱䰄。", "卜鄰與我遊，肝膽向人開。", "酒酣遺世累，謔浪絕嫌猜。", "西風換煩燠，四野無纖埃。", "方當共臨眺，公兮胡不来。"]'),
('0aee6e59-e6c0-4d50-960d-ca8112ac0ca2','題毛彦謨容膝軒','傅察','宋','宋诗','song-poetry','','[]','夫子負異才，端若會稽笴。',144,'全唐诗/poet.song.99000.json','["夫子負異才，端若會稽笴。", "平生懷剛腸，於世少許可。", "文詞類激昻，議論耻媕婀。", "高名三十年，坐此常坎坷。", "同時英俊流，往往步青瑣。", "歸来樂簞瓢，琳宫得安坐。", "小軒僅容膝，陋巷生堀堁。", "唯餘豪俠氣，屢折每不挫。", "卻眡利名場，終身繫韁鎖。", "生雖華屋居，死或翳蓬顆。", "固知宇宙間，所有終非我。", "但當清吾心，餘事等么麽。"]'),
('3d35ff21-395b-4c4e-87eb-392e6065d65b','次七兄韻','傅察','宋','宋诗','song-poetry','','[]','蝸舍席爲門，清風無所扇。',204,'全唐诗/poet.song.99000.json','["蝸舍席爲門，清風無所扇。", "閑視纔半尋，起行空百轉。", "對食不下喉，流汗常被面。", "矧復鳬鶩行，摘尾抱大卷。", "余方有公事，汝輩宜罷遣。", "賴此伯仲賢，縱談逞雄辨。", "時時雜博奕，豈不賢遊燕。", "呼奴取其来，據榻聊一戰。", "初如兩軍交，整陣咸伺便。", "俄頃鋒刃集，解紛在一箭。", "或喜而撫掌，或駭而色變。", "或傍睨而審，或當局而眩。", "剝剝伐木聲，離離衆星現。", "勝負既已分，反奩若收電。", "卻尋文字觀，觸物本無戀。", "覓句屢吟哦，誦詩乍遊衍。", "百謫勿相聞，從渠書我殿。"]'),
('edbd7bcf-dc49-426c-b5cb-9dab844a685a','晚登清微亭次祝教授韻','傅察','宋','宋诗','song-poetry','','[]','雉堞亭亭倚翠微，髙樓裊裊弄清暉。',96,'全唐诗/poet.song.99000.json','["雉堞亭亭倚翠微，髙樓裊裊弄清暉。", "共邀嘉客扶笻杖，驟喜凉風振羽衣。", "過雨山川顔色好，投林鳥雀噪聲稀。", "月搖翠浪明珠碎，雲滿金波破鏡飛。", "雄辨琅琅如落屑，新詩句句似連璣。", "自憐性僻躭幽寂，卻恨匆匆便賦歸。"]'),
('7402a96d-a218-4382-8957-cf84a0594768','送朱熙載改官還鄉','傅察','宋','宋诗','song-poetry','','[]','陶唐名臣有朱虎，揖遜夔夷尊文祖。',160,'全唐诗/poet.song.99000.json','["陶唐名臣有朱虎，揖遜夔夷尊文祖。", "後来傑出漢雲孫，折檻當時誰敢侮。", "煌煌聖代見斯人，凛凛遺風振千古。", "乘牛不数魯家俠，衣錦何妨買臣窭。", "十年牢落困膠庠，五斗栖遲尚環堵。", "唯余豪氣自不除，傾蓋向人肝膽吐。", "忽然結束事征鞍，軒軒氣色浮眉宇。", "謂余倚門親久待，况復楓宸拜明主。", "朝廷公卿重薦延，騫騰一鶚生毛羽。", "高義如君世所稀，早據要路思禆補。"]'),
('15f18cef-1e90-4516-a550-e52d72c18465','芝堂','傅察','宋','宋诗','song-poetry','','[]','弘度負土忘晨夕，空腸未忍進一溢。',224,'全唐诗/poet.song.99000.json','["弘度負土忘晨夕，空腸未忍進一溢。", "伯會隆冬不衣帛，野火燎原天雨澤。", "當時廬側産靈芝，盛事至今光史册。", "王家兄弟皆英豪，藉藉聲華若連璧。", "高文奥學乃餘事，一門躬行如萬石。", "孝思他日徹蒼旻，血淚垂頥灑枯柏。", "誰云草木但有生，始信幽明本無隔。", "煌煌三秀發坤祥，小大高低紫與白。", "搢紳駭嘆絕前聞，老稚提攜溢阡陌。", "爭言圖寫獻修門，坐見恩榮来絡繹。", "公獨掩耳更悲啼，吾忍貨名於窀穸。", "豈如採摘付兒童，大勝籯金滿千鎰。", "方今孝治軼唐虞，八行求賢常側席。", "公雖韞匵畏人知，定有新詩振奇蹟。"]'),
('2f03f250-118c-49f4-bac3-019c8cd16350','雪九首  其一','傅察','宋','宋诗','song-poetry','','[]','都城一日雪，庭戶浩已盈。',24,'全唐诗/poet.song.99000.json','["都城一日雪，庭戶浩已盈。", "呼兒試輕掃，留伴小窗明。"]'),
('97a1085d-d73a-4af9-8dc4-075252aae149','雪九首  其二','傅察','宋','宋诗','song-poetry','','[]','天公亦戲人，奇幻驚倐忽。',24,'全唐诗/poet.song.99000.json','["天公亦戲人，奇幻驚倐忽。", "朝来簷霤間，一一綴明月。"]'),
('0d4beef7-b172-4457-afe2-2b8a82c6f604','雪九首  其三','傅察','宋','宋诗','song-poetry','','[]','晚風掃連氛，客被憎夜峭。',24,'全唐诗/poet.song.99000.json','["晚風掃連氛，客被憎夜峭。", "明朝赴看燭，更把崑山照。"]'),
('23e2401b-7949-44d6-9511-f1b97e454385','雪九首  其四','傅察','宋','宋诗','song-poetry','','[]','高堂連夜賞，蛾眉映珠櫳。',24,'全唐诗/poet.song.99000.json','["高堂連夜賞，蛾眉映珠櫳。", "誰憐閉門客，衣穿履亦空。"]'),
('40fdf4dc-2ed5-422e-a402-2ac234b18df0','雪九首  其五','傅察','宋','宋诗','song-poetry','','[]','黑雲埋日車，厚雪鎮坤軸。',24,'全唐诗/poet.song.99000.json','["黑雲埋日車，厚雪鎮坤軸。", "行路勿匆匆，包藏恐深谷。"]'),
('097d08c9-4d84-411a-aaac-35d3b122cf94','雪九首  其六','傅察','宋','宋诗','song-poetry','','[]','忽驚陋巷間，踏作瓊瑤迹。',24,'全唐诗/poet.song.99000.json','["忽驚陋巷間，踏作瓊瑤迹。", "坐聞郢中歌，妙句壓元白。"]'),
('c1682e87-4669-4ae1-a9be-f339045d9cf6','雪九首  其七','傅察','宋','宋诗','song-poetry','','[]','春雷忽隱隱，春雪復紛紛。',24,'全唐诗/poet.song.99000.json','["春雷忽隱隱，春雪復紛紛。", "農夫戒及澤，荷鍤已成雲。"]'),
('cdd78dbd-d9e0-4f90-a9b8-86be3a033726','雪九首  其八','傅察','宋','宋诗','song-poetry','','[]','撒鹽乍可擬，刻楮竟難成。',24,'全唐诗/poet.song.99000.json','["撒鹽乍可擬，刻楮竟難成。", "妍詞覻天巧，應復召鄒生。"]'),
('245951e7-ced0-4676-84a2-4ff034b4a899','雪九首  其九','傅察','宋','宋诗','song-poetry','','[]','盈尺兆嘉祥，三登賀時泰。',24,'全唐诗/poet.song.99000.json','["盈尺兆嘉祥，三登賀時泰。", "我雖無寸田，一飯猶足賴。"]'),
('c1a431e3-ca16-43a0-9a94-a29b9d21c7db','次韻杜無逸西園獨坐九絕句  其一','傅察','宋','宋诗','song-poetry','','[]','南浦送微波，西山来遠綠。',24,'全唐诗/poet.song.99000.json','["南浦送微波，西山来遠綠。", "日暮獨盤旋，慨然撫孤竹。"]'),
('100b378f-851c-4a2c-8207-4867954a605a','次韻杜無逸西園獨坐九絕句  其二','傅察','宋','宋诗','song-poetry','','[]','前輩不可見，古道邈難尋。',24,'全唐诗/poet.song.99000.json','["前輩不可見，古道邈難尋。", "何時赤松子，相與歸山陰。"]'),
('de6d4bf0-cbdd-414b-9eee-d86d781bec20','次韻杜無逸西園獨坐九絕句  其三','傅察','宋','宋诗','song-poetry','','[]','折腰爲五斗，我已愧淵明。',24,'全唐诗/poet.song.99000.json','["折腰爲五斗，我已愧淵明。", "共赴東林約，悵然懷友生。"]'),
('4f0c767b-b23e-4162-be1a-918e3dc7bf20','次韻杜無逸西園獨坐九絕句  其四','傅察','宋','宋诗','song-poetry','','[]','虛齋篆爐烟，兀然得禅寂。',24,'全唐诗/poet.song.99000.json','["虛齋篆爐烟，兀然得禅寂。", "雖有錦繡腸，畫餅安可食。"]'),
('e50b371d-e1bb-48ac-92f3-c9106a2264f4','次韻杜無逸西園獨坐九絕句  其五','傅察','宋','宋诗','song-poetry','','[]','亭亭澗底松，幹凌雪霜孤。',24,'全唐诗/poet.song.99000.json','["亭亭澗底松，幹凌雪霜孤。", "既無鸞鳳翔，鳥雀来喧呼。"]'),
('459f605f-d37f-474b-8d14-0e7fe97ad322','次韻杜無逸西園獨坐九絕句  其六','傅察','宋','宋诗','song-poetry','','[]','一世競榮利，紛若空中花。',24,'全唐诗/poet.song.99000.json','["一世競榮利，紛若空中花。", "蚤作田園計，人生會有涯。"]'),
('29ce118e-424f-4d4b-bd24-ae652d7e0c53','次韻杜無逸西園獨坐九絕句  其七','傅察','宋','宋诗','song-poetry','','[]','身遊闤闠間，心在孤雲杪。',24,'全唐诗/poet.song.99000.json','["身遊闤闠間，心在孤雲杪。", "譬如登太山，頗覺天下小。"]'),
('093feeba-cc8c-4359-b31d-ff00adc45377','次韻杜無逸西園獨坐九絕句  其八','傅察','宋','宋诗','song-poetry','','[]','外慕亦無已，反身良有餘。',24,'全唐诗/poet.song.99000.json','["外慕亦無已，反身良有餘。", "乘流如可遊，韞匵豈藏諸。"]'),
('4a780070-3b0e-4f6f-81c9-c45a194c4b30','次韻杜無逸西園獨坐九絕句  其九','傅察','宋','宋诗','song-poetry','','[]','聖德覆天下，歡然萬物春。',24,'全唐诗/poet.song.99000.json','["聖德覆天下，歡然萬物春。", "北窗微笑傲，似是羲皇人。"]'),
('6d798b46-2548-4d70-b9e3-4935a0ba60cf','題張季良適性齋','傅察','宋','宋诗','song-poetry','','[]','揚雄家無甔石儲，閉門作賦擬相如。',159,'全唐诗/poet.song.99000.json','["揚雄家無甔石儲，閉門作賦擬相如。", "鄴侯插架多異書，牙籖萬卷呑石渠。", "吾友張子斯人徒，嗜好酸鹹與衆殊。", "被褐懷寶老不癯，收拾萬卷以自娱。", "但願生爲蠧書魚，咀嚼英華味道腴。", "揮毫落紙驚群儒，佳處往往凌子。", "網羅秦漢包唐虞，上下千載歸指呼。", "自言此樂世所無，不羡潭潭卿相居。", "方今清廟收璠璵，肯使滄海遺明珠。", "髙名他日播天衢，行看旌帛来庭除。"]'),
('4bde490f-f4ae-42db-9a98-054d1487f345','伯仲時德升用均父韻送德父守葘川邀余同賦','傅察','宋','宋诗','song-poetry','','[]','妙齡擢秀如黄童，藉甚詞林振古風。',224,'全唐诗/poet.song.99000.json','["妙齡擢秀如黄童，藉甚詞林振古風。", "瀾翻千載常在口，磊落萬卷獨蟠胸。", "不将龜筮論從逆，獨向詩書有高識。", "琳宫乞得十年閑，可但新詩勝疇昔。", "一麾自詭治東萊，洗眼看公手重拭。", "疲氓按堵身暫休，黠吏垂頭聲不出。", "人言功效真卓爾，歸近高堂渾含喜。", "喜公才氣更難量，致君要著巖廊裏。", "秋雲漠漠向空飛，颯颯凉風生桂枝。", "馬蹄又踏東川去，盤水洋洋可樂饑。", "我今作吏愧無補，夢寐林泉那得歸。", "會袖手版付丞相，卻掃庭闈戲綵衣。", "卜鄰僅許依仁里，與子艱難共生死。", "釣竿伴我訪滄溟，沮洳定無三尺鯉。"]'),
('4fbd78dc-0ecc-4b78-bc5e-bb25a1a26ef0','送傅倅','傅察','宋','宋诗','song-poetry','','[]','洺之水兮，其流舒舒。',200,'全唐诗/poet.song.99000.json','["洺之水兮，其流舒舒。", "公之来兮，朱服熊車。", "士元展驥，仲舉題輿。", "公之来兮，民斯樂胥。", "洺之水兮，其流洋洋。", "公之化兮，春雨秋陽。", "袴襦頌洽，禾黍歲穣。", "公之化兮，民斯悦康。", "洺之水兮，其流瀰瀰。", "公之去兮，旌旂旖旎。", "父老攀轅，縉紳方軌。", "公之去兮，瞻望徙倚。", "洺之水兮，其流洩洩。", "公之德兮，此邦所愒。", "吏遵其畫，人懷其惠。", "公之德兮，久而勿替。", "洺之水兮，其流活活。", "公之名兮，兹其彌達。", "翔於朝宁，騫於省闥。", "公之名兮，莫我敢遏。"]'),
('c6eaffaa-4c2c-4d51-8cdc-46d7a7902f15','贈朱令中泮宫二首  其一','傅察','宋','宋诗','song-poetry','','[]','折桂陪英彥，彈冠接宷僚。',48,'全唐诗/poet.song.99000.json','["折桂陪英彥，彈冠接宷僚。", "志連秦璧固，論鄙楚師恌。", "逸驥終難縶，翔鸞詎可邀。", "緬懷巖下士，猶得夢中宵。"]'),
('0e506a08-6655-4b18-a25e-e8b68abba7b4','贈朱令中泮宫二首  其二','傅察','宋','宋诗','song-poetry','','[]','異時師盛德，此地喜同僚。',48,'全唐诗/poet.song.99000.json','["異時師盛德，此地喜同僚。", "大璧完無玷，和鐘小不恌。", "尊罍傾笑語，車馬費招邀。", "莫使光陰度，從今便卜宵。"]'),
('1bfa0355-6b24-44cd-a453-f14f1763cef2','余父子妻孥各在一方欲歸未得因感成詩','傅察','宋','宋诗','song-poetry','','[]','皎皎明河漢，悠悠度女牛。',48,'全唐诗/poet.song.99000.json','["皎皎明河漢，悠悠度女牛。", "奔馳空歲月，南北尙淹留。", "所願各千里，此身兼百憂。", "如何有羽翼，来往亦遨遊。"]'),
('fb40e3f0-58a2-4852-8066-d4c66d3fa3e7','思歸','傅察','宋','宋诗','song-poetry','','[]','舊國日已遠，東秦安在哉。',48,'全唐诗/poet.song.99000.json','["舊國日已遠，東秦安在哉。", "水雲波浩蕩，林日影摧頽。", "野色撩詩興，秋風動旅懷。", "繋舟還信步，不覺詠歸来。"]'),
('42859b61-ae10-45bd-8ec6-3e9eea886b74','阻風次衡元度韻','傅察','宋','宋诗','song-poetry','','[]','水柳纜孤舟，飄飄萬里秋。',48,'全唐诗/poet.song.99000.json','["水柳纜孤舟，飄飄萬里秋。", "遠風来不斷，髙浪去還收。", "菰葦蕭疏折，烟雲惨淡浮。", "賴知師德在，舟子亦多愁。"]'),
('0acf8506-f088-4e1c-afbf-46e9003323d7','逍搖堂五詠  其一','傅察','宋','宋诗','song-poetry','','[]','欲識逍搖樂，都忘利與名。',48,'全唐诗/poet.song.99000.json','["欲識逍搖樂，都忘利與名。", "討論唯百氏，来往有諸卿。", "静覺羊腸險，閑看蝸角爭。", "超然窮妙理，知不愧荘生。"]'),
('song-ci-0','导引','和岘','宋','宋词','song-ci','导引','[]','气和玉烛，睿化著鸿明。',118,'宋词/ci.song.0.json','["气和玉烛，睿化著鸿明。", "缇管一阳生。", "郊禋盛礼燔柴毕，旋轸凤凰城。", "森罗仪卫振华缨。", "载路溢欢声。", "皇图大业超前古，垂象泰阶平。", "岁时丰衍，九土乐升平。", "睹寰海澄清。", "道高尧舜垂衣治，日月并文明。", "嘉禾甘露登歌荐，云物焕祥经。", "兢兢惕惕持谦德，未许禅云亭。"]'),
('song-ci-1','六州','和岘','宋','宋词','song-ci','六州','[]','严夜警，铜莲漏迟迟。',161,'宋词/ci.song.0.json','["严夜警，铜莲漏迟迟。", "清禁肃，森陛戟，羽卫俨皇闱。", "角声励，钲鼓攸宜。", "金管成雅奏，逐吹逶迤。", "荐苍璧，郊祀神祗。", "属景运纯禧。", "京坻丰衍，群材乐育，诸侯述职，盛德服蛮夷。", "殊祥萃，九苞丹凤来仪。", "膏露降，和气洽，三秀焕灵芝。", "鸿猷播，史册相辉。", "张四维。", "卜世永固丕基。", "敷玄化，荡荡无为。", "合尧舜文思。", "混并寰宇，休牛归马，销金偃革，蹈咏庆昌期。"]'),
('song-ci-2','十二时・忆少年','和岘','宋','宋词','song-ci','十二时・忆少年','[]','承宝运，驯致隆平。',155,'宋词/ci.song.0.json','["承宝运，驯致隆平。", "鸿庆被寰瀛。", "时清俗阜，治定功成。", "遐迩咏由庚。", "严郊祀，文物声明。", "会天正、星拱奏严更。", "布羽仪簪缨。", "宸心虔洁，明德播惟馨。", "动苍冥。", "神降享精诚。", "燔柴半，万乘移天仗，肃銮辂旋衡。", "千官云拥，群后葵倾。", "玉帛旅明庭。", "韶濩荐，金奏谐声。", "集休亨。", "皇泽浃黎庶，普率洽恩荣。", "仰钦元后，睿圣贯三灵。", "万邦宁。", "景贶福千龄。"]'),
('song-ci-3','点绛唇','王禹','宋','宋词','song-ci','点绛唇','[]','雨恨云愁，江南依旧称佳丽。',50,'宋词/ci.song.0.json','["雨恨云愁，江南依旧称佳丽。", "水村渔市。", "一缕孤烟细。", "天际征鸿，遥认行如缀。", "平生事。", "此时凝睇。", "谁会凭阑意。"]'),
('song-ci-4','越江吟','苏易简','宋','宋词','song-ci','越江吟','[]','神仙神仙瑶池宴。',38,'宋词/ci.song.0.json','["神仙神仙瑶池宴。", "片片。", "碧桃零落春风晚。", "翠云开处，隐隐金舆挽。", "玉麟背冷清风远。"]'),
('song-ci-5','甘草子','寇准','宋','宋词','song-ci','甘草子','[]','春早。',57,'宋词/ci.song.0.json','["春早。", "柳丝无力，低拂清门道。", "暖日笼啼鸟。", "初坼桃花小。", "遥望碧天净如扫。", "曳一缕、轻烟缥缈。", "堪惜流年谢芳草。", "任玉壶倾倒。"]'),
('song-ci-6','踏莎行','寇准','宋','宋词','song-ci','踏莎行','[]','春色将阑，莺声渐老。',68,'宋词/ci.song.0.json','["春色将阑，莺声渐老。", "红英落尽青梅小。", "画堂人静雨濛濛，屏山半掩馀香袅。", "密约沈沈，离情杳杳。", "菱花尘满慵将照。", "倚楼无语欲销魂，长空黯淡连芳草。"]'),
('song-ci-7','阳关引','寇准','宋','宋词','song-ci','阳关引','[]','塞草烟光阔。',94,'宋词/ci.song.0.json','["塞草烟光阔。", "渭水波声咽。", "春朝雨霁轻尘歇。", "征鞍发。", "指青青杨柳，又是轻攀折。", "动黯然、知有后会甚时节。", "更尽一杯酒，歌一阕。", "叹人生，最难欢聚易离别。", "且莫辞沉醉，听取阳关彻。", "念故人、千里自此共明月。"]'),
('song-ci-8','点绛唇','寇准','宋','宋词','song-ci','点绛唇','[]','水陌轻寒，社公雨足东风慢。',50,'宋词/ci.song.0.json','["水陌轻寒，社公雨足东风慢。", "定巢新燕。", "湿雨穿花转。", "象尺熏炉，拂晓停针线。", "愁蛾浅。", "飞红零乱。", "侧卧珠帘卷。"]'),
('song-ci-9','江南春・秋风清','寇准','宋','宋词','song-ci','江南春・秋风清','[]','波渺渺，柳依依。',36,'宋词/ci.song.0.json','["波渺渺，柳依依。", "孤村芳草远，斜日杏花飞。", "江南春尽离肠远，苹满汀洲人未归。"]'),
('song-ci-10','夜度娘','寇准','宋','宋词','song-ci','夜度娘','[]','烟波渺渺一千里，白苹香散东风起。',32,'宋词/ci.song.0.json','["烟波渺渺一千里，白苹香散东风起。", "日暮汀洲一望时，柔情不断如春水。"]'),
('song-ci-11','木兰花・玉楼春','钱惟演','宋','宋词','song-ci','木兰花・玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','城上风光莺语乱。',64,'宋词/ci.song.0.json','["城上风光莺语乱。", "城下烟波春拍岸。", "绿杨芳草几时休，泪眼愁肠先已断。", "情怀渐变成衰晚。", "鸾鉴朱颜惊暗换。", "昔年多病厌芳尊，今日芳尊惟恐浅。"]'),
('song-ci-12','玉楼春','钱惟演','宋','宋词','song-ci','玉楼春','[]','锦箨参差朱槛曲。',64,'宋词/ci.song.0.json','["锦箨参差朱槛曲。", "露濯文犀和粉绿。", "未容浓翠伴桃红，已许纤枝留凤宿。", "嫩似春荑明似玉。", "一寸芳心谁管束。", "劝君速吃莫踟蹰，看被南风吹作竹。"]'),
('song-ci-13','踏莎行','陈尧佐','宋','宋词','song-ci','踏莎行','[]','二社良辰，千家庭院。',68,'宋词/ci.song.0.json','["二社良辰，千家庭院。", "翩翩又见新来燕。", "凤凰巢稳许为邻，潇湘烟暝来何晚。", "乱入红楼，低飞绿岸。", "画梁时拂歌尘散。", "为谁归去为谁来，主人恩重珠帘卷。"]'),
('song-ci-14','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆钱塘，不是人寰是天上。',57,'宋词/ci.song.0.json','["长忆钱塘，不是人寰是天上。", "万家掩映翠微间。", "处处水潺潺。", "异花四季当窗放。", "出入分明在屏障。", "别来隋柳几经秋。", "何日得重游。"]'),
('song-ci-15','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆钱塘，临水傍山三百寺。',57,'宋词/ci.song.0.json','["长忆钱塘，临水傍山三百寺。", "僧房携杖遍曾游。", "闲话觉忘忧。", "栴檀楼阁云霞畔。", "钟梵清宵彻天汉。", "别来遥礼祗焚香。", "便恐是西方。"]'),
('song-ci-16','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','["\u897f\u6e56"]','长忆西湖，湖上春来无限景。',57,'宋词/ci.song.0.json','["长忆西湖，湖上春来无限景。", "吴姬个个是神仙。", "兢泛木兰船。", "楼台簇簇疑蓬岛。", "野人祗合其中老。", "别来已是二十年。", "东望眼将穿。"]'),
('song-ci-17','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','["\u897f\u6e56"]','长忆西湖，尽日凭阑楼上望。',57,'宋词/ci.song.0.json','["长忆西湖，尽日凭阑楼上望。", "三三两两钓鱼舟。", "岛屿正清秋。", "笛声依约芦花里。", "白鸟成行忽惊起。", "别来闲整钓鱼竿。", "思入水云寒。"]'),
('song-ci-18','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆孤山，山在湖心如黛簇。',57,'宋词/ci.song.0.json','["长忆孤山，山在湖心如黛簇。", "僧房四面向湖开。", "轻棹去还来。", "芰荷香喷连云阁。", "阁上清声檐下铎。", "别来尘土污人衣。", "空役梦魂飞。"]'),
('song-ci-19','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆西山，灵隐寺前三竺后。',57,'宋词/ci.song.0.json','["长忆西山，灵隐寺前三竺后。", "冷泉亭上旧曾游。", "三伏似清秋。", "白猿时见攀高树。", "长啸一声何处去。", "别来几向画阑看。", "终是欠峰峦。"]'),
('song-ci-20','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆高峰，峰上塔高尘世外。',57,'宋词/ci.song.0.json','["长忆高峰，峰上塔高尘世外。", "昔年独上最高层。", "月出见觚稜。", "举头咫尺疑天汉。", "星斗分明在身畔。", "别来无翼可飞腾。", "何日得重登。"]'),
('song-ci-21','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆吴山，山上森森吴相庙。',57,'宋词/ci.song.0.json','["长忆吴山，山上森森吴相庙。", "庙前江水怒为涛。", "千古恨犹高。", "寒鸦日暮鸣还聚。", "时有阴云笼殿宇。", "别来有负谒灵祠。", "遥奠酒盈卮。"]'),
('song-ci-22','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','[]','长忆龙山，日月宫中谁得到。',57,'宋词/ci.song.0.json','["长忆龙山，日月宫中谁得到。", "宫中旦暮听潮声。", "台殿竹风清。", "门前岁岁生灵草。", "人采食之多不老。", "别来已白数茎头。", "早晚却重游。"]'),
('song-ci-23','酒泉子','潘阆','宋','宋词','song-ci','酒泉子','["\u94b1\u5858\u6c5f"]','长忆观潮，满郭人争江上望。',57,'宋词/ci.song.0.json','["长忆观潮，满郭人争江上望。", "来疑沧海尽成空。", "万面鼓声中。", "弄涛儿向涛头立。", "手把红旗旗不湿。", "别来几向梦中看。", "梦觉尚心寒。"]'),
('song-ci-24','扫市舞','潘阆','宋','宋词','song-ci','扫市舞','[]','出砒霜，价钱可。',20,'宋词/ci.song.0.json','["出砒霜，价钱可。", "赢得拨灰兼弄火。", "畅杀我。"]'),
('song-ci-25','凤栖梧・蝶恋花','丁谓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','十二层楼春色早。',70,'宋词/ci.song.0.json','["十二层楼春色早。", "三殿笙歌，九陌风光好。", "堤柳岸花连复道。", "玉梯相对开蓬岛。", "莺啭乔林鱼在藻。", "太液微波，绿斗王孙草。", "南阙万人瞻羽葆。", "后天祝圣天难老。"]'),
('song-ci-26','凤栖梧・蝶恋花','丁谓','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','朱阙玉城通阆苑。',70,'宋词/ci.song.0.json','["朱阙玉城通阆苑。", "月桂星榆，春色无深浅。", "潇瑟篌笙仙客宴。", "蟠桃花满蓬莱殿。", "九色明霞裁羽扇。", "云雾为车，鸾鹤骖雕辇。", "路指瑶池归去晚。", "壶中日月如天远。"]'),
('song-ci-27','相思令・相思儿令','林逋','宋','宋词','song-ci','相思令・相思儿令','[]','吴山青。',44,'宋词/ci.song.0.json','["吴山青。", "越山青。", "两岸青山相对迎。", "争忍有离情。", "君泪盈。", "妾泪盈。", "罗带同心结未成。", "江边潮已平。"]'),
('song-ci-28','点绛唇','林逋','宋','宋词','song-ci','点绛唇','[]','金谷年年，乱生春色谁为主。',50,'宋词/ci.song.0.json','["金谷年年，乱生春色谁为主。", "馀花落处。", "满地和烟雨。", "又是离歌，一阕长亭暮。", "王孙去。", "萋萋无数。", "南北东西路。"]'),
('song-ci-29','霜天晓角','林逋','宋','宋词','song-ci','霜天晓角','[]','冰清霜洁。',54,'宋词/ci.song.0.json','["冰清霜洁。", "昨夜梅花发。", "甚处玉龙三弄，声摇动、枝头月。", "梦绝。", "金兽爇。", "晓寒兰烬灭。", "要卷珠帘清赏，且莫扫、阶前雪。"]'),
('song-ci-30','瑞鹧鸪','林逋','宋','宋词','song-ci','瑞鹧鸪','[]','众芳摇落独鲜妍。',64,'宋词/ci.song.0.json','["众芳摇落独鲜妍。", "占尽风情向小园。", "疏影横斜水清浅，暗香浮动月黄昏。", "寒禽欲下先偷眼，粉蝶如知合断魂。", "幸有微吟可相狎，不须檀板共金尊。"]'),
('song-ci-31','少年游','杨亿','宋','宋词','song-ci','少年游','[]','江南节物，水昏云淡，飞雪满前村。',64,'宋词/ci.song.0.json','["江南节物，水昏云淡，飞雪满前村。", "千寻翠岭，一枝芳艳，迢递寄归人。", "寿阳妆罢，冰姿玉态，的的写天真。", "等闲风雨又纷纷。", "更忍向、笛中闻。"]'),
('song-ci-32','生查子','陈亚','宋','宋词','song-ci','生查子','[]','朝庭数擢贤，旋占凌霄路。',50,'宋词/ci.song.0.json','["朝庭数擢贤，旋占凌霄路。", "自是郁陶人，险难无移处。", "也知没药疗饥寒，食薄何相误。", "大幅纸连粘，甘草归田赋。"]'),
('song-ci-33','生查子','陈亚','宋','宋词','song-ci','生查子','[]','相思意已深，白纸书难足。',50,'宋词/ci.song.0.json','["相思意已深，白纸书难足。", "字字苦参商，故要槟郎读。", "分明记得约当归，远至樱桃熟。", "何事菊花时，犹未回乡曲。"]'),
('song-ci-34','生查子','陈亚','宋','宋词','song-ci','生查子','[]','小院雨馀凉，石竹风生砌。',50,'宋词/ci.song.0.json','["小院雨馀凉，石竹风生砌。", "罢扇尽从容，半下纱厨睡。", "起来闲坐北亭中，滴尽真珠泪。", "为念婿辛勤，去折蟾宫桂。"]'),
('song-ci-35','生查子','陈亚','宋','宋词','song-ci','生查子','[]','浪荡去未来，踯躅花频换。',50,'宋词/ci.song.0.json','["浪荡去未来，踯躅花频换。", "可惜石榴裙，兰麝香销半。", "琵琶闲抱理相思，必拨朱弦断。", "拟续断朱弦，待这冤家看。"]'),
('song-ci-36','喜迁莺','夏竦','宋','宋词','song-ci','喜迁莺','[]','霞散绮，月沈钩。',59,'宋词/ci.song.0.json','["霞散绮，月沈钩。", "帘卷未央楼。", "夜凉河汉截天流。", "宫阙锁清秋。", "瑶阶曙。", "金盘露。", "凤髓香和烟雾。", "三千珠翠拥宸游。", "水殿按《凉州》。"]'),
('song-ci-37','鹧鸪天','夏竦','宋','宋词','song-ci','鹧鸪天','[]','镇日无心扫黛眉。',64,'宋词/ci.song.0.json','["镇日无心扫黛眉。", "临行愁见理征衣。", "尊前只恐伤郎意，阁泪汪汪不敢垂。", "停宝马，捧瑶卮。", "相斟相劝忍分离。", "不如饮待奴先醉，图得不知郎去时。"]'),
('song-ci-38','多丽','聂冠卿','宋','宋词','song-ci','多丽','[]','想人生，美景良辰堪惜。',173,'宋词/ci.song.0.json','["想人生，美景良辰堪惜。", "问其间、赏心乐事，就中难是并得。", "况东城、凤台沙苑，泛晴波、浅照金碧。", "露洗华桐，烟霏丝柳，绿阴摇曳，荡春一色。", "画堂迥、玉簪琼佩，高会尽词客。", "清欢久、重然绛蜡，别就瑶席。", "有翩若轻鸿体态，暮为行雨标格。", "逞朱唇、缓歌妖丽，似听流莺乱花隔。", "慢舞萦回，娇鬟低亸，腰肢纤细困无力。", "忍分散、彩云归后，何处更寻觅。", "休辞醉，明月好花，莫谩轻掷。"]'),
('song-ci-39','望汉月・忆汉月','李遵','宋','宋词','song-ci','望汉月・忆汉月','[]','黄菊一丛临砌。',62,'宋词/ci.song.0.json','["黄菊一丛临砌。", "颗颗露珠装缀。", "独教冷落向秋天，恨东君不曾留意。", "雕阑新雨霁。", "绿藓上，乱铺金蕊。", "此花开后更无花，愿爱惜、莫同桃李。"]'),
('song-ci-40','滴滴金','李遵','宋','宋词','song-ci','滴滴金','[]','帝城五夜宴游歇。',60,'宋词/ci.song.0.json','["帝城五夜宴游歇。", "残灯外、看残月。", "都人犹在醉乡中，听更漏初彻。", "行乐已成闲话说。", "如春梦、觉时节。", "大家同约探春行，问甚花先发。"]'),
('song-ci-41','苏幕遮','范仲淹','宋','宋词','song-ci','苏幕遮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','碧云天，黄叶地。',76,'宋词/ci.song.0.json','["碧云天，黄叶地。", "秋色连波，波上寒烟翠。", "山映斜阳天接水。", "芳草无情，更在斜阳外。", "黯乡魂，追旅思。", "夜夜除非，好梦留人睡。", "明月楼高休独倚。", "酒入愁肠，化作相思泪。"]'),
('song-ci-42','渔家傲','范仲淹','宋','宋词','song-ci','渔家傲','[]','塞下秋来风景异。',72,'宋词/ci.song.0.json','["塞下秋来风景异。", "衡阳雁去无留意。", "四面边声连角起。", "千嶂里。", "长烟落日孤城闭。", "浊酒一杯家万里。", "燕然未勒归无计。", "羌管悠悠霜满地。", "人不寐。", "将军白发征夫泪。"]'),
('song-ci-43','御街行','范仲淹','宋','宋词','song-ci','御街行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','纷纷堕叶飘香砌。',94,'宋词/ci.song.0.json','["纷纷堕叶飘香砌。", "夜寂静、寒声碎。", "真珠帘卷玉楼空，天淡银河垂地。", "年年今夜，月华如练，长是人千里。", "愁肠已断无由醉。", "酒未到、先成泪。", "残灯明灭枕头欹。", "谙尽孤眠滋味。", "都来此事，眉间心上，无计相回避。"]'),
('song-ci-44','剔银灯','范仲淹','宋','宋词','song-ci','剔银灯','[]','昨夜因看蜀志。',97,'宋词/ci.song.0.json','["昨夜因看蜀志。", "笑曹操、孙权、刘备。", "用尽机关，徒劳心力，只得三分天地。", "屈指细寻思，争如共、刘伶一醉。", "人世都无百岁。", "少痴呆、老成尩悴。", "只有中间，些子少年，忍把浮名牵系。", "一品与千金，问白发、如何回避。"]'),
('song-ci-45','定风波','范仲淹','宋','宋词','song-ci','定风波','[]','罗绮满城春欲暮。',72,'宋词/ci.song.0.json','["罗绮满城春欲暮。", "百花洲上寻芳去。", "浦映□花花映浦。", "无尽处。", "恍然身入桃源路。", "莫怪山翁聊逸豫。", "功名得丧归时数。", "莺解新声蝶解舞。", "天赋与。", "争教我辈无欢绪。"]'),
('song-ci-46','剔银灯','沈邈','宋','宋词','song-ci','剔银灯','[]','一夜隋河风劲。',94,'宋词/ci.song.0.json','["一夜隋河风劲。", "霜湿水天如镜。", "古柳堤长，寒烟不起，波上月无流影。", "那堪频听。", "疏星外、离鸿相应。", "须信道、情多是病。", "酒未到、愁肠还醒。", "数叠兰衾，馀香未减，甚时枕鸳重并。", "教伊须更。", "将盟誓、后约言定。"]'),
('song-ci-47','剔银灯','沈邈','宋','宋词','song-ci','剔银灯','[]','江上秋高霜早。',94,'宋词/ci.song.0.json','["江上秋高霜早。", "云静月华如扫。", "候雁初飞，啼螀正苦，又是黄花衰草。", "等闲临照。", "潘郎鬓、星星易老。", "那堪更、酒醒孤棹。", "望千里、长安西笑。", "臂上妆痕，胸前泪粉，暗惹离愁多少。", "此情谁表。", "除非是、重相见了。"]'),
('song-ci-48','长相思','杨适1','宋','宋词','song-ci','长相思','[]','南山明。',44,'宋词/ci.song.0.json','["南山明。", "北山明。", "中有长亭号丈亭。", "沙边供送迎。", "东江清。", "西江清。", "海上潮来两岸平。", "行人分棹行。"]'),
('song-ci-49','黄莺儿','柳永','宋','宋词','song-ci','黄莺儿','[]','园林晴昼春谁主。',116,'宋词/ci.song.0.json','["园林晴昼春谁主。", "暖律潜催，幽谷暄和，黄鹂翩翩，乍迁芳树。", "观露湿缕金衣，叶映如簧语。", "晓来枝上绵蛮，似把芳心、深意低诉。", "无据。", "乍出暖烟来，又趁游蜂去。", "恣狂踪迹，两两相呼，终朝雾吟风舞。", "当上苑柳秾时，别馆花深处。", "此际海燕偏饶，都把韶光与。"]'),
('song-ci-50','玉女摇仙佩','柳永','宋','宋词','song-ci','玉女摇仙佩','[]','飞琼伴侣，偶别珠宫，未返神仙行缀。',169,'宋词/ci.song.0.json','["飞琼伴侣，偶别珠宫，未返神仙行缀。", "取次梳妆，寻常言语，有得几多姝丽。", "拟把名花比。", "恐旁人笑我，谈何容易。", "细思算、奇葩艳卉，惟是深红浅白而已。", "争如这多情，占得人间，千娇百媚。", "须信画堂绣阁，皓月清风，忍把光阴轻弃。", "自古及今、佳人才子，少得当年双美。", "且恁相偎依。", "未消得、怜我多才多艺。", "愿妳妳、兰心蕙性，枕前言下，表余深意。", "为盟誓。", "今生断不孤鸳被。"]'),
('song-ci-51','雪梅香','柳永','宋','宋词','song-ci','雪梅香','[]','景萧索，危楼独立面晴空。',114,'宋词/ci.song.0.json','["景萧索，危楼独立面晴空。", "动悲秋情绪，当时宋玉应同。", "渔市孤烟袅寒碧，水村残叶舞愁红。", "楚天阔，浪浸斜阳，千里溶溶。", "临风。", "想佳丽，别后愁颜，镇敛眉峰。", "可惜当年，顿乖雨迹云踪。", "雅态妍姿正欢洽，落花流水忽西东。", "无憀恨、相思意，尽分付征鸿。"]'),
('song-ci-52','尾犯','柳永','宋','宋词','song-ci','尾犯','[]','夜雨滴空阶，孤馆梦回，情绪萧索。',116,'宋词/ci.song.0.json','["夜雨滴空阶，孤馆梦回，情绪萧索。", "一片闲愁，想丹青难貌。", "秋渐老、蛩声正苦，夜将阑、灯花旋落。", "最无端处，总把良宵，祗恁孤眠却。", "佳人应怪我，别后寡信轻诺。", "记得当初，翦香云为约。", "甚时向、幽闺深处，按新词、流霞共酌。", "再同欢笑，肯把金玉珠珍博。"]'),
('song-ci-53','早梅芳・喜迁莺','柳永','宋','宋词','song-ci','早梅芳・喜迁莺','[]','海霞红，山烟翠。',129,'宋词/ci.song.0.json','["海霞红，山烟翠。", "故都风景繁华地。", "谯门画戟，下临万井，金碧楼台相倚。", "芰荷浦溆，杨柳汀洲，映虹桥倒影，兰舟飞棹，游人聚散，一片湖光里。", "汉元侯，自从破虏征蛮，峻陟枢庭贵。", "筹帷厌久，盛年昼锦，归来吾乡我里。", "铃斋少讼，宴馆多欢，未周星，便恐皇家，图任勋贤，又作登庸计。"]'),
('song-ci-54','斗百花','柳永','宋','宋词','song-ci','斗百花','[]','飒飒霜飘鸳瓦，翠幕轻寒微透，长门深锁悄悄，满庭秋色将晚。',96,'宋词/ci.song.0.json','["飒飒霜飘鸳瓦，翠幕轻寒微透，长门深锁悄悄，满庭秋色将晚。", "眼看菊蕊，重阳泪落如珠，长是淹残粉面。", "鸾辂音尘远。", "无险幽恨，寄情空殢纨扇。", "应是帝王，当初怪妾辞辇。", "陡顿今来，宫中第一妖娆，却道昭阳飞燕。"]'),
('song-ci-55','斗百花','柳永','宋','宋词','song-ci','斗百花','[]','煦色韶光明媚。',96,'宋词/ci.song.0.json','["煦色韶光明媚。", "轻霭低笼芳树。", "池塘浅蘸烟芜，帘幕闲垂风絮。", "春困厌厌，抛掷斗草工夫，冷落踏青心绪。", "终日卮朱户。", "远恨绵绵，淑景迟迟难度。", "年少傅粉，依前醉眠何处。", "深院无人，黄昏乍拆秋千，空锁满庭花雨。"]'),
('song-ci-56','斗百花','柳永','宋','宋词','song-ci','斗百花','[]','满搦宫腰纤细。',96,'宋词/ci.song.0.json','["满搦宫腰纤细。", "年纪方当笄岁。", "刚被风流沾惹，与合垂杨双髻。", "初学严妆，如描似削身材，怯雨羞云情意。", "举措多娇媚。", "争奈心性，未会先怜佳婿。", "长是夜深，不肯便入鸳被。", "与解罗裳，盈盈背立银釭，却道你但先睡。"]'),
('song-ci-57','甘草子','柳永','宋','宋词','song-ci','甘草子','[]','秋暮。',57,'宋词/ci.song.0.json','["秋暮。", "乱洒衰荷，颗颗真珠雨。", "雨过月华生，冷彻鸳鸯浦。", "池长凭阑愁无侣。", "奈此个、单栖情绪。", "却傍金笼共鹦鹉。", "念粉郎言语。"]'),
('song-ci-58','甘草子','柳永','宋','宋词','song-ci','甘草子','[]','秋尽。',57,'宋词/ci.song.0.json','["秋尽。", "叶翦红绡，砌菊遗金粉。", "雁字一行来，还有边庭信。", "飘散露华清风紧。", "动翠幕、晓寒犹嫩。", "中酒残妆慵整顿。", "聚两眉离恨。"]'),
('song-ci-59','送征衣','柳永','宋','宋词','song-ci','送征衣','[]','过韶阳。',154,'宋词/ci.song.0.json','["过韶阳。", "璇枢电绕，华渚虹流，运应千载会昌。", "罄寰宇、荐殊祥。", "吾皇。", "诞弥月，瑶图缵庆，玉叶腾芳。", "并景贶、三灵眷祐，挺英哲、掩前王。", "迂年年、嘉节清和，颁率土称觞。", "无间要荒华夏，尽万里、走梯航。", "彤庭舜张大乐，禹会群方。", "鹓行。", "望上国，山呼鳌抃，遥爇炉香。", "竟就日、瞻云献寿，指南山、等无疆。", "愿巍巍、宝历鸿基，齐天地遥长。"]'),
('song-ci-60','昼夜乐','柳永','宋','宋词','song-ci','昼夜乐','[]','洞房记得初相遇。',118,'宋词/ci.song.0.json','["洞房记得初相遇。", "便只合、长相聚。", "何期小会幽欢，变作离情别绪。", "况值阑珊春色暮。", "对满目、乱花狂絮。", "直恐好风光，尽随伊归去。", "一场寂寞凭谁诉。", "算前言、总轻负。", "早知恁地难拼，悔不当时留住。", "其奈风流端正外，更别有、系人心处。", "一日不思量，也攒眉千度。"]'),
('song-ci-61','昼夜乐','柳永','宋','宋词','song-ci','昼夜乐','[]','秀香家住桃花径。',118,'宋词/ci.song.0.json','["秀香家住桃花径。", "算神仙、才堪并。", "层波细翦明眸，腻玉圆搓素颈。", "爱把歌喉当筵逞。", "遏天边，乱云愁凝。", "言语似娇莺，一声声堪听。", "洞房饮散帘帏静。", "拥香衾、欢心称。", "金炉麝袅青烟，凤帐烛摇红影。", "无限狂心乘酒兴。", "这欢娱、渐入嘉景。", "犹自怨邻鸡，道秋宵不永。"]'),
('song-ci-62','柳腰轻','柳永','宋','宋词','song-ci','柳腰轻','[]','英英妙舞腰肢软。',102,'宋词/ci.song.0.json','["英英妙舞腰肢软。", "章台柳、昭阳燕。", "锦衣冠盖，绮堂筵会，是处千金争选。", "顾香砌、丝管初调，倚轻风、佩环微颤。", "乍入霓裳促遍。", "逞盈盈、渐催檀板。", "慢垂霞袖，急趋莲步，进退奇容千变。", "算何止、倾国倾城，暂回眸、万人肠断。"]'),
('song-ci-63','西江月','柳永','宋','宋词','song-ci','西江月','[]','凤额绣帘高卷，兽环朱户频摇。',58,'宋词/ci.song.0.json','["凤额绣帘高卷，兽环朱户频摇。", "两竿红日上花梢。", "春睡厌厌难觉。", "好梦狂随飞絮，闲愁浓胜香醪。", "不成雨暮与云朝。", "又是韶光过了。"]'),
('song-ci-64','倾杯乐','柳永','宋','宋词','song-ci','倾杯乐','[]','禁漏花深，绣工日永，蕙风布暖。',130,'宋词/ci.song.0.json','["禁漏花深，绣工日永，蕙风布暖。", "变韶景、都门十二，元宵三五，银蟾光满。", "连云复道凌飞观。", "耸皇居丽，嘉气瑞烟葱蒨。", "翠华宵幸，是处层城阆苑。", "龙凤烛、交光星汉。", "对咫尺鳌山开羽扇。", "会乐府两籍神仙，梨园四部弦管。", "向晓色、都人未散。", "盈万井、山呼鳌抃。", "愿岁岁，天仗里、长瞻凤辇。"]'),
('song-ci-65','笛家弄・笛家','柳永','宋','宋词','song-ci','笛家弄・笛家','[]','花发西园，草薰南陌，韶光明媚，乍晴轻暖清明后。',156,'宋词/ci.song.0.json','["花发西园，草薰南陌，韶光明媚，乍晴轻暖清明后。", "水嬉舟动，禊饮筵开，银塘似染，金堤如绣。", "是处王孙，几多游妓，往往携纤手。", "遣离人、对嘉景，触目伤怀，尽成感旧。", "别久。", "帝城当日，兰堂夜烛，百万呼卢，画阁春风，十千沽酒。", "未省、宴处能忘管弦，醉里不寻花柳。", "岂知秦楼，玉箫声断，前事难重偶。", "空遗恨，望仙乡，一饷消凝，泪沾襟袖。"]'),
('song-ci-66','倾杯乐','柳永','宋','宋词','song-ci','倾杯乐','[]','皓月初圆，暮云飘散，分明夜色如晴昼。',141,'宋词/ci.song.0.json','["皓月初圆，暮云飘散，分明夜色如晴昼。", "渐消尽、醺醺残酒。", "危阁迥、凉生襟袖。", "追旧事、一饷凭阑久。", "如何媚容艳态，抵死孤欢偶。", "朝思暮想，自家空恁添清瘦。", "算到头、谁与伸剖。", "向道我别来，为伊牵系，度岁经年，偷眼觑、也不忍觑花柳。", "可惜恁、好景良宵，未曾略展双眉暂开口。", "问甚时与你，深怜痛惜还依旧。"]'),
('song-ci-67','迎新春','柳永','宋','宋词','song-ci','迎新春','[]','嶰管变青律，帝里阳和新布。',129,'宋词/ci.song.0.json','["嶰管变青律，帝里阳和新布。", "晴景回轻煦。", "庆嘉节、当三五。", "列华灯、千门万户。", "遍九陌、罗绮香风微度。", "十里然绛树。", "鳌山耸、喧天潇鼓。", "渐天如水，素月当午。", "香径里、绝缨掷果无数。", "更阑烛影花阴下，少年人、往往奇遇。", "太平时、朝野多欢民康阜。", "随分良聚。", "堪对此景，争忍独醒归去。"]'),
('song-ci-68','曲玉管','柳永','宋','宋词','song-ci','曲玉管','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','陇首云飞，江边日晚，烟波满目凭阑久。',128,'宋词/ci.song.0.json','["陇首云飞，江边日晚，烟波满目凭阑久。", "立望关河萧索，千里清秋。", "忍凝眸。", "杳杳神京，盈盈仙子，别来锦字终难偶。", "断雁无凭，冉冉飞下汀洲。", "思悠悠。", "暗想当初，有多少、幽欢佳会，岂知聚散难期，翻成雨恨云愁。", "阻追游。", "每登山临水，惹起平生心事，一场消黯，永日无言，却下层楼。"]'),
('song-ci-69','满朝欢','柳永','宋','宋词','song-ci','满朝欢','[]','花隔铜壶，露晞金掌，都门十二清晓。',122,'宋词/ci.song.0.json','["花隔铜壶，露晞金掌，都门十二清晓。", "帝里风光烂漫，偏爱春杪。", "烟轻昼永，引莺啭上林，鱼游灵沼。", "巷陌乍晴，香尘染惹，垂杨芳草。", "因念秦楼彩凤，楚观朝云，往惜曾迷歌笑。", "别来岁久，偶忆欢盟重到。", "人面桃花，未知何处，但掩朱扉悄悄。", "尽日伫立无言，赢得凄凉怀抱。"]'),
('song-ci-70','梦还京','柳永','宋','宋词','song-ci','梦还京','[]','夜来匆匆饮散，敧枕背灯睡。',96,'宋词/ci.song.0.json','["夜来匆匆饮散，敧枕背灯睡。", "酒力全轻，醉魂易醒，风揭帘栊，梦断披衣重起。", "悄无寐。", "追悔当初，绣阁话别太容易。", "日许时、犹阻归计。", "甚况味。", "旅馆虚度残岁。", "想娇媚。", "那里独守鸳帏静，永漏迢迢，也应暗同此意。"]'),
('song-ci-71','凤衔杯','柳永','宋','宋词','song-ci','凤衔杯','[]','有美瑶卿能染翰。',78,'宋词/ci.song.0.json','["有美瑶卿能染翰。", "千里寄、小诗长简。", "想初襞苔笺，旋挥翠管红窗畔。", "渐玉箸、银钩满。", "锦囊收，犀轴卷。", "常珍重、小斋吟玩。", "更宝若珠玑，置之怀袖时时看。", "似频见、千娇面。"]'),
('song-ci-72','凤衔杯','柳永','宋','宋词','song-ci','凤衔杯','[]','追悔当初孤深愿。',78,'宋词/ci.song.0.json','["追悔当初孤深愿。", "经年价、两成幽怨。", "任越水吴山，似屏如障堪游玩。", "奈独自、慵抬眼。", "赏烟花，听弦管。", "图欢笑、转加肠断。", "更时展丹青，强拈书信频频看。", "又争似、亲相见。"]'),
('song-ci-73','鹤冲天','柳永','宋','宋词','song-ci','鹤冲天','[]','闲窗漏永，月冷霜华堕。',103,'宋词/ci.song.0.json','["闲窗漏永，月冷霜华堕。", "悄悄下帘幕，残灯火。", "再三追往事，离魂乱、愁肠锁。", "无语沉吟坐。", "好天好景，未省展眉则个。", "从前早是多成破。", "何况经岁月，相抛亸。", "假使重相见，还得似、旧时麽。", "悔恨无计那。", "迢迢良夜，自家只恁摧挫。"]'),
('song-ci-74','受恩深','柳永','宋','宋词','song-ci','受恩深','[]','雅致装庭宇。',102,'宋词/ci.song.0.json','["雅致装庭宇。", "黄花开淡泞。", "细香明艳尽天与。", "助秀色堪餐，向晓自有真珠露。", "刚被金钱妒。", "拟买断秋天，容易独步。", "粉蝶无情蜂已去。", "要上金尊，惟有诗人曾许。", "待宴赏重阳，恁时尽把芳心吐。", "陶令轻回顾。", "免憔悴东篱，冷烟寒雨。"]'),
('song-ci-75','看花回','柳永','宋','宋词','song-ci','看花回','[]','屈指劳生百岁期。',80,'宋词/ci.song.0.json','["屈指劳生百岁期。", "荣瘁相随。", "利牵名惹逡巡过，奈两轮、玉走金飞。", "红颜成白发，极品何为。", "尘事常多雅会稀。", "忍不开眉。", "画堂歌管深深处，难忘酒盏花枝。", "醉乡风景好，携手同归。"]'),
('song-ci-76','看花回','柳永','宋','宋词','song-ci','看花回','[]','玉墄金阶舞舜干。',82,'宋词/ci.song.0.json','["玉墄金阶舞舜干。", "朝野多欢。", "九衢三市风光丽，正万家、急管繁弦。", "凤楼临绮陌，嘉气非烟。", "雅俗熙熙物态妍。", "忍负芳年。", "笑筵歌席连昏昼，任旗亭、斗酒十千。", "赏心何处好，惟有尊前。"]'),
('song-ci-77','柳初新','柳永','宋','宋词','song-ci','柳初新','[]','东郊向晓星杓亚。',100,'宋词/ci.song.0.json','["东郊向晓星杓亚。", "报帝里、春来也。", "柳抬烟眼，花匀露脸，渐觉绿娇红姹。", "妆点层台芳榭。", "运神功、丹青无价。", "别有尧阶试罢。", "新郎君、成行如画。", "杏园风细，桃花浪暖，竞喜羽迁鳞化。", "遍九陌、相将游冶。", "骤香尘、宝鞍骄马。"]'),
('song-ci-78','两同心','柳永','宋','宋词','song-ci','两同心','[]','嫩脸修蛾，淡匀轻扫。',86,'宋词/ci.song.0.json','["嫩脸修蛾，淡匀轻扫。", "最爱学、宫体梳妆，偏能做、文人谈笑。", "绮筵前、舞燕歌云，别有轻妙。", "饮散玉炉烟袅。", "洞房悄悄。", "锦帐里、低语偏浓，银烛下、细看俱好。", "那人人，昨夜分明，许伊偕老。"]'),
('song-ci-79','两同心','柳永','宋','宋词','song-ci','两同心','[]','伫立东风，断魂南国。',86,'宋词/ci.song.0.json','["伫立东风，断魂南国。", "花光媚、春醉琼楼，蟾彩迥、夜游香陌。", "忆当时、酒恋花迷，役损词客。", "别有眼长腰搦。", "痛怜深惜。", "鸳会阻、夕雨凄飞，锦书断、暮云凝碧。", "想别来，好景良时，也应相忆。"]'),
('song-ci-80','女冠子','柳永','宋','宋词','song-ci','女冠子','[]','断云残雨。',137,'宋词/ci.song.0.json','["断云残雨。", "洒微凉、生轩户。", "动清籁、萧萧庭树。", "银河浓淡，华星明灭，轻云时度。", "莎阶寂静无睹。", "幽蛩切切秋吟苦。", "疏篁一径，流萤几点，飞来又去。", "对月临风，空恁无眠耿耿，暗想旧日牵情处。", "绮罗丛里，有人人、那回饮散，略曾谐鸳侣。", "因循忍便睽阻。", "相思不得长相聚。", "好天良夜，无端惹起，千愁万绪。"]'),
('song-ci-81','玉楼春','柳永','宋','宋词','song-ci','玉楼春','[]','昭华夜醮连清曙。',64,'宋词/ci.song.0.json','["昭华夜醮连清曙。", "金殿霓旌笼瑞雾。", "九枝擎烛灿繁星，百和焚香抽翠缕。", "香罗荐地延真驭。", "万乘凝旒听秘语。", "卜年无用考灵龟，从此乾坤齐历数。"]'),
('song-ci-82','玉楼春','柳永','宋','宋词','song-ci','玉楼春','[]','凤楼郁郁呈嘉瑞。',64,'宋词/ci.song.0.json','["凤楼郁郁呈嘉瑞。", "降圣覃恩延四裔。", "醮台清夜洞天严，公宴凌晨箫鼓沸。", "保生酒劝椒香腻。", "延寿带垂金缕细。", "几行鹓鹭望尧云，齐共南山呼万岁。"]'),
('song-ci-83','玉楼春','柳永','宋','宋词','song-ci','玉楼春','[]','皇都今夕知何夕。',64,'宋词/ci.song.0.json','["皇都今夕知何夕。", "特地风光盈绮陌。", "金丝玉管咽春空，蜡炬兰灯烧晓色。", "凤楼十二神仙宅。", "珠履三千鹓鹭客。", "金吾不禁六街游，狂杀云踪并雨迹。"]'),
('song-ci-84','玉楼春','柳永','宋','宋词','song-ci','玉楼春','[]','星闱上笏金章贵。',64,'宋词/ci.song.0.json','["星闱上笏金章贵。", "重委外台疏近侍。", "百常天阁旧通班，九岁国储新上计。", "太仓日富中邦最。", "宣室夜思前席对。", "归心怡悦酒肠宽，不泛千锺应不醉。"]'),
('song-ci-85','玉楼春','柳永','宋','宋词','song-ci','玉楼春','[]','阆风歧路连银阙。',64,'宋词/ci.song.0.json','["阆风歧路连银阙。", "曾许金桃容易窃。", "乌龙未睡定惊猜，鹦鹉能言防漏泄。", "匆匆纵得邻香雪。", "窗隔残烟帘映月。", "别来也拟不思量，争奈馀香犹未歇。"]'),
('song-ci-86','金蕉叶','柳永','宋','宋词','song-ci','金蕉叶','[]','厌厌夜饮平阳第。',74,'宋词/ci.song.0.json','["厌厌夜饮平阳第。", "添银烛、旋呼佳丽。", "巧笑难禁，艳歌无间声相继。", "准拟幕天席地。", "金蕉叶泛金波齐，未更阑、已尽狂醉。", "就中有个风流，暗向灯光底。", "恼遍两行珠翠。"]'),
('song-ci-87','惜春郎','柳永','宋','宋词','song-ci','惜春郎','[]','玉肌琼艳新妆饰。',59,'宋词/ci.song.0.json','["玉肌琼艳新妆饰。", "好壮观歌席。", "潘妃宝钏，阿娇金屋，应也消得。", "属和新词多俊格。", "敢共我勍敌。", "恨少年、枉费疏狂，不早与伊相识。"]'),
('song-ci-88','传花枝','柳永','宋','宋词','song-ci','传花枝','[]','平生自负，风流才调。',127,'宋词/ci.song.0.json','["平生自负，风流才调。", "口儿里、道知张陈赵。", "唱新词，改难令，总知颠倒。", "解刷扮，能ㄋ嗽，表里都峭。", "每遇著、饮席歌筵，人人尽道。", "可惜许老了。", "阎罗大伯曾教来，道人生、但不须烦恼。", "遇良辰，当美景，追欢买笑。", "剩活取百十年，只恁厮好。", "若限满、鬼使来追，待倩个、掩通著到。"]'),
('song-ci-89','雨霖铃','柳永','宋','宋词','song-ci','雨霖铃','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','寒蝉凄切。',125,'宋词/ci.song.0.json','["寒蝉凄切。", "对长亭晚，骤雨初歇。", "都门帐饮无绪，留恋处、兰舟催发。", "执手相看泪眼，竟无语凝噎。", "念去去、千里烟波，暮霭沈沈楚天阔。", "多情自古伤离别。", "更那堪、冷落清秋节。", "今宵酒醒何处，杨柳岸、晓风残月。", "此去经年，应是良辰、好景虚设。", "便纵有、千种风情，更与何人说。"]'),
('song-ci-90','定风波','柳永','宋','宋词','song-ci','定风波','[]','伫立长堤，淡荡晚风起。',130,'宋词/ci.song.0.json','["伫立长堤，淡荡晚风起。", "骤雨歇、极目萧疏，塞柳万株，掩映箭波千里。", "走舟车向此，人人奔名竞利。", "念荡子、终日驱驱，争觉乡关转迢递。", "何意。", "绣阁轻抛，锦字难逢，等闲度岁。", "奈泛泛旅迹，厌厌病绪，迩来谙尽，宦游滋味。", "此情怀、纵写香笺，凭谁与寄。", "算孟光、争得知我，继日添憔悴。"]'),
('song-ci-91','尉迟杯','柳永','宋','宋词','song-ci','尉迟杯','[]','宠佳丽。',128,'宋词/ci.song.0.json','["宠佳丽。", "算九衢红粉皆难比。", "天然嫩脸修蛾，不假施朱描翠。", "盈盈秋水。", "恣雅态、欲语先娇媚。", "每相逢、月夕花朝，自有怜才深意。", "绸缪凤枕鸳被。", "深深处、琼枝玉树相倚。", "困极欢馀，芙蓉帐暖，别是恼人情味。", "风流事、难逢双美。", "况已断、香云为盟誓。", "且相将、共乐平生，未肯轻分连理。"]'),
('song-ci-92','慢卷绸','柳永','宋','宋词','song-ci','慢卷绸','[]','闲窗烛暗，孤帏夜永，敧枕难成寐。',136,'宋词/ci.song.0.json','["闲窗烛暗，孤帏夜永，敧枕难成寐。", "细屈指寻思，旧事前欢，都来未尽，平生深意。", "到得如今，万般追悔。", "空只添憔悴。", "对好景良辰，皱著眉儿，成甚滋味。", "红茵翠被。", "当时事、一一堪垂泪。", "怎生得依前，似恁偎香倚暖，抱著日高犹睡。", "算得伊家，也应随分，烦恼心儿里。", "又争似从前，淡淡相看，免恁牵系。"]'),
('song-ci-93','征部乐','柳永','宋','宋词','song-ci','征部乐','[]','雅欢幽会，良辰可惜虚抛掷。',130,'宋词/ci.song.0.json','["雅欢幽会，良辰可惜虚抛掷。", "每追念、狂踪旧迹。", "长祗恁、愁闷朝夕。", "凭谁去、花衢觅。", "细说此中端的。", "道向我、转觉厌厌，役梦劳魂苦相忆。", "须知最有，风前月下，心事始终难得。", "但愿我、虫虫心下，把人看待，长是初相识。", "况渐逢春色。", "便是有、举场消息。", "待这回、好好怜伊，更不轻离拆。"]'),
('song-ci-94','佳人醉','柳永','宋','宋词','song-ci','佳人醉','[]','暮景萧萧雨霁。',86,'宋词/ci.song.0.json','["暮景萧萧雨霁。", "云淡天高风细。", "正月华如水。", "金波银汉，潋滟无际。", "冷浸书帷梦断，却披衣重起。", "临轩砌。", "素光遥指。", "因念翠蛾，杳隔音尘何处，相望同千里。", "尽凝睇。", "厌厌无寐。", "渐晓雕阑独倚。"]'),
('song-ci-95','迷仙引','柳永','宋','宋词','song-ci','迷仙引','[]','才过笄年，初绾云鬟，便学歌舞。',102,'宋词/ci.song.0.json','["才过笄年，初绾云鬟，便学歌舞。", "席上尊前，王孙随分相许。", "算等闲、酬一笑，便千金慵觑。", "常祗恐、容易蕣华偷换，光阴虚度。", "已受君恩顾。", "好与花为主。", "万里丹霄，何妨携手同归去。", "永弃却、烟花伴侣。", "免教人见妾，朝云暮雨。"]'),
('song-ci-96','御街行','柳永','宋','宋词','song-ci','御街行','[]','燔柴烟断星河曙。',90,'宋词/ci.song.0.json','["燔柴烟断星河曙。", "宝辇回天步。", "端门羽卫簇雕阑，六乐舜韶先举。", "鹤书飞下，鸡竿高耸，恩霈均寰寓。", "赤霜袍烂飘香雾。", "喜色成春煦。", "九仪三事仰天颜，八彩旋生眉宇。", "椿龄无尽，萝图有庆，常作乾坤主。"]'),
('song-ci-97','御街行','柳永','宋','宋词','song-ci','御街行','[]','前时小饮春庭院。',89,'宋词/ci.song.0.json','["前时小饮春庭院。", "悔放笙歌散。", "归来中夜酒醺醺，惹起旧愁无限。", "虽看坠楼换马，争奈不是鸳鸯伴。", "朦胧暗想如花面。", "欲梦还惊断。", "和衣拥被不成眠，一枕万回千转。", "惟有画梁，新来双燕，彻曙闻长叹。"]'),
('song-ci-98','归朝欢','柳永','宋','宋词','song-ci','归朝欢','[]','别岸扁舟三两只。',122,'宋词/ci.song.0.json','["别岸扁舟三两只。", "葭苇萧萧风淅淅。", "沙汀宿雁破烟飞，溪桥残月和霜白。", "渐渐分曙色。", "路遥山远多行役。", "往来人，只轮双桨，尽是利名客。", "一望乡关烟水隔。", "转觉归心生羽翼。", "愁云恨雨两牵萦，新春残腊相催逼。", "岁华都瞬息。", "浪萍风梗诚何益。", "归去来，玉楼深处，有个人相忆。"]'),
('song-ci-99','采莲令','柳永','宋','宋词','song-ci','采莲令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','月华收，云淡霜天曙。',112,'宋词/ci.song.0.json','["月华收，云淡霜天曙。", "西征客、此时情苦。", "翠娥执手送临歧，轧轧开朱户。", "千娇面、盈盈伫立，无言有泪，断肠争忍回顾。", "一叶兰舟，便恁急桨凌波去。", "贪行色、岂知离绪。", "万般方寸，但饮恨，脉脉同谁语。", "更回首、重城不见，寒江天外，隐隐两三烟树。"]'),
('song-ci-100','秋夜月・相见欢','柳永','宋','宋词','song-ci','秋夜月・相见欢','[]','当初聚散。',100,'宋词/ci.song.0.json','["当初聚散。", "便唤作、无由再逢伊面。", "近日来、不期而会重欢宴。", "向尊前、闲暇里，敛著眉儿长叹。", "惹起旧愁无限。", "盈盈泪眼。", "漫向我耳边，作万般幽怨。", "奈你自家心下，有事难见。", "待信真个，恁别无萦绊。", "不免收心，共伊长远。"]'),
('song-ci-101','巫山一段云','柳永','宋','宋词','song-ci','巫山一段云','[]','六六真游洞，三三物外天。',54,'宋词/ci.song.0.json','["六六真游洞，三三物外天。", "九班麟稳破非烟。", "何处按云轩。", "昨夜麻姑陪宴。", "又话蓬莱清浅。", "几回山脚弄云涛。", "仿佛见金鳌。"]'),
('song-ci-102','巫山一段云','柳永','宋','宋词','song-ci','巫山一段云','[]','琪树罗三殿，金龙抱九关。',54,'宋词/ci.song.0.json','["琪树罗三殿，金龙抱九关。", "上清真籍总群仙。", "朝拜五云间。", "昨夜紫微诏下。", "急唤天书使者。", "令赍瑶检降彤霞。", "重到汉皇家。"]'),
('song-ci-103','巫山一段云','柳永','宋','宋词','song-ci','巫山一段云','[]','清旦朝金母，斜阳醉玉龟。',54,'宋词/ci.song.0.json','["清旦朝金母，斜阳醉玉龟。", "天风摇曳六铢衣。", "鹤背觉孤危。", "贪看海蟾狂戏。", "不道九关齐闭。", "相将何处寄良宵。", "还去访三茅。"]'),
('song-ci-104','巫山一段云','柳永','宋','宋词','song-ci','巫山一段云','[]','阆苑年华永，嬉游别是情。',54,'宋词/ci.song.0.json','["阆苑年华永，嬉游别是情。", "人间三度见河清。", "一番碧桃成。", "金母忍将轻摘。", "留宴鳌峰真客。", "红狵闲卧吠斜阳。", "方朔敢偷尝。"]'),
('song-ci-105','巫山一段云','柳永','宋','宋词','song-ci','巫山一段云','[]','萧氏贤夫妇，茅家好弟兄。',54,'宋词/ci.song.0.json','["萧氏贤夫妇，茅家好弟兄。", "羽轮飙驾赴层城。", "高会尽仙卿。", "一曲云谣为寿。", "倒尽金壶碧酒。", "醺酣争撼白榆花。", "踏碎九光霞。"]'),
('song-ci-106','婆罗门令','柳永','宋','宋词','song-ci','婆罗门令','[]','昨宵里、恁和衣睡。',107,'宋词/ci.song.0.json','["昨宵里、恁和衣睡。", "今宵里、又恁和衣睡。", "小饮归来，初更过、醺醺醉。", "中夜后、何事还惊起。", "霜天冷，风细细。", "触疏窗、闪闪灯摇曳。", "空床展转重追想，云雨梦、任敧枕难继。", "寸心万绪，咫尺千里。", "好景良天，彼此空有相怜意。", "未有相怜计。"]'),
('song-ci-107','法曲献仙音','柳永','宋','宋词','song-ci','法曲献仙音','[]','追想秦楼心事，当年便约，于飞比翼。',111,'宋词/ci.song.0.json','["追想秦楼心事，当年便约，于飞比翼。", "每恨临歧处，正携手、翻成云雨离拆。", "念倚玉偎香，前事顿轻掷。", "惯怜惜。", "饶心性，镇厌厌多病，柳腰花态娇无力。", "早是乍清减，别后忍教愁寂。", "记取盟言，少孜煎、剩好将息。", "遇佳景、临风对月，事须时恁相忆。"]'),
('song-ci-108','西平乐','柳永','宋','宋词','song-ci','西平乐','[]','尽日凭高目，脉脉春情绪。',123,'宋词/ci.song.0.json','["尽日凭高目，脉脉春情绪。", "嘉景清明渐近，时节轻寒乍暖，天气才晴又雨。", "烟光淡荡，妆点平芜远树。", "黯凝伫。", "台榭好、莺燕语。", "正是和风丽日，几许繁红嫩绿，雅称嬉游去。", "奈阻隔、寻芳伴侣。", "秦楼凤吹，楚馆云约，空怅望、在何处。", "寂寞韶华暗度。", "可堪向晚，村落声声杜宇。"]'),
('song-ci-109','凤栖梧・蝶恋花','柳永','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','帘下清歌帘外宴。',70,'宋词/ci.song.0.json','["帘下清歌帘外宴。", "虽爱新声，不见如花面。", "牙板数敲珠一串，梁尘暗落琉璃盏。", "桐树花深孤凤怨。", "渐遏遥天，不放行云散。", "坐上少年听不惯。", "玉山未倒肠先断。"]'),
('song-ci-110','凤栖梧・蝶恋花','柳永','宋','宋词','song-ci','凤栖梧・蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','伫倚危楼风细细。',70,'宋词/ci.song.0.json','["伫倚危楼风细细。", "望极春愁，黯黯生天际。", "草色烟光残照里。", "无言谁会凭阑意。", "拟把疏狂图一醉。", "对酒当歌，强乐还无味。", "衣带渐宽终不悔。", "为伊消得人憔悴。"]'),
('song-ci-111','凤栖梧・蝶恋花','柳永','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','蜀锦地衣丝步障。',70,'宋词/ci.song.0.json','["蜀锦地衣丝步障。", "屈曲回廊，静夜闲寻访。", "玉砌雕阑新月上。", "朱扉半掩人相望。", "旋暖熏炉温斗帐。", "玉树琼枝，迤逦相偎傍。", "酒力渐浓春思荡。", "鸳鸯绣被翻红浪。"]'),
('song-ci-112','法曲第二・法曲','柳永','宋','宋词','song-ci','法曲第二・法曲','[]','青翼传情，香径偷期，自觉当初草草。',107,'宋词/ci.song.0.json','["青翼传情，香径偷期，自觉当初草草。", "未省同衾枕，便轻许相将，平生欢笑。", "怎生向、人间好事到头少。", "漫悔懊。", "细追思，恨从前容易，致得恩爱成烦恼。", "心下事千种，尽凭音耗。", "以此萦牵，等伊来、自家向道。", "洎相见，喜欢存问，又还忘了。"]'),
('song-ci-113','秋蕊香引','柳永','宋','宋词','song-ci','秋蕊香引','[]','留不得。',75,'宋词/ci.song.0.json','["留不得。", "光阴催促，奈芳兰歇，好花谢，惟顷刻。", "彩云易散琉璃脆，验前事端的。", "风月夜，几处前踪旧迹。", "忍思忆。", "这回望断，永作终天隔。", "向仙岛，归冥路，两无消息。"]'),
('song-ci-114','一寸金','柳永','宋','宋词','song-ci','一寸金','[]','井络天开，剑岭云横控西夏。',133,'宋词/ci.song.0.json','["井络天开，剑岭云横控西夏。", "地胜异、锦里风流，蚕市繁华，簇簇歌台舞榭。", "雅俗多游赏，轻裘俊、靓妆艳冶。", "当春昼，摸石江边，浣花溪畔景如画。", "梦应三刀，桥名万里，中和政多暇。", "仗汉节、揽辔澄清，高掩武侯勋业，文翁风化。", "台鼎须贤久，方镇静、又思命驾。", "空遗爱，两蜀三川，异日成嘉话。"]'),
('song-ci-115','永遇乐','柳永','宋','宋词','song-ci','永遇乐','[]','薰风解愠，昼景清和，新霁时候。',128,'宋词/ci.song.0.json','["薰风解愠，昼景清和，新霁时候。", "火德流光，萝图荐祉，累庆金枝秀。", "璇枢绕电，华渚流虹，是日挺生元后。", "缵唐虞垂拱，千载应期，万灵敷祐。", "殊方异域，争贡琛賮，架巘航波奔凑。", "三殿称觞，九仪就列，韶頀锵金奏。", "藩侯瞻望彤庭，亲携僚吏，竞歌元首。", "祝尧龄、北极齐尊，南山共久。"]'),
('song-ci-116','永遇乐','柳永','宋','宋词','song-ci','永遇乐','[]','天阁英游，内朝密侍，当世荣遇。',128,'宋词/ci.song.0.json','["天阁英游，内朝密侍，当世荣遇。", "汉守分麾，尧庭请瑞，方面凭心膂。", "风驰千骑，云拥双旌，向晓洞开严署。", "拥朱轓、喜色欢声，处处竞歌来暮。", "吴王旧国，今古江山秀异，人烟繁富。", "甘雨车行，仁风扇动，雅称安黎庶。", "棠郊成政，槐府登贤，非久定须归去。", "且乘闲、孙阁长开，融尊盛举。"]'),
('song-ci-117','卜算子','柳永','宋','宋词','song-ci','卜算子','[]','江风渐老，汀蕙半凋，满目败红衰翠。',109,'宋词/ci.song.0.json','["江风渐老，汀蕙半凋，满目败红衰翠。", "楚客登临，正是暮秋天气。", "引疏砧、断续残阳里。", "对晚景、伤怀念远，新愁旧恨相继。", "脉脉人千里。", "念两处风情，万重烟水。", "雨歇天高，望断翠峰十二。", "尽无言、谁会凭高意。", "纵写得、离肠万种，奈归云谁寄。"]'),
('song-ci-118','鹊桥仙','柳永','宋','宋词','song-ci','鹊桥仙','[]','届征途，携书剑，迢迢匹马东去。',106,'宋词/ci.song.0.json','["届征途，携书剑，迢迢匹马东去。", "惨离怀，嗟少年易分难聚。", "佳人方恁缱绻，便忍分鸳侣。", "当媚景，算密意幽欢，尽成轻负。", "此际寸肠万绪。", "惨愁颜、断魂无语。", "和泪眼、片时几番回顾。", "伤心脉脉谁诉。", "但黯然凝伫。", "暮烟寒雨。", "望秦楼何处。"]'),
('song-ci-119','浪淘沙','柳永','宋','宋词','song-ci','浪淘沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','梦觉、透窗风一线，寒灯吹息。',167,'宋词/ci.song.0.json','["梦觉、透窗风一线，寒灯吹息。", "那堪酒醒，又闻空阶，夜雨频滴。", "嗟因循、久作天涯客。", "负佳人、几许盟言，便忍把、从前欢会，陡顿翻成忧戚。", "愁极。", "再三追思，洞房深处，几度饮散歌阑，香暖鸳鸯被，岂暂时疏散，费伊心力。", "殢云尤雨，有万般千种，相怜相惜。", "恰到如今，天长漏永，无端自家疏隔。", "知何时、却拥秦云态，愿低帏昵枕，轻轻细说与，江乡夜夜，数寒更思忆。"]'),
('song-ci-120','夏云峰','柳永','宋','宋词','song-ci','夏云峰','[]','宴堂深。',113,'宋词/ci.song.0.json','["宴堂深。", "轩楹雨，轻压暑气低沈。", "花洞彩舟泛斝，坐绕清浔。", "楚台风快，湘簟冷、永日披襟。", "坐久觉、疏弦脆管，时换新音。", "越娥兰态蕙心。", "逞妖艳、昵欢邀宠难禁。", "筵上笑歌间发，舄履交侵。", "醉乡归处，须尽兴、满酌高吟。", "向此免、名缰利锁，虚费光阴。"]'),
('song-ci-121','浪淘沙令','柳永','宋','宋词','song-ci','浪淘沙令','[]','有个人人。',62,'宋词/ci.song.0.json','["有个人人。", "飞燕精神。", "急锵环佩上华裀。", "促拍尽随红袖举，风柳腰身。", "簌簌轻裙。", "妙尽尖新。", "曲终独立敛香尘。", "应是西施娇困也，眉黛双颦。"]'),
('song-ci-122','荔枝香','柳永','宋','宋词','song-ci','荔枝香','[]','甚处寻芳赏翠，归去晚。',92,'宋词/ci.song.0.json','["甚处寻芳赏翠，归去晚。", "缓步罗袜生尘，来绕琼筵看。", "金缕霞衣轻褪，似觉春游倦。", "遥认，众里盈盈好身段。", "拟回首，又伫立、帘帏畔。", "素脸红眉，时揭盖头微见。", "笑整金翘，一点芳心在娇眼。", "王孙空恁肠断。"]'),
('song-ci-123','古倾杯・倾杯乐','柳永','宋','宋词','song-ci','古倾杯・倾杯乐','[]','冻水消痕，晓风生暖，春满东郊道。',133,'宋词/ci.song.0.json','["冻水消痕，晓风生暖，春满东郊道。", "迟迟淑景，烟和露润，偏绕长堤芳草。", "断鸿隐隐归飞，江天杳杳。", "遥山变色，妆眉淡扫。", "目极千里，闲倚危樯迥眺。", "动几许、伤春怀抱。", "念何处、韶阳偏早。", "想帝里看看，名园芳树，烂漫莺花好。", "追思往昔年少。", "继日恁、把酒听歌，量金买笑。", "别后暗负，光阴多少。"]'),
('song-ci-124','倾杯・倾杯乐','柳永','宋','宋词','song-ci','倾杯・倾杯乐','[]','离宴殷勤，兰舟凝滞，看看送行南浦。',134,'宋词/ci.song.0.json','["离宴殷勤，兰舟凝滞，看看送行南浦。", "情知道世上，难使皓月长圆，彩云镇聚。", "算人生、悲莫悲於轻别，最苦正欢娱，便分鸳侣。", "泪流琼脸，梨花一枝春带雨。", "惨黛蛾、盈盈无绪。", "共黯然消魂，重携纤手，话别临行，犹自再三、问道君须去。", "频耳畔低语。", "知多少、他日深盟，平生丹素。", "从今尽把凭鳞羽。"]'),
('song-ci-125','破阵乐','柳永','宋','宋词','song-ci','破阵乐','[]','露花倒影，烟芜蘸碧，灵沼波暖。',164,'宋词/ci.song.0.json','["露花倒影，烟芜蘸碧，灵沼波暖。", "金柳摇风树树，系彩舫龙舟遥岸。", "千步虹桥，参差雁齿，直趋水殿。", "绕金堤、曼衍鱼龙戏，簇娇春罗绮，喧天丝管。", "霁色荣光，望中似睹，蓬莱清浅。", "时见。", "凤辇宸游，鸾觞禊饮，临翠水、开镐宴。", "两两轻舠飞画楫，竞夺锦标霞烂。", "罄欢娱，歌鱼藻，徘徊宛转。", "别有盈盈游女，各委明珠，争收翠羽，相将归远。", "渐觉云海沈沈，洞天日晚。"]'),
('song-ci-126','双声子','柳永','宋','宋词','song-ci','双声子','[]','晚天萧索，断蓬踪迹，乘兴兰棹东游。',126,'宋词/ci.song.0.json','["晚天萧索，断蓬踪迹，乘兴兰棹东游。", "三吴风景，姑苏台榭，牢落暮霭初收。", "夫差旧国，香径没、徒有荒丘。", "繁华处，悄无睹，惟闻麋鹿呦呦。", "想当年、空运筹决战，图王取霸无休。", "江山如画，云涛烟浪，翻输范蠡扁舟。", "验前经旧史，嗟漫载、当日风流。", "斜阳暮草茫茫，尽成万古遗愁。"]'),
('song-ci-127','阳台路','柳永','宋','宋词','song-ci','阳台路','[]','楚天晚。',121,'宋词/ci.song.0.json','["楚天晚。", "坠冷枫败叶，疏红零乱。", "冒征尘、匹马驱驱，愁见水遥山远。", "追念少年时，正恁凤帏，倚香偎暖。", "嬉游惯。", "又岂知、前欢云雨分散。", "此际空劳回首，望帝里、难收泪眼。", "暮烟衰草，算暗锁、路歧无限。", "今宵又、依前寄宿，甚处苇村山馆。", "寒灯畔。", "夜厌厌、凭何消遣。"]'),
('song-ci-128','内家娇','柳永','宋','宋词','song-ci','内家娇','[]','煦景朝升，烟光昼敛，疏雨夜来新霁。',127,'宋词/ci.song.0.json','["煦景朝升，烟光昼敛，疏雨夜来新霁。", "垂杨艳杏，丝软霞轻，绣出芳郊明媚。", "处处踏青斗草，人人眷红偎翠。", "奈少年、自有新愁旧恨，消遣无计。", "帝里。", "风光当此际。", "正好恁携佳丽。", "阻归程迢递。", "奈好景难留，旧欢顿弃。", "早是伤春情绪，那堪困人天气。", "但赢得、独立高原，断魂一饷凝睇。"]'),
('song-ci-129','二郎神','柳永','宋','宋词','song-ci','二郎神','[]','炎光谢。',129,'宋词/ci.song.0.json','["炎光谢。", "过暮雨、芳尘轻洒。", "乍露冷风清庭户，爽天如水，玉钩遥挂。", "应是星娥嗟久阻，叙旧约、飙轮欲驾。", "极目处、微云暗度，耿耿银河高泻。", "闲雅。", "须知此景，古今无价。", "运巧思、穿针楼上女，抬粉面、云鬟相亚。", "钿合金钗私语处，算谁在、回廊影下。", "愿天上人间，占得欢娱，年年今夜。"]'),
('song-ci-130','醉蓬莱','柳永','宋','宋词','song-ci','醉蓬莱','[]','渐亭皋叶下，陇首云飞，素秋新霁。',120,'宋词/ci.song.0.json','["渐亭皋叶下，陇首云飞，素秋新霁。", "华阙中天，锁葱葱佳气。", "嫩菊黄深，拒霜红浅，近宝阶香砌。", "玉宇无尘，金茎有露，碧天如水。", "正值升平，万几多暇，夜色澄鲜，漏声迢递。", "南极星中，有老人呈瑞。", "此际宸游，凤辇何处，度管弦清脆。", "太液波翻，披香帘卷，月明风细。"]'),
('song-ci-131','宣清','柳永','宋','宋词','song-ci','宣清','[]','残月朦胧，小宴阑珊，归来轻寒凛凛。',143,'宋词/ci.song.0.json','["残月朦胧，小宴阑珊，归来轻寒凛凛。", "背银釭、孤馆乍眠，拥重衾、醉魄犹噤。", "永漏频传，前欢已去，离愁一枕。", "暗寻思、旧追游，神京风物如锦。", "念掷果朋侪，绝缨宴会，当时曾痛饮。", "命舞燕翩翻，歌珠贯串，向玳筵前，尽是神仙流品。", "至更阑、疏狂转甚。", "更相将、凤帏鸳寝。", "玉钗乱横，任散尽高阳，这欢娱、甚时重恁。"]'),
('song-ci-132','锦堂春・锦堂春慢','柳永','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','坠髻慵梳，愁蛾懒画，心绪是事阑珊。',122,'宋词/ci.song.0.json','["坠髻慵梳，愁蛾懒画，心绪是事阑珊。", "觉新来憔悴，金缕衣宽。", "认得这疏狂意下，向人诮譬如闲。", "把芳容整顿，恁地轻孤，争忍心安。", "依前过了旧约，甚当初赚我，偷翦云鬟。", "几时得归来，香阁深关。", "待伊要、尤云殢雨，缠绣衾、不与同欢。", "尽更深、款款问伊，今后敢更无端。"]'),
('song-ci-133','定风波','柳永','宋','宋词','song-ci','定风波','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','自春来、惨绿愁红，芳心是事可可。',123,'宋词/ci.song.0.json','["自春来、惨绿愁红，芳心是事可可。", "日上花梢，莺穿柳带，犹压香衾卧。", "暖酥消，腻云亸。", "终日厌厌倦梳裹。", "无那。", "恨薄情一去，音书无个。", "早知恁麽。", "悔当初、不把雕鞍锁。", "向鸡窗、只与蛮笺象管，拘束教吟课。", "镇相随，莫抛躲。", "针线闲拈伴伊坐。", "和我。", "免使年少，光阴虚过。"]'),
('song-ci-134','诉衷情近','柳永','宋','宋词','song-ci','诉衷情近','[]','雨晴气爽，伫立江楼望处。',91,'宋词/ci.song.0.json','["雨晴气爽，伫立江楼望处。", "澄明远水生光，重叠暮山耸翠。", "遥认断桥幽径，隐隐渔村，向晚孤烟起。", "残阳里。", "脉脉朱阑静倚。", "黯然情绪，未饮先如醉。", "愁无际。", "暮云过了，秋光老尽，故人千里。", "竟日空凝睇。"]'),
('song-ci-135','诉衷情近','柳永','宋','宋词','song-ci','诉衷情近','[]','景阑昼永，渐入清和气序。',91,'宋词/ci.song.0.json','["景阑昼永，渐入清和气序。", "榆钱飘满闲阶，莲叶嫩生翠沼。", "遥望水边幽径，山崦孤村，是处园林好。", "闲情悄。", "绮陌游人渐少。", "少年风韵，自觉随春老。", "追前好。", "帝城信阻，天涯目断，暮云芳草。", "伫立空残照。"]'),
('song-ci-136','留客住','柳永','宋','宋词','song-ci','留客住','[]','偶登眺。',119,'宋词/ci.song.0.json','["偶登眺。", "凭小阑、艳阳时节，乍晴天气，是处闲花芳草。", "遥山万叠云散，涨海千里，潮平波浩渺。", "烟村院落，是谁家绿树，数声啼鸟。", "旅情悄。", "远信沈沈，离魂杳杳。", "对景伤怀，度日无言谁表。", "惆怅旧欢何处，后约难凭，看看春又老。", "盈盈泪眼，望仙乡，隐隐断霞残照。"]'),
('song-ci-137','迎春乐','柳永','宋','宋词','song-ci','迎春乐','[]','近来憔悴人惊怪。',65,'宋词/ci.song.0.json','["近来憔悴人惊怪。", "为别后、相思煞。", "我前生、负你愁烦债。", "便苦恁难开解。", "良夜永、牵情无计奈。", "锦被里、馀香犹在。", "怎得依前灯下，恣意怜娇态。"]'),
('song-ci-138','隔帘听','柳永','宋','宋词','song-ci','隔帘听','[]','咫尺凤衾鸳帐，欲去无因到。',90,'宋词/ci.song.0.json','["咫尺凤衾鸳帐，欲去无因到。", "虾鬚窣地重门悄。", "认绣履频移，洞房杳杳。", "强语笑。", "逞如簧、再三轻巧。", "梳妆早。", "琵琶闲抱。", "爱品相思调。", "声声似把芳心告。", "隔帘听，赢得断肠多少。", "恁烦恼。", "除非共伊知道。"]'),
('song-ci-139','凤归云','柳永','宋','宋词','song-ci','凤归云','[]','恋帝里，金谷园林，平康巷陌，触处繁华，连日疏狂，未尝轻负，寸心双眼。',148,'宋词/ci.song.0.json','["恋帝里，金谷园林，平康巷陌，触处繁华，连日疏狂，未尝轻负，寸心双眼。", "况佳人、尽天外行云，掌上飞燕。", "向玳筵、一一皆妙选。", "长是因酒沈迷，被花萦绊。", "更可惜、淑景亭台，暑天枕簟。", "霜月夜凉，雪霰朝飞，一岁风光，尽堪随分，俊游清宴。", "算浮生事，瞬息光阴，锱铢名宦。", "正欢笑，试恁暂时分散。", "却是恨雨愁云，地遥天远。"]'),
('song-ci-140','抛球乐','柳永','宋','宋词','song-ci','抛球乐','[]','晓来天气浓淡，微雨轻洒。',231,'宋词/ci.song.0.json','["晓来天气浓淡，微雨轻洒。", "近清明，风絮巷陌，烟草池塘，尽堪图画。", "艳杏暖、妆脸匀开，弱柳困、宫腰低亚。", "是处丽质盈盈，巧笑嬉嬉，手簇秋千架。", "戏彩球罗绶，金鸡芥羽，少年驰骋，芳郊绿野。", "占断五陵游，奏脆管、繁弦声和雅。", "向名园深处，争泥画轮，竞羁宝马。", "取次罗列杯盘，就芳树、绿阴红影下。", "舞婆娑，歌宛转，仿佛莺娇燕姹。", "寸珠片玉，争似此、浓欢无价。", "任他美酒，十千一斗，饮竭仍解金貂贳。", "恣幕天席地，陶陶尽醉太平，且乐唐虞景化。", "须信艳阳天，看未足、已觉莺花谢。", "对绿蚁翠蛾，怎忍轻舍。"]'),
('song-ci-141','集贤宾・接贤宾','柳永','宋','宋词','song-ci','集贤宾・接贤宾','[]','小楼深巷狂游遍，罗绮成丛。',140,'宋词/ci.song.0.json','["小楼深巷狂游遍，罗绮成丛。", "就中堪人属意，最是虫虫。", "有画难描雅态，无花可比芳容。", "几回饮散良宵永，鸳衾暖、凤枕香浓。", "算得人间天上，惟有两心同。", "近来云雨忽西东。", "诮恼损情悰。", "纵然偷期暗会，长是匆匆。", "争似和鸣偕老，免教敛翠啼红。", "眼前时、暂疏欢宴，盟言在、更莫忡忡。", "待作真个宅院，方信有初终。"]'),
('song-ci-142','人娇','柳永','宋','宋词','song-ci','人娇','[]','当日相逢，便有怜才深意。',83,'宋词/ci.song.0.json','["当日相逢，便有怜才深意。", "歌筵罢、偶同鸳被。", "别来光景，看看经岁。", "昨夜里、方把旧欢重继。", "晓月将沈，征骖已鞴。", "愁肠乱、又还分袂。", "良辰好景，恨浮名牵系。", "无分得、与你恣情浓睡。"]'),
('song-ci-143','思归乐','柳永','宋','宋词','song-ci','思归乐','[]','天幕清和堪宴聚。',68,'宋词/ci.song.0.json','["天幕清和堪宴聚。", "想得尽、高阳俦侣。", "皓齿善歌长袖舞。", "渐引入、醉乡深处。", "晚岁光阴能几许。", "这巧宦、不须多取。", "共君把酒听杜宇。", "解再三、劝人归去。"]'),
('song-ci-144','应天长','柳永','宋','宋词','song-ci','应天长','[]','残蝉渐绝。',115,'宋词/ci.song.0.json','["残蝉渐绝。", "傍碧砌修梧，败叶微脱。", "风露凄清，正是登高时节。", "东篱霜乍结。", "绽金蕊、嫩香堪折。", "聚宴处，落帽风流，未饶前哲。", "把酒与君说。", "恁好景佳辰，怎忍虚设。", "休效牛山，空对江天凝咽。", "尘劳无暂歇。", "遇良会、剩偷欢悦。", "歌声阕。", "杯兴方浓，莫便中辍。"]'),
('song-ci-145','合欢带','柳永','宋','宋词','song-ci','合欢带','[]','身材儿、早是妖娆。',130,'宋词/ci.song.0.json','["身材儿、早是妖娆。", "算风措、实难描。", "一个肌肤浑似玉，更都来、占了千娇。", "妍歌艳舞，莺惭巧舌，柳妒纤腰。", "自相逢，便觉韩娥价减，飞燕声消。", "桃花零落，溪水潺湲，重寻仙径非遥。", "莫道千金酬一笑，便明珠、万斛须邀。", "檀郎幸有，凌云词赋，掷果风标。", "况当年，便好相携，凤楼深处吹箫。"]'),
('song-ci-146','少年游','柳永','宋','宋词','song-ci','少年游','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','长安古道马迟迟。',60,'宋词/ci.song.0.json','["长安古道马迟迟。", "高柳乱蝉栖。", "夕阳岛外，秋风原上，目断四天垂。", "归云一去无踪迹，何处是前期。", "狎兴生疏，酒徒萧索，不似去年时。"]'),
('song-ci-147','少年游','柳永','宋','宋词','song-ci','少年游','[]','参差烟树灞陵桥。',60,'宋词/ci.song.0.json','["参差烟树灞陵桥。", "风物尽前朝。", "衰杨古柳，几经攀折，憔悴楚宫腰。", "夕阳闲淡秋光老，离思满蘅皋。", "一曲阳关，断肠声尽，独自凭兰桡。"]'),
('song-ci-148','少年游','柳永','宋','宋词','song-ci','少年游','[]','层波潋滟远山横。',62,'宋词/ci.song.0.json','["层波潋滟远山横。", "一笑一倾城。", "酒容红嫩，歌喉清丽，百媚坐中生。", "墙头马上初相见，不准拟、恁多情。", "昨夜杯阑，洞房深处，特地快逢迎。"]'),
('song-ci-149','少年游','柳永','宋','宋词','song-ci','少年游','[]','世间尤物意中人。',60,'宋词/ci.song.0.json','["世间尤物意中人。", "轻细好腰身。", "香帏睡起，发妆酒酽，红脸杏花春。", "娇多爱把齐纨扇，和笑掩朱唇。", "心性温柔，品流详雅，不称在风尘。"]'),
('song-ci-150','少年游','柳永','宋','宋词','song-ci','少年游','[]','淡黄衫子郁金裙。',62,'宋词/ci.song.0.json','["淡黄衫子郁金裙。", "长忆个人人。", "文谈闲雅，歌喉清丽，举措好精神。", "当初为倚深深宠，无个事、爱娇瞋。", "想得别来，旧家模样，只是翠蛾颦。"]'),
('song-ci-151','少年游','柳永','宋','宋词','song-ci','少年游','[]','铃斋无讼宴游频。',62,'宋词/ci.song.0.json','["铃斋无讼宴游频。", "罗绮簇簪绅。", "施朱傅粉，丰肌清骨，容态尽天真。", "舞裀歌扇花光里，翻回雪、驻行云。", "绮席阑珊，凤灯明灭，谁是意中人。"]'),
('song-ci-152','少年游','柳永','宋','宋词','song-ci','少年游','[]','帘垂深院冷萧萧。',62,'宋词/ci.song.0.json','["帘垂深院冷萧萧。", "花外漏声遥。", "青灯未灭，红窗闲卧，魂梦去迢迢。", "薄情漫有归消息，鸳鸯被、半香消。", "试问伊家，阿谁心绪，禁得恁无憀。"]'),
('song-ci-153','少年游','柳永','宋','宋词','song-ci','少年游','[]','一生赢得是凄凉。',64,'宋词/ci.song.0.json','["一生赢得是凄凉。", "追前事、暗心伤。", "好天良夜，深屏香被，争忍便相忘。", "王孙动是经年去，贪迷恋、有何长。", "万种千般，把伊情分，颠倒尽猜量。"]'),
('song-ci-154','少年游','柳永','宋','宋词','song-ci','少年游','[]','日高花榭懒梳头。',62,'宋词/ci.song.0.json','["日高花榭懒梳头。", "无语倚妆楼。", "修眉敛黛，遥山横翠，相对结春愁。", "王孙走马长楸陌，贪迷恋、少年游。", "似恁疏狂，费人拘管，争似不风流。"]'),
('song-ci-155','少年游','柳永','宋','宋词','song-ci','少年游','[]','佳人巧笑值千金。',62,'宋词/ci.song.0.json','["佳人巧笑值千金。", "当日偶情深。", "几回饮散，灯残香暖，好事尽鸳衾。", "如今万水千山阻，魂杳杳、信沈沈。", "孤棹烟波，小楼风月，两处一般心。"]'),
('song-ci-156','长相思','柳永','宋','宋词','song-ci','长相思','[]','画鼓喧街，兰灯满市，皎月初照严城。',127,'宋词/ci.song.0.json','["画鼓喧街，兰灯满市，皎月初照严城。", "清都绛阙夜景，风传银箭，露叆金茎。", "巷陌纵横。", "过平康款辔，缓听歌声。", "凤烛荧荧。", "那人家、未掩香屏。", "向罗绮丛中，认得依稀旧日，雅态轻盈。", "娇波艳冶，巧笑依然，有意相迎。", "墙头马上，漫迟留、难写深诚。", "又岂知、名宦拘检，年来减尽风情。"]'),
('song-ci-157','尾犯','柳永','宋','宋词','song-ci','尾犯','[]','晴烟幂幂。',122,'宋词/ci.song.0.json','["晴烟幂幂。", "渐东郊芳草，染成轻碧。", "野塘风暖，游鱼动触，冰嘶微坼。", "几行断雁，旋次第、归霜碛。", "咏新诗，手拈江梅，故人赠我春色。", "似此光阴催逼。", "念浮生、不满百。", "虽照人轩冕，润屋珠金，於身何益。", "一种劳心力。", "图利禄，殆非长策。", "除是恁、点检笙歌，访寻罗绮消得。"]'),
('song-ci-158','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','心娘自小能歌舞。',64,'宋词/ci.song.0.json','["心娘自小能歌舞。", "举意动容皆济楚。", "解教天上念奴羞，不怕掌中飞燕妒。", "玲珑绣扇花藏语。", "宛转香茵云衬步。", "王孙若拟赠千金，只在画楼东畔住。"]'),
('song-ci-159','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','佳娘捧板花钿簇。',64,'宋词/ci.song.0.json','["佳娘捧板花钿簇。", "唱出新声群艳伏。", "金鹅扇掩调累累，文杏梁高尘簌簌。", "鸾吟凤啸清相续。", "管裂弦焦争可逐。", "何当夜召入连昌，飞上九天歌一曲。"]'),
('song-ci-160','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','虫娘举措皆温润。',64,'宋词/ci.song.0.json','["虫娘举措皆温润。", "每到婆娑偏恃俊。", "香檀敲缓玉纤迟，画鼓声催莲步紧。", "贪为顾盼夸风韵。", "往往曲终情未尽。", "坐中年少暗消魂，争问青鸾家远近。"]'),
('song-ci-161','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','酥娘一搦腰肢袅。',64,'宋词/ci.song.0.json','["酥娘一搦腰肢袅。", "回雪萦尘皆尽妙。", "几多狎客看无厌，一辈舞童功不到。", "星眸顾指精神峭。", "罗袖迎风身段小。", "而今长大懒婆娑，只要千金酬一笑。"]'),
('song-ci-162','驻马听','柳永','宋','宋词','song-ci','驻马听','[]','凤枕鸾帷。',114,'宋词/ci.song.0.json','["凤枕鸾帷。", "二三载，如鱼似水相知。", "良天好景，深怜多爱，无非尽意依随。", "奈何伊。", "恣性灵、忒煞些儿。", "无事孜煎，万回千度，怎忍分离。", "而今渐行渐远，渐觉虽悔难追。", "漫寄消寄息，终久奚为。", "也拟重论缱绻，争奈翻覆思维。", "纵再会，只恐恩情，难似当时。"]'),
('song-ci-163','诉衷情','柳永','宋','宋词','song-ci','诉衷情','[]','一声画角日西曛。',54,'宋词/ci.song.0.json','["一声画角日西曛。", "催促掩朱门。", "不堪更倚危阑，肠断已消魂。", "年渐晚，雁空频。", "问无因。", "思心欲碎，愁泪难收，又是黄昏。"]'),
('song-ci-164','戚氏','柳永','宋','宋词','song-ci','戚氏','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晚秋天。',260,'宋词/ci.song.0.json','["晚秋天。", "一霎微雨洒庭轩。", "槛菊萧疏，井梧零乱惹残烟。", "凄然。", "望江关。", "飞云黯淡夕阳间。", "当时宋玉悲感，向此临水与登山。", "远道迢递，行人凄楚，倦听陇水潺湲。", "正蝉吟败叶，蛩响衰草，相应喧喧。", "孤馆度日如年。", "风露渐变，悄悄至更阑。", "长天净，绛河清浅，皓月婵娟。", "思绵绵。", "夜永对景，那堪屈指，暗想从前。", "未名未禄，绮陌红楼，往往经岁迁延。", "帝里风光好，当年少日，暮宴朝欢。", "况有狂朋怪侣，遇当歌、对酒竞留连。", "别来迅景如梭，旧游似梦，烟水程何限。", "念利名、憔悴长萦绊。", "追往事、空惨愁颜。", "漏箭移、稍觉轻寒。", "渐呜咽、画角数声残。", "对闲窗畔，停灯向晓，抱影无眠。"]'),
('song-ci-165','轮台子','柳永','宋','宋词','song-ci','轮台子','[]','一枕清宵好梦，可惜被、邻鸡唤觉。',139,'宋词/ci.song.0.json','["一枕清宵好梦，可惜被、邻鸡唤觉。", "匆匆策马登途，满目淡烟衰草。", "前驱风触鸣珂，过霜林、渐觉惊栖鸟。", "冒征尘远况，自古凄凉长安道。", "行行又历孤村，楚天阔、望中未晓。", "念劳生，惜芳年壮岁，离多欢少。", "叹断梗难停，暮云渐杳。", "但黯黯魂消，寸肠凭谁表。", "恁驱驱、何时是了。", "又争似、却返瑶京，重买千金笑。"]'),
('song-ci-166','引驾行','柳永','宋','宋词','song-ci','引驾行','[]','虹收残雨。',124,'宋词/ci.song.0.json','["虹收残雨。", "蝉嘶败柳长堤暮。", "背都门、动消黯，西风片帆轻举。", "愁睹。", "泛画鹢翩翩，灵龟隐隐下前浦。", "忍回首、佳人渐远，想高城、隔烟树。", "几许。", "秦楼永昼，谢阁连宵奇遇。", "算赠笑千金，酬歌百琲，尽成轻负。", "南顾。", "念吴邦越国，风烟萧索在何处。", "独自个、千山万水，指天涯去。"]'),
('song-ci-167','望远行','柳永','宋','宋词','song-ci','望远行','[]','绣帏睡起。',129,'宋词/ci.song.0.json','["绣帏睡起。", "残妆浅，无绪匀红补翠。", "藻井凝尘，金梯铺藓，寂寞凤楼十二。", "风絮纷纷，烟芜苒苒，永日画阑，沈吟独倚。", "望远行，南陌春残悄归骑。", "凝睇。", "消遣离愁无计。", "但暗掷、金钗买醉。", "对好景、空饮香醪，争奈转添珠泪。", "待伊游冶归来，故故解放翠羽，轻裙重系。", "见纤腰，图信人憔悴。"]'),
('song-ci-168','彩云归','柳永','宋','宋词','song-ci','彩云归','[]','蘅皋向晚舣轻航。',125,'宋词/ci.song.0.json','["蘅皋向晚舣轻航。", "卸云帆、水驿鱼乡。", "当暮天、霁色如晴昼，江练静、皎月飞光。", "那堪听、远村羌管，引离人断肠。", "此际浪萍风梗，度岁茫茫。", "堪伤。", "朝欢暮宴，被多情、赋与凄凉。", "别来最苦，襟袖依约，尚有馀香。", "算得伊、鸳衾凤枕，夜永争不思量。", "牵情处，惟有临歧，一句难忘。"]'),
('song-ci-169','洞仙歌','柳永','宋','宋词','song-ci','洞仙歌','[]','佳景留心惯。',152,'宋词/ci.song.0.json','["佳景留心惯。", "况少年彼此，风情非浅。", "有笙歌巷陌，绮罗庭院。", "倾城巧笑如花面。", "恣雅态、明眸回美盼。", "同心绾。", "算国艳仙材，翻恨相逢晚。", "缱绻。", "洞房悄悄，绣被重重，夜永欢馀，共有海约山盟，记得翠云偷翦。", "和鸣彩凤于飞燕。", "间柳径花阴携手遍。", "情眷恋。", "向其间、密约轻怜事何限。", "忍聚散。", "况已结深深愿。", "愿人间天上，暮云朝雨长相见。"]'),
('song-ci-170','离别难','柳永','宋','宋词','song-ci','离别难','[]','花谢水流倏忽，嗟年少光阴。',138,'宋词/ci.song.0.json','["花谢水流倏忽，嗟年少光阴。", "有天然、蕙质兰心。", "美韶容、何啻值千金。", "便因甚、翠弱红衰，缠绵香体，都不胜任。", "算神仙、五色灵丹无验，中路委瓶簪。", "人悄悄，夜沈沈。", "闭香闺、永弃鸳衾。", "想娇魂媚魄非远，纵洪都方士也难寻。", "最苦是、好景良天，尊前歌笑，空想遗音。", "望断处，杳杳巫峰十二，千古暮云深。"]'),
('song-ci-171','击梧桐','柳永','宋','宋词','song-ci','击梧桐','[]','香靥深深，姿姿媚媚，雅格奇容天与。',131,'宋词/ci.song.0.json','["香靥深深，姿姿媚媚，雅格奇容天与。", "自识伊来，便好看承，会得妖娆心素。", "临歧再约同欢，定是都把、平生相许。", "又恐恩情，易破难成，未免千般思虑。", "近日书来，寒喧而已，苦没忉忉言语。", "便认得、听人教当，拟把前言轻负。", "见说兰台宋玉，多才多艺善词赋。", "试与问、朝朝暮暮。", "行云何处去。"]');
